-- | Função para teste coords comida 
-- 
confirma:: (Int,Int)-> [(Int,Int)]-> Bool 
confirma (x,y) [] = False 
confirma (x,y) ((a,b):xs)= if a == x && y == b then True else confirma (x,y) xs
-- | Função que dá as coordenadas de cada Ghost 
-- 
coordenadasG :: State -> [(Int,Int)]
coordenadasG (State m [] ni) = error "Impossivel de calcular"
coordenadasG (State m [((Pacman (PacState (a,b,c,d,e,f) g h i))),(Ghost (GhoState (a1,(x,y),c1,d1,e1,f1) g1 ))] ni)= [(x,y)]
coordenadasG (State m ((Pacman (PacState (a,b,c,d,e,f) g h i)):(Ghost (GhoState (a1,(x,y),c1,d1,e1,f1) g1 )):xs) ni) = (x,y) : coordenadasG (State m ((Pacman (PacState (a,b,c,d,e,f) g h i)):xs) ni) 
-- | Função auxiliares
--
mudaOrientation :: Orientation -> Orientation 
mudaOrientation L = R 
mudaOrientation R = L 
mudaOrientation U = D
mudaOrientation D = U 

verPecaDoMaze :: Maze -> Coords -> Piece 
verPecaDoMaze l (x,y) = ((l!!y)!!x)
-- | Função que dá as coordenadas da comida 
-- 
coordsComida :: Maze -> [(Int,Int)]
coordsComida [] = []
coordsComida l = [(x,y)|y<-[1..((length (l!!0))-1)] , x<- [1..((length l)-1)] , l !! x !! y == Food Little || l !! x !! y == Food Big ]
-- | Função que dá as coordenadas da comida mais proxima de um Pacman
-- 
comidaMaisProxima :: [(Int,Int)]-> State -> (Int,Int)
comidaMaisProxima ((x,y):xs) (State m ((Pacman (PacState (a,(x1,y1),c,d,e,f) g h i)):ys) ni) = aux ((x,y):xs) (State m ((Pacman (PacState (a,(x1,y1),c,d,e,f) g h i)):ys) ni) (0,0)
                                                                                      where aux [] (State m l ni) (x2,y2) = (x2,y2)
                                                                                            aux ((x,y):xs) (State m ((Pacman (PacState (a,(x1,y1),c,d,e,f) g h i)):ys) ni) (x2,y2)
                                                                                             | abs (x1-x) + abs (y1-y) > abs (x1-x2) + abs (y1-y2) = aux xs (State m ((Pacman (PacState (a,(x1,y1),c,d,e,f) g h i)):ys) ni) (x2,y2)
                                                                                             | abs (x1-x) + abs (y1-y) <= abs (x1-x2) + abs (y1-y2) = aux xs (State m ((Pacman (PacState (a,(x1,y1),c,d,e,f) g h i)):ys) ni) (x,y)
                                                                                             | otherwise = aux xs (State m ((Pacman (PacState (a,(x1,y1),c,d,e,f) g h i)):ys) ni) (x2,y2)


-- | Função que faz o caminho mais curto para a comida 
-- 
caminhoMaisCurtoComida :: (Int,Int)-> State -> Play 
caminhoMaisCurtoComida (a,b) (State m ((Pacman (PacState (a1,(x,y),c,d,e,f) g h i)):xs) ni) | abs (x-a) == abs (y-b) && (x-a) < 0 && (y-b) <0 = (Move a1 U)
                                                                                            | abs (x-a) == abs (y-b) && (x-a) > 0 && (y-b) >0 = (Move a1 D)
                                                                                            | abs (x-a) == abs (y-b) && (x-a) > 0 && (y-b) <0 = (Move a1 U)
                                                                                            | abs (x-a) == abs (y-b) && (x-a) < 0 && (y-b) >0 = (Move a1 D) 
                                                                                            | abs (x-a) >= abs (y-b) && (x-a) > 0 && (y-b) <0 = (Move a1 L)
                                                                                            | abs (x-a) >= abs (y-b) && (x-a) > 0 && (y-b) >0 = (Move a1 L)
                                                                                            | abs (x-a) >= abs (y-b) && (x-a) < 0 && (y-b) <0 = (Move a1 R)
                                                                                            | abs (x-a) >= abs (y-b) && (x-a) < 0 && (y-b) >0 = (Move a1 R)
                                                                                            | abs (x-a) <= abs (y-b) && (x-a) < 0 && (y-b) >0 = (Move a1 D)
                                                                                            | abs (x-a) <= abs (y-b) && (x-a) < 0 && (y-b) <0 = (Move a1 U)
                                                                                            | abs (x-a) <= abs (y-b) && (x-a) > 0 && (y-b) <0 = (Move a1 U)
                                                                                            | abs (x-a) <= abs (y-b) && (x-a) > 0 && (y-b) >0 = (Move a1 D)
                                                                                            | otherwise = caminhoMaisCurtoComida (a,b) (State m xs ni)
-- | Função que come a comida                                                                                             
comeComida :: State -> Play 
comeComida (State m ((Pacman (PacState (a1,(x,y),c,d,e,f) g h i)):xs) ni) = caminhoMaisCurtoComida (comidaMaisProxima (coordsComida m) (State m ((Pacman (PacState (a1,(x,y),c,d,e,f) g h i)):xs) ni)) (State m ((Pacman (PacState (a1,(x,y),c,d,e,f) g h i)):xs) ni)
-- | Função que faz o bot inverter a posição caso o pacman esteja em Mega 

{-fugirDoPacman :: State -> Play
fugirDoPacman (State m ((Pacman (PacState (a,(x,y),c,d,e,f) g h i)):xs) ni)  = controleEspacoSeguranca (State m ((Pacman (PacState (a,(x,y),c,d,e,f) g h i)):xs) ni) (controleEspacoSeguranca'' (State m ((Pacman (PacState (a,(x,y),c,d,e,f) g h i)):xs) ni))

controleEspacoSeguranca'':: State -> (Int,Int)
 controleEspacoSeguranca'' (State m ((Pacman (PacState (a,(x,y),c,d,e,f) g h i)):xs) ni) = aux2 (State m ((Pacman (PacState (a,(x,y),c,d,e,f) g h i)):xs) ni) (coordenadasG (State m ((Pacman (PacState (a,(x,y),c,d,e,f) g h i)):xs) ni)) (0,0)
 
 aux2  (State m ((Pacman (PacState (a,(x,y),c,d,e,f) g h i)):xs) ni) [] (x1,y1) = (x1,y1)
