-- |Função que caso encontre uma parede faz o que deve com o pacman 
--    
aparecerParedes :: Play -> State-> State  
aparecerParedes (Move x1 Null) (State m [(Pacman(PacState(a,(x,y),1,D,d,e) f g i)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni)    = if verPecaDoMaze m (y-1,x)   == Wall  then (State m [(Pacman(PacState(a,(x,y),0,D,d,e) f g i)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni) else (State m [(Pacman(PacState(a,(y-1,x),1,D,d,e) f g i)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni)
aparecerParedes (Move x1 Null) (State m [(Pacman(PacState(a,(x,y),1,U,d,e) f g i)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni)    = if verPecaDoMaze m (y+1,x)   == Wall then (State m [(Pacman(PacState(a,(x,y),0,U,d,e) f g i)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni) else (State m [(Pacman(PacState(a,(y+1,x),1,U,d,e) f g i)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni)
aparecerParedes (Move x1 Null) (State m [(Pacman(PacState(a,(x,y),1,R,d,e) f g i)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni)    = if verPecaDoMaze m (y,x+1)   == Wall then (State m [(Pacman(PacState(a,(x,y),0,R,d,e) f g i)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni) else (State m [(Pacman(PacState(a,(y,x+1),1,R,d,e) f g i)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni)
aparecerParedes (Move x1 Null) (State m [(Pacman(PacState(a,(x,y),1,L,d,e) f g i)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni)    = if verPecaDoMaze m (y,x-1)   == Wall then (State m [(Pacman(PacState(a,(x,y),0,L,d,e) f g i)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni) else (State m [(Pacman(PacState(a,(y,x-1),1,L,d,e) f g i)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni)
aparecerParedes (Move x1 L) (State m [(Pacman(PacState(a,(x,y),1,L,d,e) f g i)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni)   = if verPecaDoMaze m (y,x-1)   == Wall then (State m [(Pacman(PacState(a,(x,y),0,L,d,e) f g i)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni) else (State m [(Pacman(PacState(a,(y,x-1),1,L,d,e) f g i)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni)
aparecerParedes (Move x1 R) (State m [(Pacman(PacState(a,(x,y),1,R,d,e) f g i)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni)   = if verPecaDoMaze m (y,x+1)   == Wall then (State m [(Pacman(PacState(a,(x,y),0,R,d,e) f g i)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni) else (State m [(Pacman(PacState(a,(y,x+1),1,R,d,e) f g i)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni) 
aparecerParedes (Move x1 U) (State m [(Pacman(PacState(a,(x,y),1,U,d,e) f g i)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni)   = if verPecaDoMaze m (y+1,x)   == Wall then (State m [(Pacman(PacState(a,(x,y),0,U,d,e) f g i)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni) else (State m [(Pacman(PacState(a,(y+1,x),1,U,d,e) f g i)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni)
aparecerParedes (Move x1 D) (State m [(Pacman(PacState(a,(x,y),1,D,d,e) f g i)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni)   = if verPecaDoMaze m (y-1,x)   == Wall then (State m [(Pacman(PacState(a,(x,y),0,D,d,e) f g i)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni) else (State m [(Pacman(PacState(a,(y-1,x),1,D,d,e) f g i)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni)
-- |Comparar coordenadas
-- 
compCoords:: Coords-> Coords -> Bool 
compCoords (x1,y1) (x2,y2) = if x1 == x2 && y1 == y2 then True else False 
-- |Função caso encontre um tunel num  labirinto de altura Par faz o que deve com o pacman  
--
aparecerTunelL :: Play-> State-> State  
aparecerTunelL (Move x1 a2) (State m [(Pacman(PacState(a,(x,y),b,L,d,e) f g i)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni) | verPecaDoMaze m (y,0)==Empty && compCoords (x,y) (y,0)== True  && a2 == L= (State m [(Pacman(PacState(a,(y,((length(m!!0))-1)),b,L,d,e) f g i)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni) 
                                                                                                                             | verPecaDoMaze m (y,0)==Empty && compCoords (x,y) (y,0)== True  && a2 == Null = (State m [(Pacman(PacState(a,(y,((length(m!!0))-1)),b,L,d,e) f g i)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni) 
                                                                                                                             | otherwise = (State m [(Pacman(PacState(a,(y,x),b,L,d,e) f g i)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni)
-- |Função caso encontre um tunel num  labirinto de altura Par faz o que deve com o pacman 
--
aparecerTunelR :: Play-> State -> State 
aparecerTunelR (Move x1 a2) (State m [(Pacman(PacState(a,(x,y),b,R,d,e) f g i)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni) | verPecaDoMaze m (y,(length(m!!0)))==Empty && compCoords (x,y) (y,(length(m!!0)))== True  && a2 == R = (State m [(Pacman(PacState(a,(y,1),b,R,d,e) f g i)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni) 
                                                                                                                             | verPecaDoMaze m (y,(length(m!!0)))==Empty && compCoords (x,y) (y,(length(m!!0)))== True  && a2 == Null = (State m [(Pacman(PacState(a,(y,1),b,R,d,e) f g i)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni) 
                                                                                                                             | otherwise = (State m [(Pacman(PacState(a,(x,y),b,R,d,e) f g i)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni)


-- |Alterar o score do player e o tipo do player   mudar as coordenadas no ver peça maze 
--
aumentarPontos:: Play->State->State 
aumentarPontos (Move p z)(State m[(Pacman(PacState (a,(x,y),c,d,e,f) g h i)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni)  | d==R && z==R && verPecaDoMaze m (y,x+1)== Food Big = (State m[(Pacman(PacState (a,(y,x+1),c,d,(e+5),f) 10 h Mega)),(Ghost(GhoState(a1,b1,0.5,mudarOrientation d1,e1,f1) Dead))] ni)
                                                                                                                           | d==R && z==R && verPecaDoMaze m (y,x+1)== Food Little =(State m[(Pacman(PacState (a,(y,x+1),c,d,(e+1),f) g h Normal)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni)
                                                                                                                           | d==R && z==Null && verPecaDoMaze m (y,x+1) == Food Little =(State m[(Pacman(PacState (a,(y,x+1),c,d,(e+1),f) g h Normal)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni)
                                                                                                                           | d==R && z==Null && verPecaDoMaze m (y,x+1) == Food Big = (State m[(Pacman(PacState (a,(y,x+1),c,d,(e+5),f) 10 h Mega)),(Ghost(GhoState(a1,b1,0.5,mudarOrientation d1,e1,f1) Dead))] ni)
                                                                                                                           | d==L && z==L && verPecaDoMaze m (y,x-1) == Food Little =(State m[(Pacman(PacState (a,(y,x-1),c,d,(e+1),f) g h Normal)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni)
                                                                                                                           | d==L && z==L && verPecaDoMaze m (y,x-1) == Food Big =(State m[(Pacman(PacState (a,(y,x-1),c,d,(e+5),f) 10 h Mega)),(Ghost(GhoState(a1,b1,0.5,mudarOrientation d1,e1,f1) Dead))] ni)
                                                                                                                           | d==L && z==Null && verPecaDoMaze m (y,x-1) == Food Big = (State m[(Pacman(PacState (a,(y,x-1),c,d,(e+5),f) 10 h Mega)),(Ghost(GhoState(a1,b1,0.5,mudarOrientation d1,e1,f1) Dead))] ni)
                                                                                                                           | d==L && z==Null && verPecaDoMaze m (y,x-1) == Food Little = (State m[(Pacman(PacState (a,(y,x-1),c,d,(e+1),f) g h Normal)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni)
                                                                                                                           | d==U && z==U && verPecaDoMaze m (y+1,x)== Food Big = (State m[(Pacman(PacState (a,(y+1,x),c,d,(e+5),f) 10 h Mega)),(Ghost(GhoState(a1,b1,0.5,mudarOrientation d1,e1,f1) Dead))] ni)
                                                                                                                           | d==U && z==U && verPecaDoMaze m (y+1,x)== Food Little = (State m[(Pacman(PacState (a,(y+1,x),c,d,(e+1),f) g h Normal)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni)
                                                                                                                           | d==U && z==Null && verPecaDoMaze m (y+1,x)==Food Big = (State m[(Pacman(PacState (a,(y+1,x),c,d,(e+5),f) 10 h Mega)),(Ghost(GhoState(a1,b1,0.5,mudarOrientation d1,e1,f1) Dead))] ni)
                                                                                                                           | d==U && z==Null && verPecaDoMaze m (y+1,x)==Food Little =  (State m[(Pacman(PacState (a,(y+1,x),c,d,(e+1),f) g h Normal)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni)
                                                                                                                           | d==D && z==D && verPecaDoMaze m (y-1,x)== Food Little = (State m[(Pacman(PacState (a,(y-1,x),c,d,(e+1),f) g h Normal)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni)
                                                                                                                           | d==D && z==Null && verPecaDoMaze m (y-1,x)== Food Big = (State m[(Pacman(PacState (a,(y-1,x),c,d,(e+5),f) 10 h Mega)),(Ghost(GhoState(a1,b1,0.5,mudarOrientation d1,e1,f1) Dead))] ni)
                                                                                                                           | d==D && z==D && verPecaDoMaze m (y-1,x)==Food Big = (State m[(Pacman(PacState (a,(y-1,x),c,d,(e+5),f) 10 h Mega)),(Ghost(GhoState(a1,b1,0.5,mudarOrientation d1,e1,f1)Dead ))] ni)
                                                                                                                           | d==D && z==Null && verPecaDoMaze m (y-1,x)== Food Big = (State m[(Pacman(PacState (a,(y-1,x),c,d,(e+5),f) 10 h Mega)),(Ghost(GhoState(a1,b1,0.5,mudarOrientation d1,e1,f1) Dead))] ni)
                                                                                                                           | d==D && z==Null && verPecaDoMaze m (y-1,x)== Food Little =(State m[(Pacman(PacState (a,(y-1,x),c,d,(e+1),f) g h Normal)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni)
                                                                                                                           |otherwise = (State m[(Pacman(PacState (a,(x,y),c,d,e,f) g h i)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni)
-- |Contacto entre os fantasmas e o pacman(Normal) e o resultado disso    
--
contactoPacManGhostN:: State -> State
contactoPacManGhostN (State m [Pacman(PacState (a,(x,y),c,d,e,f) g h i),Ghost(GhoState (a1,(x1,y1),c1,d1,e1,f1) i1)] ni)  |(x==x1 && y==y1) && f>1 && i==Normal = (State m [Pacman(PacState (a,(y,x),c,d,e,(f-1)) g h Normal),Ghost(GhoState (a1,(y1,x1),c1,d1,e1,f1) i1)] ni)
                                                                                                                          |(x==x1 && y==y1) && (f<=1 && f>=0) && i==Normal = (State m [Pacman(PacState (a,(y,x),c,d,e,0) g h Dying),Ghost(GhoState (a1,(y1,x1),c1,d1,e1,f1) i1)] ni)
-- |Contacto entre os fantasmas e o pacman (Mega) e o resultado disso
-- 
contactoPacManGhostM:: State -> State
contactoPacManGhostM (State m [Pacman(PacState (a,(x,y),c,d,e,f) g h Mega),Ghost(GhoState (a1,(x1,y1),c1,d1,e1,f1) Dead )] ni) |  x==x1 && y==y1 && mod (length m) 2==0 = (State m [Pacman(PacState(a,(y,x),c,d,(e+10),f) g h Mega), Ghost(GhoState(a1,(div (length m) 2,(div(length(m!!0))2)),c1,d1,e1,f1) Alive)] ni) 
                                                                                                                               |  x==x1 && y==y1 && mod (length m) 2/=0 = (State m [Pacman(PacState(a,(y,x),c,d,(e+10),f) g h Mega), Ghost(GhoState(a1,(((div (length m) 2)+1),(div(length(m!!0))2)),c1,d1,e1,f1) Alive)] ni)
                                                                                                                               | otherwise= (State m [Pacman(PacState (a,(x,y),c,d,e,f) g h Mega),Ghost(GhoState (a1,(x1,y1),c1,d1,e1,f1) Dead )] ni)
