-- |Tempo que o pacman permanece em modo Mega
-- 
tempoMega::State -> State 
tempoMega (State m [(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1)),(Pacman(PacState(a,b,c,d,e,f) g h i))] ni) | i==Mega && g>1 = (State m [(Pacman(PacState(a,b,c,d,e,f) (g-1) h Mega)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) Dead))] ni) 
                                                                                                       | i==Mega && g==1= (State m [(Pacman(PacState(a,b,c,d,e,f) 0 h Normal)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) Alive))] ni)
                                                                                                       |otherwise = (State m [(Pacman(PacState(a,b,c,d,e,f) g h i)), (Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni)
-- |Animação da boca a abrir e a fechar 
--
bocaAbreFecha :: State -> State 
bocaAbreFecha (State m [Pacman(PacState(a,(x,y),c,d,e,f) g h i),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni) = if h == Closed then (State m [Pacman(PacState(a,(y,x),c,d,e,f) g Open i),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni) else (State m [Pacman(PacState(a,(y,x),c,d,e,f) g Closed i),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni) 
-- |Dividir o tempo 
--
dividirTempo:: (Fractional a, Num a) => a -> a -> a 
dividirTempo x y = x / y 
-- |Mudar a velocidade do pacman 
--
mudaVelocidadeGhost :: State -> State 
mudaVelocidadeGhost (State m [(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1)),(Pacman(PacState(a,b,c,d,e,f) g h i))] ni) | i==Mega = (State m [(Ghost(GhoState(a1,b1,( dividirTempo c1 2),d1,e1,f1) Dead)),(Pacman(PacState(a,b,c,d,e,f) g h Mega))] ni)
                                                                                                                 | otherwise = (State m [(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1)),(Pacman(PacState(a,b,c,d,e,f) g h i))] ni)

-- |Atualiza o estado do ghost quando é comido pelo pacman em modo Mega e esta na mesma coordenada das comidas
-- 
contactoPacManGhostMComida:: State -> State
contactoPacManGhostMComida (State m [Pacman(PacState (a,(x,y),c,d,e,f) g h Mega),Ghost(GhoState (a1,(x1,y1),c1,d1,e1,f1) Dead )] ni) |  x==x1 && y==y1 && mod (length m) 2==0 && verPecaDoMaze m (y1,x1) ==Food Big = (State m [Pacman(PacState(a,(y,x),c,d,(e+15),f) g h Mega), Ghost(GhoState(a1,(div (length m) 2,(div(length(m!!0))2)),c1,d1,e1,f1) Alive)] ni) 
                                                                                                                                     |  x==x1 && y==y1 && mod (length m) 2/=0 && verPecaDoMaze m (y1,x1) ==Food Little = (State m [Pacman(PacState(a,(y,x),c,d,(e+11),f) g h Mega), Ghost(GhoState(a1,((div (length m) 2)+1,(div(length(m!!0))2)),c1,d1,e1,f1) Alive)] ni)
                                                                                                                                     |otherwise =(State m [Pacman(PacState (a,(y,x),c,d,e,f) g h Mega),Ghost(GhoState (a1,(y1,x1),c1,d1,e1,f1) Dead )] ni)
contactoPacManGhostNComida :: State -> State                                                                                                                                      
contactoPacManGhostNComida (State m [Pacman(PacState (a,(x,y),c,d,e,f) g h i),Ghost(GhoState (a1,(x1,y1),c1,d1,e1,f1) i1)] ni)  |(x==x1 && y==y1) && f>1 && i==Normal && verPecaDoMaze m (y1,x1)==Food Big  = (State m [Pacman(PacState (a,(y,x),c,d,(e+5),(f-1)) g h Normal),Ghost(GhoState (a1,(y1,x1),c1,d1,e1,f1) i1)] ni)
                                                                                                                                |(x==x1 && y==y1) && f>1 && i==Normal && verPecaDoMaze m (y1,x1)==Food Little  = (State m [Pacman(PacState (a,(y,x),c,d,(e+1),(f-1)) g h Normal),Ghost(GhoState (a1,(y1,x1),c1,d1,e1,f1) i1)] ni)
                                                                                                                                |(x==x1 && y==y1) && (f<=1 && f>=0) && i==Normal && verPecaDoMaze m (y1,x1)==Food Little = (State m [Pacman(PacState (a,(y,x),c,d,(e+1),0) g h Dying),Ghost(GhoState (a1,(y1,x1),c1,d1,e1,f1) i1)] ni)
                                                                                                                                |(x==x1 && y==y1) && (f<=1 && f>=0) && i==Normal && verPecaDoMaze m (y1,x1)==Food Big = (State m [Pacman(PacState (a,(y,x),c,d,(e+5),0) g h Dying),Ghost(GhoState (a1,(y1,x1),c1,d1,e1,f1) i1)] ni)
                                                                                                                                |otherwise = (State m [Pacman(PacState (a,(x,y),c,d,e,f) g h i),Ghost(GhoState (a1,(x1,y1),c1,d1,e1,f1) i1)] ni)

-- |Funções final 
--
play:: Play -> State -> State 
play (Move x y) (State m [] ni)= error "Impossivel de fazer as jogadas"
play (Move x y) (State m [(Pacman(PacState(a,b,c,d,e,f) g h i)),(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1))] ni) =  (atualizarState(mudaAOrientacaoDoPacman (Move x y)(aumentarPontos (Move x y) (aparecerTunelR (Move x y) (aparecerTunelL (Move x y) (aparecerParedes (Move x y) (moverJogador (Move x y) (State m [(Pacman(PacState(a,b,c,d,e,f) g h i))] ni))))))))


atualizarState :: State -> State 
atualizarState (State m [(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1)),(Pacman(PacState(a,b,c,d,e,f) g h i))] ni) = (contactoPacManGhostMComida (contactoPacManGhostNComida (mudaVelocidadeGhost(bocaAbreFecha(tempoMega (contactoPacManGhostM (contactoPacManGhostN (State m [(Ghost(GhoState(a1,b1,c1,d1,e1,f1) g1)),(Pacman(PacState(a,b,c,d,e,f) g h i))] ni))))))))

