-- Conjunto de funções que necessitamos de acrescentar na Tarefa2
-- | Função que muda a orientação do pacman quando este passa para dead 
-- 
mudarOrientation :: Orientation -> Orientation 
mudarOrientation L = R 
mudarOrientation R = L 
mudarOrientation U = D
mudarOrientation D = U 




-- |Parte realizada por mim 
--
murosDeLado::[Piece]->[Piece]
murosDeLado (h:t)=Wall:(take(length t -1) t ++[Wall])

fazerParedes:: Maze->Maze
fazerParedes(h:t)=
    let corridor = map murosDeLado(take(length t - 1)t)
    in (replicate (length h) Wall): corridor ++ [(replicate (length h)Wall)]

-- |Criar tunel no labirinto e criar labirinto com as paredes e o tunel 
--

tunel:: [Piece]-> [Piece]
tunel (h:t)=(Empty:(take ((length t)-1) t))++ [Empty]

labirintocomTunel :: Maze -> Maze
labirintocomTunel []=[]
labirintocomTunel l | mod (length l) 2 /= 0 = take((div (length l)2)) l ++ [tunel (l!!(div(length l)2))] ++ drop ((div (length l) 2)+1) l
                    | otherwise=take((div (length l) 2 )-1) l ++ [tunel (l!!((div(length l)2)-1))] ++[tunel (l!!((div(length l)2)))]  ++ drop ((div (length l) 2)+1) l 
-- |cria Labirinto Correto com Tunel e paredes 
--
geraLabirintoCorrecto1 x y s = labirintocomTunel $ fazerParedes (geraLabirinto x y s)



fantasmasNoCorredorPar :: Corridor -> Corridor-> Corridor 
fantasmasNoCorredorPar l t  =  take(((length l) `div` 2)-5) l ++t++ drop (((length l) `div` 2)+5) l 

fantasmasNoCorredorImpar:: Corridor-> Corridor -> Corridor
fantasmasNoCorredorImpar l t =take(((length l) `div` 2)-5) l ++t++ drop (((length l) `div` 2)+6) l 

-- |Constroi casa dos fantasmas com comprimento impar  
--
estruturasCasadeFantasmasImparl1  = ([Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty])
estruturasCasadeFantasmasImparl2  = ([Empty]++[Wall]++[Wall]++[Wall] ++[Empty] ++ [Empty]++[Empty] ++[Wall]++[Wall]++ [Wall] ++ [Empty])
estruturasCasadeFantasmasImparl3  = ([Empty]++[Wall]++ [Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Wall]++[Empty])
estruturasCasadeFantasmasImparl4  = ([Empty]++ [Wall]++[Wall]++[Wall]++[Wall]++[Wall]++[Wall]++[Wall]++[Wall] ++[Wall]++ [Empty])
estruturasCasadeFantasmasImparl5 = ([Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty])
-- |criar a casa dos fantasmas 
-- 
calcularAlturaLabirinto :: Maze -> Bool
calcularAlturaLabirinto l = if (mod (length l) 2)==0 then True else False 
calculaComprimentoLabirinto :: Corridor-> Bool
calculaComprimentoLabirinto l = if (mod (length l) 2)== 0 then True else False 
-- |Constroi casa dos fantasmas com comprimento par
--
estruturasCasadeFantasmasParl1 = ([Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty])
estruturasCasadeFantasmasParl2  = ([Empty]++[Wall]++[Wall]++[Wall] ++[Empty] ++ [Empty] ++[Wall]++[Wall]++ [Wall] ++ [Empty])
estruturasCasadeFantasmasParl3  = ([Empty]++[Wall]++ [Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Wall]++[Empty])
estruturasCasadeFantasmasParl4  = ([Empty]++ [Wall]++[Wall]++[Wall]++[Wall]++[Wall]++[Wall]++[Wall]++[Wall] ++ [Empty])
estruturasCasadeFantasmasParl5  = ([Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty]++[Empty])

montarlabirinto :: Maze-> Maze
montarlabirinto l | calculaComprimentoLabirinto (l!!0)  && calcularAlturaLabirinto l = take ((div(length l) 2 )-3 ) l ++ [fantasmasNoCorredorPar (l!!((div(length l) 2)-2)) estruturasCasadeFantasmasParl1 ]++ [fantasmasNoCorredorPar (l!!((div(length l) 2)-1)) estruturasCasadeFantasmasParl2 ]++ [fantasmasNoCorredorPar (l!!((div(length l) 2))) estruturasCasadeFantasmasParl3] ++ [fantasmasNoCorredorPar (l!!((div(length l) 2)+1)) estruturasCasadeFantasmasParl4 ]++ [fantasmasNoCorredorPar (l!!((div(length l) 2)+2)) estruturasCasadeFantasmasParl5 ]++ drop ((div(length l) 2 )+2) l
                  | calculaComprimentoLabirinto (l!!0) == False && calcularAlturaLabirinto l == False = take ((div(length l) 2)-2) l ++ [fantasmasNoCorredorImpar (l!!((div(length l) 2)-1)) estruturasCasadeFantasmasImparl1] ++ [fantasmasNoCorredorImpar (l!!((div(length l) 2))) estruturasCasadeFantasmasImparl2] ++ [fantasmasNoCorredorImpar (l!!((div(length l) 2)+1)) estruturasCasadeFantasmasImparl3]++ [fantasmasNoCorredorImpar (l!!((div(length l) 2)+2)) estruturasCasadeFantasmasImparl4 ]++ [fantasmasNoCorredorImpar (l!!((div(length l) 2)+3)) estruturasCasadeFantasmasImparl5 ]++ drop ((div(length l)2) +3) l 
                  | calculaComprimentoLabirinto (l!!0)  && calcularAlturaLabirinto l == False = take ((div(length l) 2)-2) l ++ [fantasmasNoCorredorPar (l!!((div(length l) 2)-2)) estruturasCasadeFantasmasParl1] ++ [fantasmasNoCorredorPar (l!!((div(length l) 2)-1)) estruturasCasadeFantasmasParl2] ++ [fantasmasNoCorredorPar (l!!((div(length l) 2))) estruturasCasadeFantasmasParl3 ]++ [fantasmasNoCorredorPar (l!!((div(length l) 2)+1)) estruturasCasadeFantasmasParl4] ++ [fantasmasNoCorredorPar (l!!((div(length l) 2)+2)) estruturasCasadeFantasmasParl5] ++ drop ((div(length l)2) +3) l 
                  | calculaComprimentoLabirinto (l!!0) == False && calcularAlturaLabirinto l == True =take ((div(length l) 2)-3) l ++ [fantasmasNoCorredorImpar (l!!((div(length l) 2)-1)) estruturasCasadeFantasmasImparl1] ++ [fantasmasNoCorredorImpar (l!!((div(length l) 2))) estruturasCasadeFantasmasImparl2] ++ [fantasmasNoCorredorImpar (l!!((div(length l) 2)+1)) estruturasCasadeFantasmasImparl3] ++ [fantasmasNoCorredorImpar (l!!((div(length l) 2)+2)) estruturasCasadeFantasmasImparl4] ++ [fantasmasNoCorredorImpar (l!!((div(length l) 2)+3)) estruturasCasadeFantasmasParl5] ++ drop ((div(length l)2) +2) l 
-- |Gera Labirinto apenas com casa dos fantasmas 
-- 
geraLabirintoCF  x y s = montarlabirinto (geraLabirinto x y s)

-- |Gera Labirinto Funcional com tudo direito 
--
geraLabirintoFinal x y s = labirintocomTunel $ fazerParedes $ (geraLabirintoCF x y s)


imprime:: Maze -> IO()
imprime m = putStrLn $ printMaze m







loadManager :: Manager
loadManager = ( Manager (loadMaze "maps/1.txt") 0 0 0 0 defaultDelayTime )

updateControlledPlayer :: Key -> Manager -> Manager
updateControlledPlayer KeyUpArrow (Manager (State m ((Pacman (PacState (a,b,c,d,e,f) g h i)):(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):xs)ni) id sp be del dy) = (Manager (State m ((Pacman (PacState (a,b,c,U,e,f) g h i)):(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):xs)ni) id sp be del dy)
updateControlledPlayer KeyDownArrow (Manager (State m ((Pacman (PacState (a,b,c,d,e,f) g h i)):(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):xs)ni) id sp be del dy) = (Manager (State m ((Pacman (PacState (a,b,c,D,e,f) g h i)):(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):xs)ni) id sp be del dy)
updateControlledPlayer KeyLeftArrow (Manager (State m ((Pacman (PacState (a,b,c,d,e,f) g h i)):(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):xs)ni) id sp be del dy) = (Manager (State m ((Pacman (PacState (a,b,c,L,e,f) g h i)):(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):xs)ni) id sp be del dy)
updateControlledPlayer KeyRightArrow (Manager (State m ((Pacman (PacState (a,b,c,d,e,f) g h i)):(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):xs)ni) id sp be del dy) = (Manager (State m ((Pacman (PacState (a,b,c,R,e,f) g h i)):(Ghost (GhoState (a1,b1,c1,d1,e1,f1) g1 )):xs)ni) id sp be del dy)
updateScreen :: Window  -> ColorID -> Manager -> Curses ()
updateScreen w a man =
                  do
                    updateWindow w $ do
                      clear
                      setColor a
                      moveCursor 0 0 
                      drawString $ show (state man)
                    render
     
currentTime :: IO Integer
currentTime = fmap ( round . (* 1000) ) getPOSIXTime

updateTime :: Integer -> Manager -> Manager
updateTime now  (Manager st i sp be del dy) = (Manager st i sp now ((now-be)+del) dy )     

resetTimer :: Integer -> Manager -> Manager
resetTimer now man = man {delta=0,before=now}     

nextFrame :: Integer -> Manager -> Manager
nextFrame now (Manager st i sp be del dy) = let newstate =  passTime sp st
                                            in resetTimer now (Manager newstate i (sp+1) be del dy)


loop :: Window -> Manager -> Curses ()
loop w man@(Manager s pid step bf delt del ) = do 
  color_schema <- newColorID ColorBlue ColorWhite  10
  now <- liftIO  currentTime
  updateScreen w  color_schema man
  if ( delt > del )
    then loop w $ nextFrame now man
    else do
          ev <- getEvent w $ Just 0
          case ev of
                Nothing -> loop w (updateTime now man)
                Just (EventSpecialKey arrow ) -> loop w $ updateControlledPlayer arrow (updateTime now man)
                Just ev' ->
                  if (ev' == EventCharacter 'q')
                    then return ()
                    else loop w (updateTime now man)

main :: IO ()
main =
  runCurses $ do
    setEcho False
    setCursorMode CursorInvisible
    w <- defaultWindow
    loop w loadManager





loadMaze :: String -> State
loadMaze filepath = unsafePerformIO $ readStateFromFile filepath



readStateFromFile :: String -> IO State
readStateFromFile f = do
                content <- readFile f
                let llines = lines content 
                    (new_map,pl) = convertLinesToPiece llines 0 []
                return (State new_map pl 1)



convertLinesToPiece :: [String] -> Int -> [Player] -> (Maze,[Player])
convertLinesToPiece [] _ l = ([],l)
convertLinesToPiece (x:xs) n l  = let (a,b) = convertLineToPiece x n 0 l 
                                      (a1,b1) = convertLinesToPiece xs (n+1) b
                                  in (a:a1,b1)

convertLineToPiece :: String -> Int -> Int -> [Player] -> ([Piece],[Player])
convertLineToPiece [] _ _ l = ([],l)
convertLineToPiece (z:zs) x y l = let (a,b ) = charToPiece z x y l
                                      (a1,b1) = convertLineToPiece zs x (y+1) b 
                                  in (a:a1,b1)


charToPiece :: Char -> Int -> Int -> [Player] -> (Piece,[Player])
charToPiece c x y l
    | c == '{' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Open Normal ))   :l) )
    | c == '<' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Closed Normal )) :l) )
    | c == '}' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, L,0,1 ) 0 Open Normal ))   :l) )
    | c == '>' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, L,0,1 ) 0 Closed Normal )) :l) )
    | c == 'V' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, U,0,1 ) 0 Open Normal ))   :l) )
    | c == 'v' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, U,0,1 ) 0 Closed Normal )) :l) )
    | c == '^' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, D,0,1 ) 0 Open Normal ))   :l) )
    | c == '|' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, D,0,1 ) 0 Closed Normal )) :l) )
    | c == 'X' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Open Dying ))    :l) )
    | c == 'M' =  (Empty, ((Ghost (  GhoState (length l,(x,y),0,Null,0,1 ) Alive))            :l) )
    | c == '?' =  (Empty, ((Ghost (  GhoState (length l,(x,y),0,Null,0,1 ) Dead))             :l) )
    | c == 'o' =  (Food Big,l)
    | c == '.' =  (Food Little,l)
    | c == '#' =  (Wall,l)
    | otherwise = (Empty,l)

--Exercício 2
data Exp a = Const a
           | Simetrico (Exp a)
           | Mais (Exp a) (Exp a)
           | Menos (Exp a) (Exp a)
           | Mult (Exp a) (Exp a)
--2a
calcular:: Exp a -> Exp a 
calcular (Const x)= show x 
calcular (Simetrico x) = show (-x)
calcular (Mais x y) =show  (x + y) 
calcular (Menos x y) = show  (x - y) 
calcular (Mult x y) = show  (x * y) 


data State = State 
    {
        maze :: Maze
    ,   playersState :: [Player]
    ,   level :: Int
    }

type Maze = [Corridor]
type Corridor = [Piece]
data Piece =  Food FoodType | PacPlayer Player| Empty | Wall deriving (Eq)
data Player =  Pacman PacState | Ghost GhoState deriving (Eq)

data Orientation = L | R | U | D | Null deriving (Eq,Show)
data PacState= PacState 
    {   
        pacState :: PlayerState
    ,   timeMega :: Double
    ,   openClosed :: Mouth
    ,   pacmanMode :: PacMode
    
    } deriving Eq

data GhoState= GhoState 
    {
        ghostState :: PlayerState
    ,   ghostMode :: GhostMode
    } deriving Eq

type Coords = (Int,Int)
type PlayerState = (Int, Coords, Double , Orientation, Int, Int)
--                 (ID,  (x,y), velocity, orientation, points, lives) 
data Mouth = Open | Closed deriving (Eq,Show)
data PacMode = Dying | Mega | Normal deriving (Eq,Show)
data GhostMode = Dead  | Alive deriving (Eq,Show)
data FoodType = Big | Little deriving (Eq)
data Color = Blue | Green | Purple | Red | Yellow | None deriving Eq 

data Play = Move Int Orientation deriving (Eq,Show)

type Instructions = [Instruction]

data Instruction = Instruct [(Int, Piece)]
                 | Repeat Int deriving (Show, Eq)



instance Show State where
  show (State m ps p) = printMaze mz ++ "Level: " ++ show p ++ "\nPlayers: \n" ++ (foldr (++) "\n" (map (\y-> printPlayerStats y) ps))
                          where mz = placePlayersOnMap ps m

instance Show PacState where
   show ( PacState s o m Dying  ) =  "X"
   show ( PacState (a,b,c,R,i,l) _ Open m  ) =  "{"
   show ( PacState (a,b,c,R,i,l) _ Closed m  ) =  "<"
   show ( PacState (a,b,c,L,i,l) _ Open m  ) =  "}"
   show ( PacState (a,b,c,L,i,l) _ Closed m  ) =  ">"
   show ( PacState (a,b,c,U,i,l) _ Open m  ) =  "V"
   show ( PacState (a,b,c,U,i,l) _ Closed m  ) =  "v"
   show ( PacState (a,b,c,D,i,l) _ Open m  ) =  "^"
   show ( PacState (a,b,c,D,i,l) _ Closed m  ) =  "|"
   show ( PacState (a,b,c,Null,i,l) _ Closed m  ) =  "<"
   show ( PacState (a,b,c,Null,i,l) _ Open m  ) =  "{"

instance Show Player where
   show (Pacman x ) =  show x
   show ( Ghost x ) =   show x

instance Show GhoState where
   show (GhoState x Dead ) =  "?"
   show (GhoState x Alive ) =  "M"

instance Show FoodType where
   show ( Big ) =  "o"
   show ( Little ) =  "."

instance Show Piece where
   show (  Wall ) = coloredString "#" None
   show (  Empty ) = coloredString " " None
   show (  Food z ) = coloredString (show z )   Green
   show ( PacPlayer ( Pacman ( PacState (i, c, x, y,z,l) o m Normal ) ) ) = coloredString (show ( PacState (i, c, x, y,z,l) o m Normal)  ) Yellow
   show ( PacPlayer ( Pacman ( PacState (i, c, x, y,z,l) o m Mega   ) ) ) = coloredString (show ( PacState (i, c, x, y,z,l) o m Mega)  ) Blue
   show ( PacPlayer ( Pacman ( PacState (i, c, x, y,z,l) o m Dying   ) ) ) = coloredString (show ( PacState (i, c, x, y,z,l) o m Dying)  ) Red
   show ( PacPlayer (Ghost z) ) = coloredString (show z)  Purple


coloredString :: String -> Color -> String
coloredString x y = x
 --   | y == Blue ="\x1b[36m" ++  x ++ "\x1b[0m"
 --   | y == Red = "\x1b[31m" ++ x ++ "\x1b[0m"
 --   | y == Green = "\x1b[32m" ++ x ++ "\x1b[0m"
 --   | y == Purple ="\x1b[35m" ++ x ++ "\x1b[0m"
 --   | y == Yellow ="\x1b[33m" ++ x ++ "\x1b[0m"
 --   | otherwise =  "\x1b[0m" ++ x 


placePlayersOnMap :: [Player] -> Maze -> Maze
placePlayersOnMap [] x = x
placePlayersOnMap (x:xs) m = placePlayersOnMap xs ( replaceElemInMaze (getPlayerCoords x) (PacPlayer x) m )


printMaze :: Maze -> String
printMaze []  =  ""
printMaze (x:xs) = foldr (++) "" ( map (\y -> show y) x )  ++ "\n" ++ printMaze ( xs )

printPlayerStats :: Player -> String
printPlayerStats p = let (a,b,c,d,e,l) = getPlayerState p
                     in "ID:" ++ show a ++  " Points:" ++ show e ++ " Lives:" ++ show l ++"\n"

getPlayerID :: Player -> Int
getPlayerID (Pacman (PacState (x,y,z,t,h,l) q c d )) = x
getPlayerID  (Ghost (GhoState (x,y,z,t,h,l) q )) = x
 
getPlayerPoints :: Player -> Int
getPlayerPoints (Pacman (PacState (x,y,z,t,h,l) q c d )) = h
getPlayerPoints (Ghost (GhoState (x,y,z,t,h,l) q )) = h

setPlayerCoords :: Player -> Coords -> Player
setPlayerCoords (Pacman (PacState (x,y,z,t,h,l) q c d )) (a,b) = Pacman (PacState (x,(a,b),z,t,h,l) q c d )
setPlayerCoords (Ghost (GhoState (x,y,z,t,h,l) q )) (a,b) = Ghost (GhoState (x,(a,b),z,t,h,l) q )

getPieceOrientation :: Piece -> Orientation
getPieceOrientation (PacPlayer p) =  getPlayerOrientation p
getPieceOrientation _ = Null

getPacmanMode :: Player -> PacMode
getPacmanMode (Pacman (PacState a b c d)) = d
  
getPlayerState :: Player -> PlayerState
getPlayerState (Pacman (PacState a b c d )) = a
getPlayerState (Ghost (GhoState a b )) = a

getPlayerOrientation :: Player -> Orientation
getPlayerOrientation (Pacman (PacState (x,y,z,t,h,l) q c d )) = t
getPlayerOrientation  (Ghost (GhoState (x,y,z,t,h,l) q )) = t

replaceElemInMaze :: Coords -> Piece -> Maze -> Maze
replaceElemInMaze (a,b) _ [] = []
replaceElemInMaze (a,b) p (x:xs) 
  | a == 0 = replaceNElem b p x : xs 
  | otherwise = x : replaceElemInMaze (a-1,b) p xs


replaceNElem :: Int -> a -> [a] -> [a]
replaceNElem i _ [] = [] 
replaceNElem i el (x:xs)
  |  i == 0 = el : xs 
  | otherwise =  x : replaceNElem (i-1) el xs

getPlayerCoords :: Player -> Coords
getPlayerCoords (Pacman (PacState (x,y,z,t,h,l) b c d )) = y
getPlayerCoords (Ghost (GhoState (x,y,z,t,h,l) b )) = y

{- |

=Introdução 
 Encaramos esta Tarefa como as "instruções" a devolver para o bot para o mesmo as aplicar.
 Para isso consideramos que este bot vai ter 3 modos de Jogo, juntando esse 3 modos na função final da Tarefa.

=Objetivos 
 Modo Farm : neste modo o objetivo do bot é adquirir o máximo de pontos sendo assim o seu objetivo comer a comida Pequena mais próxima.
 Caso o bot coma acidentalmente uma Comida Grande este para para o modo Chase (descrito posteriormente).
 Modo Run : este modo consiste na fuga por parte do bot quando uma ghost se encontra perto dele. 
 Para isso definimos que quando algum ghost se encontra no "perímetro de segurança do pacman" (a duas coordenadas de distância), o bot simplesmente altera a sua orientação.
 Modo Chase: quando o bot acaba por comer uma comida grande, este vai calcular a posição do ghost mais próximo dele e devolve a melhor jogada para o bot aproximar-se do ghost.

=Discussão e conclusão
 Nesta Tarefa acreditamos que cumprimos com todos os nossos objetivos a apresentamos um bot razoável que aplica 3 estratégias de jogos bastante usadas. 

-}



------------------------------------------------------------------------------------------------

-- | Função que define o que o Pacman faz quando não é ameaçado por Ghosts (tenta comer as comidas pequenas)
--
modoFarm :: State -> Play
modoFarm (State m (x:xs) le) = coordsPlay (State m (x:xs) le) (modoFarm' (State m (x:xs) le) (coordsFoodLittle m)) 

modoFarm' :: State -> [Coords] -> Coords
modoFarm' s (t:ts) = modoFarm'' s (t:ts) (0,0)
   where modoFarm'' s [] ac = ac
         modoFarm'' (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c k1 )):xs) le) (t:ts) ac
             | (abs (c1-(fst ac))) + (abs (c2-(snd ac))) > (abs (c1-(fst t))) + (abs (c2-(snd t))) = modoFarm'' (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c k1 )):xs) le) ts t
             | otherwise = modoFarm'' (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c k1 )):xs) le) ts ac

coordsPlay :: State -> Coords -> Play
coordsPlay (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c k1 )):xs) le) (c3,c4)
    | c3==c1 && (c4-c2) < 0 = (Move x L)
    | c3==c1 && (c4-c2) > 0 = (Move x R)
    | c4==c2 && (c3-c1) < 0 = (Move x U)
    | c4==c2 && (c3-c1) > 0 = (Move x D)
    | abs (c3-c1) < abs (c4-c2) && (c3-c1) < 0 = (Move x U)
    | abs (c3-c1) < abs (c4-c2) && (c3-c1) > 0 = (Move x D)
    | abs (c3-c1) > abs (c4-c2) && (c4-c2) < 0 = (Move x L)
    | abs (c3-c1) > abs (c4-c2) && (c4-c2) > 0 = (Move x R)
    | abs (c3-c1) == abs (c4-c2) && (c4-c2) < 0 = (Move x L)
    | abs (c3-c1) == abs (c4-c2) && (c4-c2) > 0 = (Move x R)

-- | Função utilizada para conhecer as localizações das Comidas Pequenas presentes no Labirinto (modoFarm)
--
coordsFoodLittle :: Maze -> [Coords]
coordsFoodLittle m = l
   where l = [(x,y) | x <- [0..((length m)-1)], y <-  [0..((length (head m))-1)], m !! x !! y == Food Little]

{-
-- | Função utilizada para conhecer as localizações dos Ghosts presentes no Labirinto
--
coordsGhosts :: State -> [Coords]
coordsGhosts (State m [] le) = []
coordsGhosts (State m ((Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) k )):xs) le) = (c3,c4) : coordsGhosts (State m xs le)
coordsGhosts (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):xs) le) = coordsGhosts (State m xs le)
-}

-- | Função que define os movimentos do Pacman quando é ameaçado por Ghosts (inverte a orientação)
--
modoRun :: State -> Play
modoRun s = perimetroPacman s (perimetroPacman' s)

-- | Função que verifica se há um Ghost no perímetro de segurança do Pacman. Se houver, devolve as coordenadas do Ghost
--
perimetroPacman :: State -> Coords -> Play
perimetroPacman (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):xs) le) (c3,c4)
    | (abs (c3-c1)) + (abs (c4-c2)) <= 2 = (Move x (inverteOt z))
    | otherwise = modoFarm (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):xs) le)

-- | Função que verifica se há um Ghost no perímetro de segurança do Pacman
--
perimetroPacmanSafe :: State -> Coords -> Bool
perimetroPacmanSafe (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):xs) le) (c3,c4)
    | (abs (c3-c1)) + (abs (c4-c2)) <= 2 = False
    | otherwise = True

-- | Função que devolve as coordenadas do Ghost que se encontra mais perto do Pacman
--
perimetroPacman' :: State -> Coords
perimetroPacman' (State m ps le) = perimetroPacman'' (State m ps le) (coordsGhosts (State m ps le)) (0,0)
   where perimetroPacman'' s [] ac = ac
         perimetroPacman'' (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):xs) le) (t:ts) ac 
            | (abs (c1-(fst ac)))+(abs (c2-(snd ac))) > (abs (c1-(fst t)))+(abs (c2-(snd t))) = perimetroPacman'' (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):xs) le) ts t
            | otherwise = perimetroPacman'' (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):xs) le) ts ac

-- | Função utilizada para conhecer as localizações das Comidas Grandes presentes no Labirinto (modoChase)
--
coordsFoodBig :: Maze -> [Coords]
coordsFoodBig m = l
   where l = [(x,y) | x <- [0..((length m)-1)], y <-  [0..((length (head m))-1)], m !! x !! y == Food Big]

-- | Função que define os movimentos do Pacman quando este entra no modo Mega
--
modoChase :: State -> Play
modoChase (State m ps le) 
    | isMega ps = comparaCoords (State m ps le) (perimetroPacman' (State m ps le))
    | otherwise = modoFarm (State m ps le)

-- |
--
isMega :: [Player] -> Bool
isMega ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Mega )):xs) = True
isMega ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):xs) = False

-- |
--
comparaCoords :: State -> Coords -> Play
comparaCoords (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d )):xs) le) (c3,c4)
    | c3==c1 && (c4-c2) < 0 = (Move x L)
    | c3==c1 && (c4-c2) > 0 = (Move x R)
    | c4==c2 && (c3-c1) < 0 = (Move x U)
    | c4==c2 && (c3-c1) > 0 = (Move x D)
    | abs (c3-c1) < abs (c4-c2) && (c3-c1) < 0 = (Move x U)
    | abs (c3-c1) < abs (c4-c2) && (c3-c1) > 0 = (Move x D)
    | abs (c3-c1) > abs (c4-c2) && (c4-c2) < 0 = (Move x L)
    | abs (c3-c1) > abs (c4-c2) && (c4-c2) > 0 = (Move x R)
    | abs (c3-c1) == abs (c4-c2) && (c4-c2) < 0 = (Move x L)
    | abs (c3-c1) == abs (c4-c2) && (c4-c2) > 0 = (Move x R)

bot :: Int -> State -> Play
bot id (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d)):xs) le) 
    | id==x && isMega ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d)):xs) = (modoChase (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d)):xs) le))
    | id==x && perimetroPacmanSafe (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d)):xs) le) (perimetroPacman' (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d)):xs) le)) = (modoFarm (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d)):xs) le))
    | otherwise = (modoRun (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c d)):xs) le))

{- |

=Introdução
 Na Tarefa 5 o desafio era a elaboração das jogadas dos Ghost. 

=Objetivos
 Para conseguirmos definir as jogadas dos Ghost tivemos que definir duas funções principais: chaseMode e scatterMode.
 Na função chaseMode o objetivo era retornar a melhor jogada de cada ghost para apanhar o pacman da melhor forma.
 Para isso definimos que os ghost incialmente andam numa direção aleatória e só quando embatem com uma parede é que este calculam a posição dos Pacman e determinam qual a melhor jogada.
 Na função scatterMode o objetivo era retornar a melhor jogada de cada ghost para fugir do pacman (quando este estavas em modo Mega).
 Para isso definimos que assim que o pacMan come uma comida Grande os fantasmas invertem a sua orientação (Alteramos a função ghostParaDead e aplicamo-la na função movimentoContraFantasma2 da Tarefa 2)
 Após os fantasmas inverterem a sua orientação a função scatterMode faz com que quando eles, eventualmente, embatam com uma parede este rotacionem no sentido dos ponteiros do relógio para fugir ao Pacman.

=Discussão e conclusão
 Na nossa visão, obtemos todos os resultados pretendidos descritos anteriormente.

-}



