passTime' :: Int  -> State -> State
passTime' k (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Dying )):ps) n) = (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Dying )):ps) n)
