-- | Função que atualiza o estado de jogo de acordo com a movimentação de cada Player
--
realizaPlaysG :: State -> State
realizaPlaysG (State m ps l) = (realizaPlaysG' (ghostPlay (State m ps l)) (State m (pacmanEmPrimeiro ps) l))

-- | Função auxiliar da função realizaPlaysG, que tem o mesmo propósito mas com o pacman à cabeça de qualquer lista
--
realizaPlaysG' :: [Play] -> State -> State
realizaPlaysG' [] k = k
realizaPlaysG' (p:ps) k = (realizaPlaysG' ps (play p k))

