passTime i (State m (p:ps) lv) = passTime' i (State m (pacmanEmPrimeiro(p:ps)) lv)

-- | Função auxiliar da função passTime
--
passTime' :: Int -> State -> State
passTime' i (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Dying )):xs) le) = (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Dying )):xs) le)
