-- | Função que define o movimento simples de um Player em modo Normal
--
movimentoPlayer :: Play -> State -> State
movimentoPlayer (Move a b) (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )): xs) le ) 
    | a == x && b == L && z == L = (State m ((Pacman (PacState (x,(c1,c2-1),1,L,h,l) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )): xs) le)
    | a == x && b == R && z == R = (State m ((Pacman (PacState (x,(c1,c2+1),1,R,h,l) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )): xs) le)
    | a == x && b == U && z == U = (State m ((Pacman (PacState (x,(c1-1,c2),1,U,h,l) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )): xs) le)
    | a == x && b == D && z == D = (State m ((Pacman (PacState (x,(c1+1,c2),1,D,h,l) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )): xs) le)
    | otherwise = mudaOrientacao (Move a b) (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):xs) le )

-- | Função que define o movimento simples de um Player em modo Mega
--
movimentoPlayer2 :: Play -> State -> State
movimentoPlayer2 (Move a b) (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Mega )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Dead )): xs) le ) 
    | a == x && b == L && z == L = (State m ((Pacman (PacState (x,(c1,c2-1),1,L,h,l) q c Mega )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Dead )): xs) le)
    | a == x && b == R && z == R = (State m ((Pacman (PacState (x,(c1,c2+1),1,R,h,l) q c Mega )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Dead )): xs) le)
    | a == x && b == U && z == U = (State m ((Pacman (PacState (x,(c1-1,c2),1,U,h,l) q c Mega )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Dead )): xs) le)
    | a == x && b == D && z == D = (State m ((Pacman (PacState (x,(c1+1,c2),1,D,h,l) q c Mega )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Dead )): xs) le)
    | otherwise = mudaOrientacao2 (Move a b) (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Mega )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Dead )):xs) le )

-- | Função que aplica a um Player em modo Normal uma Play em q a orientação do Player é diferente da jogada realizada
--
mudaOrientacao :: Play -> State -> State
mudaOrientacao (Move a b) (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):xs) le ) = if a == x then (State m ((Pacman (PacState (x,(c1,c2),0,b,h,l) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):xs) le )
                                                                                              else (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):xs) le )

-- | Função que aplica a um Player em modo Mega uma Play em q a orientação do Player é diferente da jogada realizada
--
mudaOrientacao2 :: Play -> State -> State
mudaOrientacao2 (Move a b) (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Mega )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Dead )):xs) le ) = if a == x then (State m ((Pacman (PacState (x,(c1,c2),0,b,h,l) q c Mega )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Dead )):xs) le )
                                                                                              else (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Mega )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Dead )):xs) le )

-- | Função que impede o Player em modo Normal de se mexer se o local para onde este se dirige for ocupado por uma Wall
--
movimentoContraWall :: Play -> State -> State
movimentoContraWall (Move a b) (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):xs) le ) 
    | a == x && b == L && z == L && (pecaCoordenada (c1,c2-1) m) == Wall = (State m ((Pacman (PacState (x,(c1,c2),0,z,h,l) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):xs) le )
    | a == x && b == R && z == R && (pecaCoordenada (c1,c2+1) m) == Wall = (State m ((Pacman (PacState (x,(c1,c2),0,z,h,l) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):xs) le )
    | a == x && b == U && z == U && (pecaCoordenada (c1-1,c2) m) == Wall = (State m ((Pacman (PacState (x,(c1,c2),0,z,h,l) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):xs) le )
    | a == x && b == D && z == D && (pecaCoordenada (c1+1,c2) m) == Wall = (State m ((Pacman (PacState (x,(c1,c2),0,z,h,l) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):xs) le )
    | otherwise = movimentoPlayer (Move a b) (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):xs) le )

-- | Função que impede o Player em modo Mega de se mexer se o local para onde este se dirige for ocupado por uma Wall
--
movimentoContraWall2 :: Play -> State -> State
movimentoContraWall2 (Move a b) (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Mega )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Dead )):xs) le ) 
    | a == x && b == L && z == L && (pecaCoordenada (c1,c2-1) m) == Wall = (State m ((Pacman (PacState (x,(c1,c2),0,z,h,l) q c Mega )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Dead )):xs) le )
    | a == x && b == R && z == R && (pecaCoordenada (c1,c2+1) m) == Wall = (State m ((Pacman (PacState (x,(c1,c2),0,z,h,l) q c Mega )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Dead )):xs) le )
    | a == x && b == U && z == U && (pecaCoordenada (c1-1,c2) m) == Wall = (State m ((Pacman (PacState (x,(c1,c2),0,z,h,l) q c Mega )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Dead )):xs) le )
    | a == x && b == D && z == D && (pecaCoordenada (c1+1,c2) m) == Wall = (State m ((Pacman (PacState (x,(c1,c2),0,z,h,l) q c Mega )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Dead )):xs) le )
    | otherwise = movimentoPlayer2 (Move a b) (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Mega )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Dead )):xs) le )

-- | Função que teletransporta o Player em modo Normal para o outro lado do Labirinto
--
movimentoContraTunel :: Play -> State -> State
movimentoContraTunel (Move a b) (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):xs) le ) 
    | a == x && b == L && z == L && (pecaCoordenada (c1,c2-1) m) == Empty && (c2-1) == 0                     = (State m ((Pacman (PacState (x,(c1,length (head m) - 2),y,z,h,l) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):xs) le )
    | a == x && b == R && z == R && (pecaCoordenada (c1,c2+1) m) == Empty && (c2+1) == (length (head m)) - 1 = (State m ((Pacman (PacState (x,(c1,1),y,z,h,l) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):xs) le )
    | otherwise = movimentoContraWall (Move a b) (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):xs) le )

-- | Função que teletransporta o Player em modo Mega para o outro lado do Labirinto
--
movimentoContraTunel2 :: Play -> State -> State
movimentoContraTunel2 (Move a b) (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Mega )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Dead )):xs) le ) 
    | a == x && b == L && z == L && (pecaCoordenada (c1,c2-1) m) == Empty && (c2-1) == 0                     = (State m ((Pacman (PacState (x,(c1,length (head m) - 2),y,z,h,l) q c Mega )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Dead )):xs) le )
    | a == x && b == R && z == R && (pecaCoordenada (c1,c2+1) m) == Empty && (c2+1) == (length (head m)) - 1 = (State m ((Pacman (PacState (x,(c1,1),y,z,h,l) q c Mega )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Dead )):xs) le )
    | otherwise = movimentoContraWall2 (Move a b) (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Mega )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Dead )):xs) le )

-- | Função que aumenta os pontos do Player e muda-o para o estado Mega se este comer uma comida grande (a orientação dos Ghosts foi invertida)
--
movimentoContraComida :: Play -> State -> State
movimentoContraComida (Move a b) (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):xs) le )
    | a == x && b == L && z == L && (pecaCoordenada (c1,c2-1) m) == Food Little = (State (replaceElemInMaze (c1,c2-1) Empty m) ((Pacman (PacState (x,(c1,c2-1),y,z,h+1,l) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):xs) le )
    | a == x && b == L && z == L && (pecaCoordenada (c1,c2-1) m) == Food Big    = (State (replaceElemInMaze (c1,c2-1) Empty m) ((Pacman (PacState (x,(c1,c2-1),y,z,h+5,l) 10 c Mega )):(Ghost (GhoState (x1,(c3,c4),0.5,inverteOt z1,h1,l1) Dead )):(ghostParaDead xs)) le )
    | a == x && b == R && z == R && (pecaCoordenada (c1,c2+1) m) == Food Little = (State (replaceElemInMaze (c1,c2+1) Empty m) ((Pacman (PacState (x,(c1,c2+1),y,z,h+1,l) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):xs) le )
    | a == x && b == R && z == R && (pecaCoordenada (c1,c2+1) m) == Food Big    = (State (replaceElemInMaze (c1,c2+1) Empty m) ((Pacman (PacState (x,(c1,c2+1),y,z,h+5,l) 10 c Mega )):(Ghost (GhoState (x1,(c3,c4),0.5,inverteOt z1,h1,l1) Dead )):(ghostParaDead xs)) le )
    | a == x && b == U && z == U && (pecaCoordenada (c1-1,c2) m) == Food Little = (State (replaceElemInMaze (c1-1,c2) Empty m) ((Pacman (PacState (x,(c1-1,c2),y,z,h+1,l) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):xs) le )
    | a == x && b == U && z == U && (pecaCoordenada (c1-1,c2) m) == Food Big    = (State (replaceElemInMaze (c1-1,c2) Empty m) ((Pacman (PacState (x,(c1-1,c2),y,z,h+5,l) 10 c Mega )):(Ghost (GhoState (x1,(c3,c4),0.5,inverteOt z1,h1,l1) Dead )):(ghostParaDead xs)) le )
    | a == x && b == D && z == D && (pecaCoordenada (c1+1,c2) m) == Food Little = (State (replaceElemInMaze (c1+1,c2) Empty m) ((Pacman (PacState (x,(c1+1,c2),y,z,h+1,l) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):xs) le )
    | a == x && b == D && z == D && (pecaCoordenada (c1+1,c2) m) == Food Big    = (State (replaceElemInMaze (c1+1,c2) Empty m) ((Pacman (PacState (x,(c1+1,c2),y,z,h+5,l) 10 c Mega )):(Ghost (GhoState (x1,(c3,c4),0.5,inverteOt z1,h1,l1) Dead )):(ghostParaDead xs)) le )
    | otherwise = movimentoContraTunel (Move a b) (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):xs) le ) 

-- | Função que aumenta os pontos do Player e não altera o estado do Pacman devido a já estar anteriormente no estado Mega
--
movimentoContraComida2 :: Play -> State -> State
movimentoContraComida2 (Move a b) (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Mega )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Dead )):xs) le )
    | a == x && b == L && z == L && (pecaCoordenada (c1,c2-1) m) == Food Little = (State (replaceElemInMaze (c1,c2-1) Empty m) ((Pacman (PacState (x,(c1,c2-1),y,z,h+1,l) q c Mega )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Dead )):xs) le )
    | a == x && b == L && z == L && (pecaCoordenada (c1,c2-1) m) == Food Big    = (State (replaceElemInMaze (c1,c2-1) Empty m) ((Pacman (PacState (x,(c1,c2-1),y,z,h+5,l) 10 c Mega )):(Ghost (GhoState (x1,(c3,c4),0.5,z1,h1,l1) Dead )):xs) le )
    | a == x && b == R && z == R && (pecaCoordenada (c1,c2+1) m) == Food Little = (State (replaceElemInMaze (c1,c2+1) Empty m) ((Pacman (PacState (x,(c1,c2+1),y,z,h+1,l) q c Mega )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Dead )):xs) le )
    | a == x && b == R && z == R && (pecaCoordenada (c1,c2+1) m) == Food Big    = (State (replaceElemInMaze (c1,c2+1) Empty m) ((Pacman (PacState (x,(c1,c2+1),y,z,h+5,l) 10 c Mega )):(Ghost (GhoState (x1,(c3,c4),0.5,z1,h1,l1) Dead )):xs) le )
    | a == x && b == U && z == U && (pecaCoordenada (c1-1,c2) m) == Food Little = (State (replaceElemInMaze (c1-1,c2) Empty m) ((Pacman (PacState (x,(c1-1,c2),y,z,h+1,l) q c Mega )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Dead )):xs) le )
    | a == x && b == U && z == U && (pecaCoordenada (c1-1,c2) m) == Food Big    = (State (replaceElemInMaze (c1-1,c2) Empty m) ((Pacman (PacState (x,(c1-1,c2),y,z,h+5,l) 10 c Mega )):(Ghost (GhoState (x1,(c3,c4),0.5,z1,h1,l1) Dead )):xs) le )
    | a == x && b == D && z == D && (pecaCoordenada (c1+1,c2) m) == Food Little = (State (replaceElemInMaze (c1+1,c2) Empty m) ((Pacman (PacState (x,(c1+1,c2),y,z,h+1,l) q c Mega )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Dead )):xs) le )
    | a == x && b == D && z == D && (pecaCoordenada (c1+1,c2) m) == Food Big    = (State (replaceElemInMaze (c1+1,c2) Empty m) ((Pacman (PacState (x,(c1+1,c2),y,z,h+5,l) 10 c Mega )):(Ghost (GhoState (x1,(c3,c4),0.5,z1,h1,l1) Dead )):xs) le )
    | otherwise = movimentoContraTunel2 (Move a b) (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Mega )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Dead )):xs) le ) 

-- | Função que retira uma vida ao Player em modo Normal quando este colide com um Fantasma em modo Alive
--
movimentoContraFantasma :: Play -> State -> State
movimentoContraFantasma (Move a b) (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):xs) le ) 
    | a == x && b == L && z == L && c1 == c3 && (c2-1) == c4 && l == 1 = (State m ((Pacman (PacState (x,(c1,c2-1),y,z,h,0) q c Dying )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):ghostsParaAlive xs) le )
    | a == x && b == L && z == L && c1 == c3 && (c2-1) == c4 && l > 1  = (State m ((Pacman (PacState (x,(c1,c2-1),y,z,h,l-1) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):ghostsParaAlive xs) le )
    | a == x && b == R && z == R && c1 == c3 && (c2+1) == c4 && l == 1 = (State m ((Pacman (PacState (x,(c1,c2+1),y,z,h,0) q c Dying )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):ghostsParaAlive xs) le )
    | a == x && b == R && z == R && c1 == c3 && (c2+1) == c4 && l > 1  = (State m ((Pacman (PacState (x,(c1,c2+1),y,z,h,l-1) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):ghostsParaAlive xs) le )
    | a == x && b == U && z == U && (c1-1) == c3 && c2 == c4 && l == 1 = (State m ((Pacman (PacState (x,(c1-1,c2),y,z,h,0) q c Dying )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):ghostsParaAlive xs) le )
    | a == x && b == U && z == U && (c1-1) == c3 && c2 == c4 && l > 1  = (State m ((Pacman (PacState (x,(c1-1,c2),y,z,h,l-1) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):ghostsParaAlive xs) le )
    | a == x && b == D && z == D && (c1+1) == c3 && c2 == c4 && l == 1 = (State m ((Pacman (PacState (x,(c1+1,c2),y,z,h,0) q c Dying )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):ghostsParaAlive xs) le )
    | a == x && b == D && z == D && (c1+1) == c3 && c2 == c4 && l > 1  = (State m ((Pacman (PacState (x,(c1+1,c2),y,z,h,l-1) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):ghostsParaAlive xs) le )
    | otherwise = movimentoContraComida (Move a b) (State m ((Pacman (PacState (x,(c1,c2),y,z,h,l) q c Normal )):(Ghost (GhoState (x1,(c3,c4),y1,z1,h1,l1) Alive )):xs) le )

