-- | When given a player and coords, it returns the value of the distance between the player and the coords
--
distance :: Player -> Coords  -> Float 
distance (Ghost (GhoState (id,(x,y),ve,o,p,v) s)) (x1,y1) = (sqrt ((fromIntegral (x-x1)^2)+(fromIntegral (y-y1)^2)))

-- | It returns a play that makes the ghost closer to the pacman
--
goGhost :: State -> Coords -> Play
goGhost (State m [Ghost (GhoState (i,(x,y),ve,o,p,v) Alive)] l) (a,b) | y < b && (pieceInFrontP (x,y) o m /= Wall) = (Move i R)
                                                                        | y < b && (pieceInFrontP (x,y) o m == Wall) = if distance (Ghost (GhoState (i,(x+1,y),ve,o,p,v) Alive)) (a,b) > distance (Ghost (GhoState (i,(x-1,y),ve,o,p,v) Alive)) (a,b) then (Move i U)
                                                                                                                    else (Move i D)
                                                                        | y < b && (pieceInFrontP (x,y) o m == Wall) && (pieceInFrontP (x,y) o m == Wall) = (Move i U)
                                                                        | y < b && (pieceInFrontP (x,y) o m == Wall) && (pieceInFrontP (x,y) o m == Wall) = (Move i D)
                                                                        | y < b && (pieceInFrontP (x,y) o m == Wall) && (pieceInFrontP (x,y) o m == Wall) && (pieceInFrontP (x,y) o m == Wall) = (Move i L)                                
                                                                        | y < b && (pieceInFrontP (x,y) o m /= Wall) = (Move i L)
                                                                        | y < b && (pieceInFrontP (x,y) o m == Wall) = if distance (Ghost (GhoState (i,(x+1,y),ve,o,p,v) Alive)) (a,b) > distance (Ghost (GhoState (i,(x-1,y),ve,o,p,v) Alive)) (a,b) then (Move i U)
                                                                                                                    else (Move i D)
                                                                        | y < b && (pieceInFrontP (x,y) o m == Wall) && (pieceInFrontP (x,y) o m == Wall) = (Move i U)
                                                                        | y < b && (pieceInFrontP (x,y) o m == Wall) && (pieceInFrontP (x,y) o m == Wall) = (Move i D)
                                                                        | y < b && (pieceInFrontP (x,y) o m == Wall) && (pieceInFrontP (x,y) o m == Wall) && (pieceInFrontP (x,y) o m == Wall) = (Move i R)
                                                                        | y == b && x < a && (pieceInFrontP (x,y) o m /= Wall) = (Move i D)
                                                                        | y == b && x < a && (pieceInFrontP (x,y) o m == Wall) = if distance (Ghost (GhoState (i,(x,y+1),ve,o,p,v) Alive)) (a,b) > distance (Ghost (GhoState (i,(x,y-1),ve,o,p,v) Alive)) (a,b) then (Move i L)
                                                                                                                            else (Move i R)
                                                                        | y == b && x < a && (pieceInFrontP (x,y) o m == Wall) && (pieceInFrontP (x,y) o m == Wall) = (Move i L)
                                                                        | y == b && x < a && (pieceInFrontP (x,y) o m == Wall) && (pieceInFrontP (x,y) o m == Wall) = (Move i R)
                                                                        | y == b && x < a && (pieceInFrontP (x,y) o m == Wall) && (pieceInFrontP (x,y) o m == Wall) && (pieceInFrontP (x,y) o m == Wall) = (Move i U)
                                                                        | y == b && x > a && (pieceInFrontP (x,y) o m /= Wall) = (Move i U)
                                                                        | y == b && x > a && (pieceInFrontP (x,y) o m == Wall) = if distance (Ghost (GhoState (i,(x,y+1),ve,o,p,v) Alive)) (a,b) > distance (Ghost (GhoState (i,(x,y-1),ve,o,p,v) Alive)) (a,b) then (Move i L)
                                                                                                                            else (Move i R)
                                                                        | y == b && x > a && (pieceInFrontP (x,y) o m == Wall) && (pieceInFrontP (x,y) o m == Wall) = (Move i L)
                                                                        | y == b && x > a && (pieceInFrontP (x,y) o m == Wall) && (pieceInFrontP (x,y) o m == Wall) && (pieceInFrontP (x,y) o m == Wall) = (Move i D)
                                                                        | otherwise = (Move i o)

-- | If the player does not encounter a wall, it keeps moving foward
--
killGhost :: State -> Coords -> Play
killGhost (State m [Ghost (GhoState (id,(x,y),ve,o,p,v) Dead )] l) (a,b) | (pieceInFrontP (x,y) o m) /= Wall && o == D = (Move id D)
                                                                         | (pieceInFrontP (x,y) o m) == Wall && o == D = (Move id L)
                                                                         | (pieceInFrontP (x,y) o m) /= Wall && o == U = (Move id U)
                                                                         | (pieceInFrontP (x,y) o m) == Wall && o == U = (Move id R)
                                                                         | (pieceInFrontP (x,y) o m) /= Wall && o == R = (Move id R)
                                                                         | (pieceInFrontP (x,y) o m) == Wall && o == R = (Move id D)
                                                                         | (pieceInFrontP (x,y) o m) /= Wall && o == L = (Move id L)
                                                                         | otherwise = (Move id o)

-- | If the player is the pacman it returns True
--
pacPl :: Player -> Bool
pacPl (Pacman _) = True 
pacPl _ = False

-- | If the player is a ghost it returns True
--
ghoPl :: Player -> Bool
ghoPl (Ghost _) = True 
ghoPl _ = False

-- | In a list of player, it returns the coordinates of the pacman
--
plPac :: [Player] -> Coords
plPac (x:xs) | pacPl x = getPlayerCoords x
             | otherwise = plPac xs

-- | When given a state, it returns the coordinates of the pacman
--
getPacCoords :: State -> Coords
getPacCoords (State m p l) = plPac p

-- | The ghost chooses what to do
--
rMode :: State -> Int -> Play
rMode (State m (x:xs) l) id | getPlayerID x == id = killGhost (State m [x] l) (getPacCoords (State m (x:xs) l))
                            | otherwise = rMode (State m (xs) l) id

-- | Adds a player to a state
--
newin :: Player -> State -> State
newin y (State m (x:xs) l) = (State m (y:x:xs) l)

-- | Gives priority to the pacman 
--
priority :: State -> State
priority (State m (x:xs) l) | pacPl x = (State m (xs ++ [x]) l)
                            | otherwise = newin x (priority (State m (xs) l))

-- | When the ghosts are dead, this function makes them move the furthest away from the pacman
--
scatterMode :: State -> Int -> Play
scatterMode x1 x2 = rMode (priority x1) x2

-- | When the ghost are alive, this fuction makes them move in the direction of the pacman
--
chaseMode :: State -> Int -> Play
chaseMode (State m (Ghost (GhoState (i,(x,y),ve,o,p,v) Alive):xs) l) id | id == i = goGhost (State m [(Ghost (GhoState (i,(x,y),ve,o,p,v) Alive))] l) (getPacCoords (State m (Ghost (GhoState (i,(x,y),ve,o,p,v) Alive):xs) l))
                                                                        | otherwise = chaseMode (State m xs l) id

-- | Sees is the given player is a ghost
--
isGhost :: Player -> Bool
isGhost (Ghost (GhoState (_,_,_,_,_,_) _)) = True
isGhost (Pacman (PacState (_,_,_,_,_,_) _ _ _ )) = False

-- | Sees if a given player is Dead
--
isDead :: Player -> Bool
isDead (Pacman (PacState (_,_,_,_,_,_) _ _ _ )) = False
isDead (Ghost (GhoState (_,_,_,_,_,_) x)) | x == Dead = True
                                          | otherwise = False

-- | When given a certain state, it returns the list of plays that the ghosts will do
--
ghostPlay :: State -> [Play]
ghostPlay (State m (h:t) ls) | isGhost h && isDead h = scatterMode (State m (h:t) ls) (getPlayerID h) : ghostPlay (State m t ls)
                             | isGhost h = chaseMode (State m (h:t) ls) (getPlayerID h) : ghostPlay (State m t ls)
                             | otherwise = ghostPlay (State m t ls)

{- |

= Introdução

Nesta tarefa 4, o nosso objetivo era conseguir criar a passagem de tempo para o nosso trabalho. Demoramos algum tempo
nesta tarefa pois era complicado perceber o que devíamos fazer para que tal acontecesse. Foi uma tarefa desafiante
onde conseguimos chegar ao nosso objetivo final.

= Objetivos

Começamos por pensar nas velocidades requeridas para o jogo em si. Sabendo que a velocidade tanto dos fantasmas
como do pacman era 1 e que a velocidade dos fantasmas em modo "Dead" era 0.5, criamos duas possíveis passagens:
quando um fantasma estivesse em modo "Dead" e o valor do step fosse ímpar, a passagem de tempo só ocorreria
para todos aqueles que a velocidade fosse 1 (quando o valor do step fosse par, todos se moveriam); quando
não havia nenhum fantasma em modo "Dead", a passagem de tempo era aplicada a todos os jogadores.

Para aplicarmos isso, foi criado uma função que devolvia a lista só com os jogadores com velocidade 1, outra
que devolvia todas as plays que ocorreriam para todos os jogadores e outra que devolvia a orientação de um
determinado jogador.

= Discussão e Conclusão

Com isto, conseguimos concluir a tarefa 4. Foi uma tarefa com poucas funções, mas que requeriu muito tempo
devido à sua complexidade.

Assim, conseguimos atribuir a passagem de tempo ao trabalho, fazendo com que fosse possível que os jogadores
se movessem sozinhos.

-}


-- | When given a player, it returns his orientation
--
getPOrientation :: Player -> Orientation 
getPOrientation (Pacman (PacState (_,_,_,o,_,_) _ _ _ )) = o
getPOrientation (Ghost (GhoState (_,_,_,o,_,_) _)) = o

-- | When given the list of players, it returns a play to move foward for each player 
--
plays :: [Player] -> [Play]
plays [] = []
plays (x:xs) = (Move (getPlayerID x) (getPOrientation x)) : plays xs

-- | When given a list of player, it returns a list with all the player with velocity == 1
--
filterVel :: [Player] -> [Player]
filterVel [] = []
filterVel ((Pacman (PacState (a,b,c,d,e,f) g h i )):t) = (Pacman (PacState (a,b,c,d,e,f) g h i )) : filterVel t
filterVel ((Ghost (GhoState (a,b,vel,c,d,e) f)):t) | vel == 1 = (Ghost (GhoState (a,b,vel,c,d,e) f)) : filterVel t
                                                   | otherwise = filterVel t

-- | When given a step and a state, it returns a state that creates a passage of time
--
passTime :: Int  -> State -> State 
passTime x (State m (a:b:xs) ls) | (isDead a || isDead b) && odd x = foldr play (State m (a:b:xs) ls) (plays (filterVel (a:b:xs)))
                                 | otherwise = foldr play (State m (a:b:xs) ls) (plays (a:b:xs))

