mRMegE (Pacman (PacState(i,(x,y),ve,R,p,l) c b Mega)) m | ((y == ((lengthCorridor m)-1)) && (x == (div (length m) 2))) = Pacman (PacState (i,(x,0),ve,R,p,l) (c-1) Closed Mega)
                                                        | ((y == ((lengthCorridor m)-1)) && (x == ((div (length m) 2) - 1))) = Pacman (PacState (i,(x,0),ve,R,p,l) (c-1) Closed Mega)
                                                        | (pieceInFrontP (x,y) R m) == Empty = Pacman (PacState (i,(x,y+1),ve,R,p,l) (c-1) Closed Mega)
