-- | 
 
pacCatch:: Maze -> [Player] -> [Player]
pacCatch m [(Pacman ( PacState (id,(a,b),vel,or,pt,lv) cd mth e))] = [(Pacman ( PacState (id,(a,b),vel,or,pt,lv) cd mth e))]
pacCatch m ((Pacman ( PacState (id,(a,b),vel,or,pt,lv) cd mth e)): (Ghost (GhoState (x,(j,k),z,t,h,l) es )) :xs) | ((e==Normal) && (a==j) && (b==k) && (lv==1)) = ([Pacman ( PacState (id,(a,b),vel,or,pt,0) cd mth Dying)] ++ [(Ghost (GhoState (x,(j,k),z,t,h,l) es ))]) ++ xs
                                                                                                                 | ((e==Normal) && (a==j) && (b==k) && (lv/=1)) = ([Pacman ( PacState (id,(a,b),vel,or,pt,lv-1) cd mth e)] ++ [(Ghost (GhoState (x,(j,k),z,t,h,l) es ))]) ++ xs
                                                                                                                 | otherwise = [(Ghost (GhoState (x,(j,k),z,t,h,l) es ))] ++ (pacCatch m (Pacman ( PacState (id,(a,b),vel,or,pt,lv) cd mth e) : xs))

-- | When the pacman becomes Mega, all the ghosts go to a dying form
--
deadGhostss :: [Player] -> [Player]
deadGhostss [x] = [x]
deadGhostss ((Pacman ( PacState (id,(a,b),vel,or,pt,lv) cd mth e)): (Ghost (GhoState (x,y,z,t,h,l) es )) :xs) | (e == Mega) = (Pacman ( PacState (id,(a,b),vel,or,pt,lv) cd mth e)): (Ghost (GhoState (x,y,(vel*0.5),t,h,l) Dead )) : aux xs 
                                                                                                              | otherwise = (Pacman ( PacState (id,(a,b),vel,or,pt,lv) cd mth e)): (Ghost (GhoState (x,y,vel,t,h,l) Alive )) : aux2 xs
                                                                                                               where
                                                                                                               aux [] = []
                                                                                                               aux ((Ghost (GhoState (x,y,z,t,h,l) es )) : g) = (Ghost (GhoState (x,y,(vel*0.5),t,h,l) Dead )) : aux g
                                                                                                               aux2 [] = []
                                                                                                               aux2 ((Ghost (GhoState (x,y,z,t,h,l) es )) : g) = (Ghost (GhoState (x,y,vel,t,h,l) Alive )) : aux2 g

-- | Sorts the list of players, putting the pacman first and then uses the function deadGhostss
--
deadGhosts :: [Player] -> [Player]
deadGhosts [] = []
deadGhosts x = deadGhostss (ordPac x)

-- | Moves a ghost to his house
--
goHome :: Maze -> Player -> Player
goHome m (Ghost (GhoState (x,y,z,t,h,l) es )) = (Ghost (GhoState (x,((div (length m) 2)-1,(div (lengthCorridor m) 2)),z,t,h,l) Alive ))

foundDGhost' :: Maze ->[Player] -> [Player]
foundDGhost' m [(Pacman ( PacState (id,(a,b),vel,or,pt,lv) cd mth e))] = []
foundDGhost' m ((Pacman ( PacState (id,(a,b),vel,or,pt,lv) cd mth e)): (Ghost (GhoState (x,(j,k),z,t,h,l) es )) : xs) | ((e==Mega) && (a==j) && (b==k)) = (goHome m (Ghost (GhoState (x,(j,k),z,t,h,l) es ))) : (foundDGhost m ((Pacman ( PacState (id,(a,b),vel,or,pt+10,lv) cd mth e)) : xs))
                                                                                                                      | otherwise = (Ghost (GhoState (x,(j,k),z,t,h,l) es )) : foundDGhost m ((Pacman ( PacState (id,(a,b),vel,or,pt,lv) cd mth e)) : xs)

foundDGhost :: Maze -> [Player] -> [Player]
foundDGhost _ [(Pacman ( PacState (id,(a,b),vel,or,pt,lv) cd mth e))] = []
foundDGhost m x = foundDGhost' m (ordPac x)

-- | When the pacman in Mega form touches a ghosts (eats), it goes to his house
--
eatenGhost' :: Maze -> [Player] -> [Player]
eatenGhost' m [x] = [x]
eatenGhost' m ((Pacman ( PacState (id,(a,b),vel,or,pt,lv) cd mth e)): (Ghost (GhoState (x,(j,k),z,t,h,l) es )) :xs) | ((e==Mega) && (a==j) && (b==k)) = ([Pacman ( PacState (id,(a,b),vel,or,pt+10,lv) cd mth e)] ++ [goHome m (Ghost (GhoState (x,(j,k),z,t,h,l) es ))]) ++ aux xs
                                                                                                                    | otherwise = ([Pacman ( PacState (id,(a,b),vel,or,pt,lv) cd mth e)] ++ [(Ghost (GhoState (x,(j,k),z,t,h,l) es ))]) ++ aux xs 
                                                                                                                     where 
                                                                                                                     aux [] = []
                                                                                                                     aux xs = foundDGhost m ((Pacman ( PacState (id,(a,b),vel,or,pt,lv) cd mth e)) : xs)

-- | Sorts the list of players, putting the pacman first and then uses the function eatenGhost'
-- 
eatenGhost :: Maze -> [Player] -> [Player]
eatenGhost _ [] = []
eatenGhost m x = eatenGhost' m (ordPac x)

-- | When given a list of players, it will return the player's list with the pacman in the head of the list
--   
ordPac :: [Player] -> [Player]
ordPac [] = []
ordPac ((Pacman ( PacState (id,(a,b),vel,or,pt,lv) cd mth e)) : t) = ((Pacman ( PacState (id,(a,b),vel,or,pt,lv) cd mth e)) : t)
ordPac ((Ghost (GhoState (x,(j,k),z,t,h,l) es )) : a : b) = ordPac ([a] ++ b ++ [(Ghost (GhoState (x,(j,k),z,t,h,l) es ))])


ordPacSt :: State -> State
ordPacSt (State m pl le) = (State m (ordPac pl) le)

-- | When given a play, the selected player does an action depending on his surroundings and what's in the piece in front of him
--
playPac :: Play -- ^ Invoques the data play 
        -> State -- ^ Tells what will the selected player do 
        -> State -- ^ Returns the maze with the changes applied to it
playPac (Move x y) (State m ((Pacman ( PacState (id,(a,b),vel,or,pt,lv) cd mth e)):xs) le) | ((y==or) && (or == R) && (e == Normal) && (odd(length m)==True)) = (State (replaceElemInMaze (a,b) Empty m) (pacCatch m (eatenGhost m (deadGhosts((mRPacO (Pacman (PacState(id,(a,b),vel,R,pt,lv) cd mth Normal)) m) : xs)))) le)
                                                                                           | ((y==or) && (or == R) && (e == Normal) && (even(length m)==True)) = (State (replaceElemInMaze (a,b) Empty m) (pacCatch m (eatenGhost m (deadGhosts((mRPacE (Pacman (PacState(id,(a,b),vel,R,pt,lv) cd mth Normal)) m) : xs)))) le)
                                                                                           | ((y==or) && (or == L) && (e == Normal) && (odd(length m)==True)) = (State (replaceElemInMaze (a,b) Empty m) (pacCatch m (eatenGhost m (deadGhosts((mLPacO (Pacman (PacState(id,(a,b),vel,L,pt,lv) cd mth Normal)) m) : xs)))) le)
                                                                                           | ((y==or) && (or == L) && (e == Normal) && (even(length m)==True)) = (State (replaceElemInMaze (a,b) Empty m) (pacCatch m (eatenGhost m (deadGhosts((mLPacE (Pacman (PacState(id,(a,b),vel,L,pt,lv) cd mth Normal)) m) : xs)))) le)
                                                                                           | ((y==or) && (or == U) && (e == Normal)) = (State (replaceElemInMaze (a,b) Empty m) (pacCatch m (eatenGhost m (deadGhosts((mUPac (Pacman (PacState(id,(a,b),vel,U,pt,lv) cd mth Normal)) m) : xs)))) le)
                                                                                           | ((y==or) && (or == D) && (e == Normal)) = (State (replaceElemInMaze (a,b) Empty m) (pacCatch m (eatenGhost m (deadGhosts((mDPac (Pacman (PacState(id,(a,b),vel,D,pt,lv) cd mth Normal)) m) : xs)))) le)
                                                                                           | ((y==or) && (or == R) && (e == Mega) && (odd(length m)==True)) = (State (replaceElemInMaze (a,b) Empty m) (pacCatch m (eatenGhost m (deadGhosts((mRMegO (Pacman (PacState(id,(a,b),vel,R,pt,lv) cd mth Mega)) m) : xs)))) le)
                                                                                           | ((y==or) && (or == R) && (e == Mega) && (even(length m)==True)) = (State (replaceElemInMaze (a,b) Empty m) (pacCatch m (eatenGhost m (deadGhosts((mRMegE (Pacman (PacState(id,(a,b),vel,R,pt,lv) cd mth Mega)) m) : xs)))) le)
                                                                                           | ((y==or) && (or == L) && (e == Mega) && (odd(length m)==True)) = (State (replaceElemInMaze (a,b) Empty m) (pacCatch m (eatenGhost m (deadGhosts((mLMegO (Pacman (PacState(id,(a,b),vel,L,pt,lv) cd mth Mega)) m) : xs)))) le)
                                                                                           | ((y==or) && (or == L) && (e == Mega) && (even(length m)==True)) = (State (replaceElemInMaze (a,b) Empty m) (pacCatch m (eatenGhost m (deadGhosts((mLMegE (Pacman (PacState(id,(a,b),vel,L,pt,lv) cd mth Mega)) m) : xs)))) le)
                                                                                           | ((y==or) && (or == U) && (e == Mega)) = (State (replaceElemInMaze (a,b) Empty m) (pacCatch m (eatenGhost m (deadGhosts((mUMeg (Pacman (PacState(id,(a,b),vel,U,pt,lv) cd mth Mega)) m) : xs)))) le)
                                                                                           | ((y==or) && (or == D) && (e == Mega)) = (State (replaceElemInMaze (a,b) Empty m) (pacCatch m (eatenGhost m (deadGhosts((mDMeg (Pacman (PacState(id,(a,b),vel,D,pt,lv) cd mth Mega)) m) : xs)))) le)
                                                                                           | ((y/=or) && (y==R)) = (State (replaceElemInMaze (a,b) Empty m) (pacCatch m (eatenGhost m (deadGhosts((Pacman ( PacState (id,(a,b),vel,R,pt,lv) cd mth e)):xs)))) le)
                                                                                           | ((y/=or) && (y==L)) = (State (replaceElemInMaze (a,b) Empty m) (pacCatch m (eatenGhost m (deadGhosts((Pacman ( PacState (id,(a,b),vel,L,pt,lv) cd mth e)):xs)))) le)
                                                                                           | ((y/=or) && (y==U)) = (State (replaceElemInMaze (a,b) Empty m) (pacCatch m (eatenGhost m (deadGhosts((Pacman ( PacState (id,(a,b),vel,U,pt,lv) cd mth e)):xs)))) le)
                                                                                           | otherwise = (State (replaceElemInMaze (a,b) Empty m) (pacCatch m (eatenGhost m (deadGhosts((Pacman ( PacState (id,(a,b),vel,D,pt,lv) cd mth e)):xs)))) le)

-- | Moves the ghost to his right in an odd maze
--
mRGhoO :: Player -> Maze -> Player
mRGhoO (Ghost (GhoState (i,(x,y),ve,R,p,l) es )) m | ((y==((lengthCorridor m)-1)) && (x == ((div (length m) 2) - 1))) = Ghost (GhoState (i,(x,0),ve,R,p,l) es)
                                                   | ((pieceInFrontP (x,y) R m) == Wall) = Ghost (GhoState (i,(x,y),ve,R,p,l) es)
                                                   | otherwise = Ghost (GhoState (i,(x,y+1),ve,R,p,l) es)

-- | Moves the ghost to his right in an even maze
--
mRGhoE :: Player -> Maze -> Player
mRGhoE (Ghost (GhoState (i,(x,y),ve,R,p,l) es )) m | ((y == ((lengthCorridor m)-1)) && (x == (div (length m) 2))) = Ghost (GhoState (i,(x,0),ve,R,p,l) es)
                                                   | ((y == ((lengthCorridor m)-1)) && (x == ((div (length m) 2) - 1))) = Ghost (GhoState (i,(x,0),ve,R,p,l) es)
                                                   | ((pieceInFrontP (x,y) R m) == Wall) = Ghost (GhoState (i,(x,y),ve,R,p,l) es)
                                                   | otherwise = Ghost (GhoState (i,(x,y+1),ve,R,p,l) es)

-- | Moves the ghost to his left in an odd maze
--
mLGhoO :: Player -> Maze -> Player
mLGhoO (Ghost (GhoState (i,(x,y),ve,L,p,l) es )) m | ((y==0) && (x == ((div (length m) 2) + 1))) = Ghost (GhoState (i,(x,(lengthCorridor m) - 1),ve,L,p,l) es)
                                                   | (pieceInFrontP (x,y) L m) == Wall = Ghost (GhoState (i,(x,y),ve,L,p,l) es)
                                                   | otherwise = Ghost (GhoState (i,(x,y-1),ve,L,p,l) es)

-- | Ghost moves to the left in an maze with an even number of lines
--
mLGhoE :: Player -> Maze -> Player
mLGhoE (Ghost (GhoState (i,(x,y),ve,L,p,l) es )) m | ((y == 0) && (x == (div (length m) 2))) = Ghost (GhoState (i,(x,(lengthCorridor m) - 1),ve,L,p,l) es)
                                                   | ((y == 0) && (x == ((div (length m) 2) - 1))) = Ghost (GhoState (i,(x,(lengthCorridor m) - 1),ve,L,p,l) es)
                                                   | (pieceInFrontP (x,y) L m) == Wall = Ghost (GhoState (i,(x,y),ve,L,p,l) es)
                                                   | otherwise = Ghost (GhoState (i,(x,y-1),ve,L,p,l) es)

-- | Moves the ghost upwards
--
mUGho :: Player -> Maze -> Player
mUGho (Ghost (GhoState (i,(x,y),ve,U,p,l) es )) m | (pieceInFrontP (x,y) U m) == Wall =  Ghost (GhoState (i,(x,y),ve,U,p,l) es)
                                                  | otherwise = Ghost (GhoState (i,(x-1,y),ve,U,p,l) es)

-- | Moves the ghost downwards
--
mDGho :: Player -> Maze -> Player
mDGho (Ghost (GhoState (i,(x,y),ve,D,p,l) es )) m | (pieceInFrontP (x,y) D m) == Wall =  Ghost (GhoState (i,(x,y),ve,D,p,l) es)
                                                  | otherwise = Ghost (GhoState (i,(x+1,y),ve,D,p,l) es)

-- | Opens and closes the pacman mouth every frame
--
mangia :: Player -> Player
mangia (Pacman (PacState (i,(x,y),ve,o,p,l) c Open mode)) = (Pacman (PacState (i,(x,y),ve,o,p,l) c Closed mode))
mangia (Pacman (PacState (i,(x,y),ve,o,p,l) c Closed mode)) = (Pacman (PacState (i,(x,y),ve,o,p,l) c Open mode))
--------------------------------------------

-- | Same as playPac but for the ghosts
--
playGhost :: Play -> State -> State
playGhost (Move x y) (State m ((Pacman ( PacState (id,(a,b),vel,or,pt,lv) cd mth e)):(Ghost (GhoState (i,(as,bs),ve,o,p,l) es )):xs) le) | ((i==x) && (y==o) && (y==R) && (odd (length m))) = (State m (pacCatch m (eatenGhost m ((Pacman ( PacState (id,(a,b),vel,or,pt,lv) cd mth e)):(mRGhoO (Ghost (GhoState (i,(as,bs),ve,R,p,l) es )) m):xs))) le)
                                                                                                                                         | ((i==x) && (y==o) && (y==R) && (even (length m))) = (State m (pacCatch m (eatenGhost m ((Pacman ( PacState (id,(a,b),vel,or,pt,lv) cd mth e)):(mRGhoE (Ghost (GhoState (i,(as,bs),ve,R,p,l) es )) m):xs))) le)
                                                                                                                                         | ((i==x) && (y==o) && (y==L) && (odd (length m))) = (State m (pacCatch m (eatenGhost m ((Pacman ( PacState (id,(a,b),vel,or,pt,lv) cd mth e)):(mLGhoO (Ghost (GhoState (i,(as,bs),ve,L,p,l) es )) m):xs))) le)
                                                                                                                                         | ((i==x) && (y==o) && (y==L) && (even (length m))) = (State m (pacCatch m (eatenGhost m ((Pacman ( PacState (id,(a,b),vel,or,pt,lv) cd mth e)):(mLGhoE (Ghost (GhoState (i,(as,bs),ve,L,p,l) es )) m):xs))) le)
                                                                                                                                         | ((i==x) && (y==o) && (y==U)) = (State m (pacCatch m (eatenGhost m ((Pacman ( PacState (id,(a,b),vel,or,pt,lv) cd mth e)):(mUGho (Ghost (GhoState (i,(as,bs),ve,U,p,l) es )) m):xs))) le)
                                                                                                                                         | ((i==x) && (y==o) && (y==D)) = (State m (pacCatch m (eatenGhost m ((Pacman ( PacState (id,(a,b),vel,or,pt,lv) cd mth e)):(mDGho (Ghost (GhoState (i,(as,bs),ve,D,p,l) es )) m):xs))) le)
                                                                                                                                         | ((i==x) && (y/=o) && (y==R)) = (State m (pacCatch m (eatenGhost m ((Pacman ( PacState (id,(a,b),vel,or,pt,lv) cd mth e)):(Ghost (GhoState (i,(as,bs),ve,R,p,l) es )):xs))) le)
                                                                                                                                         | ((i==x) && (y/=o) && (y==L)) = (State m (pacCatch m (eatenGhost m ((Pacman ( PacState (id,(a,b),vel,or,pt,lv) cd mth e)):(Ghost (GhoState (i,(as,bs),ve,L,p,l) es )):xs))) le)
                                                                                                                                         | ((i==x) && (y/=o) && (y==D)) = (State m (pacCatch m (eatenGhost m ((Pacman ( PacState (id,(a,b),vel,or,pt,lv) cd mth e)):(Ghost (GhoState (i,(as,bs),ve,D,p,l) es )):xs))) le)
                                                                                                                                         | ((i==x) && (y/=o) && (y==U)) = (State m (pacCatch m (eatenGhost m ((Pacman ( PacState (id,(a,b),vel,or,pt,lv) cd mth e)):(Ghost (GhoState (i,(as,bs),ve,U,p,l) es )):xs))) le)
                                                                                                                                         | otherwise = playGhost (Move x y) (State m (((Pacman ( PacState (id,(a,b),vel,or,pt,lv) cd mth e)):xs)++[(Ghost (GhoState (i,(as,bs),ve,o,p,l) es ))]) le)                                                                                                                                                
-- | Sorts the list of players, putting the pacman first and then uses the function playPac
--
playOrd :: Play -> State -> State
playOrd (Move x y) (State m ((Pacman ( PacState (id,(a,b),vel,or,pt,lv) cd mth e)):t) le) = (State m ((Pacman ( PacState (id,(a,b),vel,or,pt,lv) cd mth e)):t) le)

-- | When given a play and a state, it makes the play in the maze
--
play :: Play -> State -> State
play (Move x y) (State m (pl:t) le) = playOrd (Move x y) (State m (ordPac (pl:t)) le)


