-- | Tempo definido para o delay
defaultDelayTime = 250 -- 250 ms


-- | Dado um step e estado, altera o estado do jogo em uma iteração. 
passTime :: Int -> State -> State
passTime step s@(State maze (x:xs) lvl) = (play (Move (getPlayerID ((getPacman (x:xs)))) (getPlayerOrientation ((getPacman (x:xs))))) i)
                                        where i = allGhosts (ghostPlay s) s

-- | Efetua as jogadas para uma lista de fantasmas
allGhosts :: [Play] -> State -> State
allGhosts [] i = i
allGhosts [x] i = play x i
allGhosts (x:xs) i = allGhosts xs (play x i) 


{-Funçôes para colocar os fantasmas aleatórios 

passTime :: Int -> State -> State
passTime step s@(State maze (x:xs) lvl) = movePls step (play (Move (getPlayerID (setPlayertimeMega (head (isPacman (x:xs))))) (getPlayerOrientation (head (isPacman (x:xs))))) s)

movePls :: Int-> State->State
movePls n (State maze lp lvl) = (State maze (moveGhost n maze lp) lvl)

moveGhost :: Int-> Maze -> [Player] -> [Player]
moveGhost n maze [] = []
moveGhost n maze ((Ghost(GhoState (x,y,z,t,h,l) q)):ys) = (Ghost (GhoState (x, move (infereCoords (seedNum n) maze y) (veDirection n) ,z,t,h,l) q)) : moveGhost (seedNum n) maze ys
moveGhost n maze (y:ys) = y : moveGhost (seedNum n) maze ys


seedNum :: Int -> Int
seedNum x = head $ randomRs (0,1000000) (mkStdGen x)

getDirectionG :: Int -> Int
getDirectionG x  = head $ randomRs (1,4) (mkStdGen (head $ randomRs (0,1000000) (mkStdGen x)))

veDirection :: Int -> Orientation
veDirection x | getDirectionG x == 1 = R 
              | getDirectionG x == 2 = L
              | getDirectionG x == 3 = D
              | getDirectionG x == 4 = U
              | otherwise = Null

isWall :: Coords -> Maze -> Bool
isWall (x,y) maze | (getpiece (x,y) maze) == Wall = True
                  | (getpiece (x,y) maze) == Wall = True
                  | (getpiece (x,y) maze) == Wall = True
                  | (getpiece (x,y) maze) == Wall = True
                  | otherwise = False

infereCoords :: Int-> Maze-> Coords-> Coords
infereCoords s maze (x,y) | s == 1 && (isWall (move (x,y) R)maze) == False = (x+1,y)
                          | s == 2 && (isWall (move (x,y) L)maze) == False = (x-1,y)
                          | s == 3 && (isWall (move (x,y) U) maze) == False = (x,y-1)
                          | s == 4 && (isWall (move (x,y) D) maze) == False = (x,y+1)
                          | s == 1 && x==0 = (((length (head maze))-1),y)
                          | s == 2 && x==0 = (((length (head maze))-1),y)
                          | otherwise = (x,y)
-}                 



{-|
Module: Tarefa3
Description: Converter um labirinto numa sequência de instruções de modo a recriá-lo num formato mais compacto para leitura.
Copyright : A97652 <a97652@alunosuminho.pt> 
            A97141 <a97141@alunosuminho.pt>

= Introdução

Na Tarefa3 é pretendido recriar um labirinto válido como uma sequência de instruções de forma a tornar mais compacta a leitura do mesmo.
Por outras palavras, codificar o labirinto para uma sequência de instruções que, quando executadas, produzem o mesmo labirinto.

= Objetivos

O nosso concreto objetivo, como indicado no enunciado, foi conseguir reduzir um labirinto 
a uma lista de tuplos cujo primeiro valor é um inteiro e o segundo é uma peça. Assim, o somatório de todos 
os inteiros deverá ser igual à largura do labirinto e o comprimento da lista de instruções deve ser igual à altura do labirinto, e
de imediato, uma instrução válida não pode conter um número maior ou menor de peças do que a largura do labirinto.  
Começamos então pela procura de padrões horizontais, ou seja, a ocorrência de peças consecutivas iguais numa mesma pista
Passamos depois à busca de padrões verticais, ou seja, diferentes corredores com peças iguais em posições iguais.

= Discussão e Conclusão

Acreditamos que fizemos o melhor que conseguimos nesta tarefa, com os conhecimentos que possuímos, resultou
um código simples e conciso, de rápida leitura e fácil interpretação, bem como funcional e com os resultados esperados e objetivos delineados.
Julgamos o facto de conseguir equilibrar a compressão/descompressão do labirinto com a qualidade do código como uma tarefa desafiante.

-}




-- | Teste (State x y z) = compactMaze x

-- | Converte um Maze numa lista de Instructions
converterMI:: Maze -> [Instruction]
converterMI [] = []
converterMI (x:xs) = (Instruct (geraInstruct x)) : converterMI xs  



-- | Dada uma lista de peças agrupa peças iguais em pares em que Int é o número de peças Piece iguais 
geraInstruct :: [Piece] -> [(Int, Piece)]
geraInstruct l = aux l 1
               where
                 aux [] _ = []
                 aux [x] i = [(i,x)]
                 aux (x:y:xs) i | x==y = aux (x:xs) (i+1)
                                | x/=y = (i,x):aux (y:xs) 1

-- | Verifica se existem Instructions iguais
igual :: [Instruction] ->  [Instruction] 
igual [] = []
igual (x:xs) | elem x xs = procura x (reverse xs) 0 : igual xs
             | otherwise  = x : igual xs 

-- | Procura instruções iguais numa lista de intruções
procura :: Instruction -> [Instruction] -> Int -> Instruction
procura x [] _ = x
procura x (h:t) c | x == h = Repeat c
                  | otherwise = procura x t (c+1)

-- | Codifica um labirinto para uma lista de instruções
compactMaze :: Maze -> Instructions
compactMaze x = reverse (igual (reverse (converterMI x)))  
