play :: Play -> State -> State
play (Move a b) (State maze [] l) = (State maze [] l)
play (Move a b) (State maze (x:xs) l) = acrescenta (umjog (filtro (Move a b) (State maze (x:xs) l))) (jogo (Move a b) (State maze (x:xs) l))

deteta :: Maze -> Coords -> Piece         -- indica onde está as peças do jogo
deteta x (a,b) = head (drop b (head (drop a x)))

-- função para mover para uma peça

detetaPacman :: Maze -> State -> Coords -- descobre onde está o pacman
detetaPacman maze (State maze [(Pacman (PacState (id,(a,b),s,o,p,v) t mo Normal))] l) = (a,b)

estadoGinst :: State -> Play   -- aplica a função da jogada para o estado especifico 
estadoGinst State maze (x:xs) l | init xs == alive = chaseMode (State maze (x:xs) l)
                                | otherwise = scatterMode (State maze (x:xs) l)
 
direcGalive :: Maze -> Coords -> State   -- o fantasma vivo vai em direção a 4 casas de espaçamento do pacman
direcGalive maze (a,b) | (deteta maze (a,b+4)) == Wall        =  State maze (x:(Ghost (GhoState (id,(a,b+3),s,o,p,v) l)):xs) l2
                       | (deteta maze (a,b-4)) == Wall        =  State maze (x:(Ghost (GhoState (id,(a,b-3),s,o,p,v) l)):xs) l2
                       | (deteta maze (a+4,b)) == Wall        =  State maze (x:(Ghost (GhoState (id,(a+3,b),s,o,p,v) l)):xs) l2
                       | (deteta maze (a-4,b)) == Wall        =  State maze (x:(Ghost (GhoState (id,(a-3,b),s,o,p,v) l)):xs) l2
                       | (deteta maze (a,b+4)) == Food Little =  State maze (x:(Ghost (GhoState (id,(a,b+4),s,o,p,v) l)):xs) l2
                       | (deteta maze (a,b-4)) == Food Little =  State maze (x:(Ghost (GhoState (id,(a,b-4),s,o,p,v) l)):xs) l2
                       | (deteta maze (a+4,b)) == Food Little =  State maze (x:(Ghost (GhoState (id,(a+4,b),s,o,p,v) l)):xs) l2
                       | (deteta maze (a-4,b)) == Food Little =  State maze (x:(Ghost (GhoState (id,(a-4,b),s,o,p,v) l)):xs) l2
                       | (deteta maze (a,b+4)) == Food Big    =  State maze (x:(Ghost (GhoState (id,(a,b+4),s,o,p,v) l)):xs) l2
                       | (deteta maze (a,b-4)) == Food Big    =  State maze (x:(Ghost (GhoState (id,(a,b-4),s,o,p,v) l)):xs) l2
                       | (deteta maze (a+4,b)) == Food Big    =  State maze (x:(Ghost (GhoState (id,(a+4,b),s,o,p,v) l)):xs) l2
                       | (deteta maze (a-4,b)) == Food Big    =  State maze (x:(Ghost (GhoState (id,(a-4,b),s,o,p,v) l)):xs) l2
                       | otherwise = State maze (x:(Ghost (GhoState (id,(a+4,b+4),s,o,p,v) l)):xs) l2


chaseMode :: State -> Int -> Play
{-
=Introdução
A tarefa 4 foca-se em dois pontos principais - a movimentação e a passagem de tempo - para
o funcionamento do Pacman da forma que conhecemos, com alterações na posição e aparência do 
Pacman e Fantasmas com a passagem do tempo.

=Objetivos
O objetivo principal desta tarefa é calcular o efeito da passagem de um instante de tempo num 
estado de jogo, definindo a função passTime :: Int -> State -> State; Bem como permitir a 
"movimentação" de todos os jogadores no mapa, através da utilização da biblioteca NCurses.

-}


defaultDelayTime = 250 -- 250 ms

passTime :: Int  -> State -> State             --altera o estado do jogo em uma iteração
passTime x s = updtPlay ((ghostPlay s) (runPacman s)) s


runPacman :: State -> Maybe Play 
runPacman (State maze [] l) = Nothing
runPacman (State maze (x:xs) l) | isPacman x = Just (orientPac x)
                                | otherwise  = runPacman (State maze xs l)

orientPac :: Player -> Play      --retorna a jogada do player       
orientPac (Pacman (PacState (id,(a,b),s,R,p,v) t m e)) = (Move id R) --orientação do Player (voltado para a direita)
orientPac (Pacman (PacState (id,(a,b),s,L,p,v) t m e)) = (Move id L) --orientação do Player (voltado para a esquerda)
orientPac (Pacman (PacState (id,(a,b),s,U,p,v) t m e)) = (Move id U) --orientação do Player (voltado para cima)
orientPac (Pacman (PacState (id,(a,b),s,D,p,v) t m e)) = (Move id D) --orientação do Player (voltado para baixo)

changeOrientPac :: Int -> Player -> Player   --dado um int e um player, altera a sua orientação
changeOrientPac 1 (Pacman (PacState (id,(a,b),s,o,p,v) t m e)) = (Pacman (PacState (id,(a,b),s,R,p,v) t m e)) --alteração da orientação para a direita
changeOrientPac 2 (Pacman (PacState (id,(a,b),s,o,p,v) t m e)) = (Pacman (PacState (id,(a,b),s,L,p,v) t m e)) --alteração da orientação para a esquerda
changeOrientPac 3 (Pacman (PacState (id,(a,b),s,o,p,v) t m e)) = (Pacman (PacState (id,(a,b),s,U,p,v) t m e)) --alteração da orientação para cima
changeOrientPac 4 (Pacman (PacState (id,(a,b),s,o,p,v) t m e)) = (Pacman (PacState (id,(a,b),s,D,p,v) t m e)) --alteração da orientação para baixo

changeOrState :: Int -> [Player] -> [Player] --muda o state dos players
changeOrState n [] = []
changeOrState n (x:xs) | isPacman x = (changeOrientPac n x) : changeOrState n xs
                       | otherwise = x : changeOrState n xs

megaTimer :: [Player] -> [Player] --funcionamento do timer quando se encontra em estado mega
megaTimer [] = []
megaTimer ((Pacman (PacState (id,(a,b),s,o,p,v) t m Mega)):xs) | t > 1     = (Pacman (PacState (id,(a,b),s,o,p,v) (t - 1) m Mega))   : megaTimer xs
                                                               | otherwise = (Pacman (PacState (id,(a,b),s,o,p,v) (t - 1) m Normal)) : megaTimer xs
megaTimer ((Pacman (PacState (id,(a,b),s,o,p,v) t m e)):xs) = (Pacman (PacState (id,(a,b),s,o,p,v) e)) : megaTimer xs
megaTimer ((Ghost (GhostState (id,(a,b),s,o,p,v) e)):xs)    = (Ghost (GhostState (id,(a,b),s,o,p,v) e)) : megaTimer xs

megaState :: State -> State --retorna o state em estado mega
megaState (State maze (x:xs) l) = (State maze (megaTimer (x:xs)) l)

updtPlay :: [Play] -> State -> State --retorna os states atualizados dos players
updtPlay [] s     = s 
updtPlay (x:xs) s = updtPlay xs (play x s)

spdW :: Player -> Double
spdW (Ghost (GhostState (id,(a,b),s,o,p,v) e)) = s
spdW (Pacman (PacState (id,(a,b),s,o,p,v) t m e)) = s




