ms = putStrLn $ printMaze $ mz
mz = (generateMaze 400 400 5)


despiece :: Piece -> (Int,Piece)                   -- função que vai descrever uma peça
despiece x | x == Wall = (1,Wall)
           | x == Empty = (1,Empty)
           | x == Food Big = (1,Food Big)
           | otherwise = (1,Food Little)

descorri :: Corridor -> [(Int,Piece)]
descorri [] = []
descorri (x:xs) = ((despiece x):(descorri xs)) -- função que vai descrever o corredor utilizando n-uplos

compareInst :: Instruction -> Instruction -> Bool         -- função que analisa se duas instruções são iguais
compareInst (Instruct []) (Instruct []) = True
compareInst (Instruct ((a,b):xs)) (Instruct ((c,d):ys)) | a == c && b == d = compareInst (Instruct xs) (Instruct ys) 
                                                        | otherwise = False
compareInst _ _ = False

comparone :: Instruction -> Instructions -> Int -> Instructions   
comparone l [] n = []
comparone l (h:t) n | compareInst l h == True = (Repeat n) : (comparone l t n)
                    | otherwise = h : (comparone l t n)
                                                                       -- comparone e comparall servem para ver quais são as linhas iguais e as que forem iguais substituimos por repeat 
comparall :: Instructions -> Int -> Instructions           
comparall [] n = []
comparall (x:xs) n = x : comparall (comparone x xs n) (n + 1)

joinpiece :: [(Int,Piece)] -> [(Int,Piece)]               -- junta os n-uplos das peças do corredor que são compativeis
joinpiece [] = []
joinpiece [x] = [x]
joinpiece ((a,b):(c,d):xs) | b == d = joinpiece ((a + c,d):xs)
                           | otherwise = ((a,b):(joinpiece ((c,d):xs)))

reftranscorri :: Corridor -> Instruction                  -- dado um corridor válido, converte-o numa instrução de modo a recria-lo num formato mais compacto para leitura
reftranscorri (x:xs) = Instruct (joinpiece (descorri (x:xs)))

compactMaze :: Maze -> Instructions                        --dado um labirinto válido, convertê-lo numa sequência de instruções de modo a recriá-lo num formato mais compacto para leitura.
compactMaze [] = []
compactMaze (x:xs) = comparall (map reftranscorri (x:xs)) 0
