-- | Given a Play and a State, it returns a State--
-- Função responsável pela execução dos movimentos das peças.

play :: Play -> State -> State
play (Move a b) (State maze [] l) = (State maze [] l)
play (Move a b) (State maze (x:xs) l) = add (onePlayer (filter (Move a b) (State maze (x:xs) l))) (play2 (Move a b) (State maze (x:xs) l))

-- | Given a Play and a State, it returns a State--
--

play2 :: Play -> State -> State
play2 (Move a b) (State maze (x:xs) l) | a == getPlayerID x = (State maze (xs) l)
                                       | otherwise = (State maze (x:(transform (play2 (Move a b) (State maze xs l)))) l)

-- | Given a Player and a State, returns a State--
--

selectPlayer :: Player -> State -> State
selectPlayer x (State maze (h:t) l) = (State maze (filter (/= x) (h:t)) l)

-- | Given a Play and a State, returns a State--
filter' :: Play -> State -> State
filter' (Move a b) (State maze [] l) = (State maze [] l)
filter' (Move a b) (State maze (x:xs) l) | getPlayerID x == a = sidePacmanN (Move a b) (convert (State maze (x:xs) l))
                                         | otherwise = filter' (Move a b) (State maze (xs) l)
 

 -- | Turns a State into a list of Player--
 -- transforma um state num jogador 
transform :: State -> [Player]
transform (State maze [] l)     = []
transform (State maze [x] l)    = [x]
transform (State maze (x:xs) l) = (x:xs)

 -- | Turns a State into a Player--
 -- encontrar um determinado player no jogo que tenha um state específico
onePlayer :: State -> Player
onePlayer (State maze [x] l) = x

 -- | Given a State, it returns a list of Player--
 --
getRidPlayer :: State -> [Player]
getRidPlayer (State maze (x:xs) l) = (x:xs)
                                  -- dadp um jogador, retira esse jogador da lista de jogadores 
getRidPlayer2 :: State -> [Player]
getRidPlayer2 (State maze [] l) = []
getRidPlayer2 (State maze (x:xs) l) | isGhostV2 x == True = getRidPlayer2 (State maze (xs) l)
                                    | otherwise = x : getRidPlayer2 (State maze (xs) l)


 -- | Turns a State into a State--
 -- Posiciona os jogadores dentro do mapa com os respetivos States.

convert :: State -> State
convert (State maze (x:xs) l) = (State (placePlayersOnMap (getRidPlayer (State maze (x:xs) l)) maze) [x] l)

-- | Given a Maze, returns an Integer--
-- Identifica o meio do labirinto. 

mMaze :: Maze -> Int
mMaze m = div (length m) 2

-- | Given a Maze, returns an Integer--
--  Obtém o comprimento de uma linha do labirinto.

corridorsize :: Maze -> Int
corridorsize e = length (head e)


 -- | Turns a State into a new State
 -- | Altera os valores de um fantasma para o mandar para dentro da casa dos fantasmas (apenas se for fantasma).
 
telepo :: State -> State
telepo (State maze (x:(Ghost (GhoState (id,(a,b),s,o,p,v) l)):xs) l2) | even (mMaze maze) == True = (State maze (x:(Ghost (GhoState (id,((mMaze maze) - 1,div (corridorsize e) 2),s,o,p,v) Alive)):xs) l2)
                                                                      | otherwise = (State maze (x:(Ghost (GhoState (id,(mMaze maze,div (corridorsize maze) 2),s,o,p,v) Alive)):xs) l2)

 -- | Given a Player and a State, returns a State--
 ---------------------------------------------------------------------------------------
add :: Player -> State -> State
add y (State maze (x:xs) l) | (getPlayerID y) < (getPlayerID x) = (State maze (y:x:xs) l)
                            | otherwise = (State maze (x:(transform (add y (State maze (xs) l))):xs) l)

 -- | Given a Play and a State, returns a State--
 --
sidePacmanN :: Play -> State -> State  -- Dada uma direção e um movimento pretendido a função adequa o posicionamento do jogador para poder realizar o movimento.  
sidePacmanN (Move x y) (State maze [(Pacman (PacState (id,(a,b),s,o,p,v) t mo Normal))] l) | y == R && o == R = moveRN (convert (State maze [(Pacman (PacState (id,(a,b),s,o,p,v) t mo Normal))] l))
                                                                                           | y == R && o /= R  = (State maze [(Pacman (PacState (id,(a,b),s,R,p,v) t mo Normal))] l)
                                                                                           | y == L && o == L  = moveLN (State maze [(Pacman (PacState (id,(a,b),s,o,p,v) t mo Normal))] l)
                                                                                           | y == L && o /= L  = (State maze [(Pacman (PacState (id,(a,b),s,L,p,v) t mo Normal))] l)
                                                                                           | y == U && o == U  = moveUN (State maze [(Pacman (PacState (id,(a,b),s,o,p,v) t mo Normal))] l)
                                                                                           | y == U && o /= U  = (State maze [(Pacman (PacState (id,(a,b),s,U,p,v) t mo Normal))] l)
                                                                                           | y == D && o == D  = moveDN (State maze [(Pacman (PacState (id,(a,b),s,o,p,v) t mo Normal))] l)
                                                                                           | otherwise = (State maze [(Pacman (PacState (id,(a,b),s,D,p,v) t mo Normal))] l)

sidePacmanN (Move x y) (State maze [(Pacman (PacState (id,(a,b),s,o,p,v) t mo Mega))] l) | y == R && o == R = moveRN (convert (State maze [(Pacman (PacState (id,(a,b),s,o,p,v) t mo Mega))] l))
                                                                                         | y == R && o /= R = (State maze [(Pacman (PacState (id,(a,b),s,R,p,v) t mo Mega))] l)
                                                                                         | y == L && o == L = moveLN (State maze [(Pacman (PacState (id,(a,b),s,o,p,v) t mo Mega))] l)
                                                                                         | y == L && o /= L = (State maze [(Pacman (PacState (id,(a,b),s,L,p,v) t mo Mega))] l)
                                                                                         | y == U && o == U = moveUN (State maze [(Pacman (PacState (id,(a,b),s,o,p,v) t mo Mega))] l)
                                                                                         | y == U && o /= U = (State maze [(Pacman (PacState (id,(a,b),s,U,p,v) t mo Mega))] l)
                                                                                         | y == D && o == D = moveDN (State maze [(Pacman (PacState (id,(a,b),s,o,p,v) t mo Mega))] l)
                                                                                         | otherwise = (State maze [(Pacman (PacState (id,(a,b),s,D,p,v) t mo Mega))] l)
 -- | Turns a Piece into a Bool--
 -- | Verifica se uma peça é um fantasma.
isGhost :: Piece -> Bool
isGhost (PacPlayer (Ghost _)) = True
isGhost _ = False

-- | Verifica se um jogador é um fantasma.

isGhostV2 :: Player -> Bool
isGhostV2 (Ghost _) = True
isGhostV2 _ = False

 -- | Given a Maze and Coords (coordinates), it returns a Piece--
 -- | Deteta a peça que está nas coordenadas dadas.
detect :: Maze -> Coords -> Piece
detect x (a,b) = head (drop b (head (drop a x)))

-- | Posiciona os jogadores dentro do mapa com os respetivos States.

convert_state :: State -> State
convert_state (State maze (x:xs) l) = (State maze [x] l)
 -- | Turns a State into a State--
 --
moveRN :: State -> State -- - dado o estado do pacman devolve um novo estado quando este se move para a direita e embate numa peça
moveRN (State maze [(Pacman (PacState (id,(a,b),s,o,p,v) t mo Normal))] l)| b == (corridorsize e) -1 && even (length maze) && a == (mMaze m) -1 = (State maze [(Pacman (PacState (id,(a,0),s,o,p,v) t mo Normal))] l)
                                                                          | b == (corridorsize e) -1 && a == (mMaze m) = (State maze [(Pacman (PacState (id,(a,0),s,o,p,v)       t mo Normal))] l)
                                                                          | detect maze (a,b + 1) == Empty          = (State maze [(Pacman (PacState (id,(a,b + 1),s,o,p,v)      t mo Normal))] l)
                                                                          | detect maze (a,b + 1) == Food Little    = (State maze [(Pacman (PacState (id,(a,b + 1),s,o,p + 1 ,v) t mo Normal))] l)
                                                                          | detect maze (a,b + 1) == Food Big       = (State maze [(Pacman (PacState (id,(a,b + 1),s,o,p + 5 ,v) t mo Mega))]   l)
                                                                          | isGhost (detect maze (a,b + 1)) == True = if v >= 1 then (State maze [(Pacman (PacState (id,(a,b + 1),s,o,p,v - 1) t mo Normal))] l) else (State maze [(Pacman (PacState (id,(a,b),s,o,p,v) t mo Dying))] l)
                                                                          | otherwise = (State maze [(Pacman (PacState (id,(a,b),s,o,p,v) t mo Normal))] l)

moveRN (State maze [(Pacman (PacState (id,(a,b),s,o,p,v) t mo Mega))] l)  | b == (corridorsize e) -1 && even (length m) && a == (mMaze m) -1 = (State maze [(Pacman (PacState (id,(a,0),s,o,p,v) t m Mega))] l)
                                                                          | b == (corridorsize e) -1 && a == (mMaze m)                       = (State maze [(Pacman (PacState (id,(a,0),s,o,p,v)        t mo Mega))] l) 
                                                                          | detect maze (a,b + 1)  == Empty                                  = (State maze [(Pacman (PacState (id,(a,b + 1),s,o,p,v)       t mo Mega))] l)
                                                                          | detect maze (a,b + 1)  == Food Little                            = (State maze [(Pacman (PacState (id,(a,b + 1),s,o,p + 1  ,v) t mo Mega))] l)
                                                                          | detect maze (a,b + 1)  == Food Big                               = (State maze [(Pacman (PacState (id,(a,b + 1),s,o,p + 5  ,v) t mo Mega))] l)
                                                                          | isGhost (detect (maze (a,b + 1))) == True                        = (State maze [(Pacman (PacState (id,(a,b + 1),s,o,p + 10 ,v) t mo Mega))] l)
                                                                          | otherwise = (State maze [(Pacman (PacState (id,(a,b),s,o,p,v) t mo Mega))] l) 
 -- | Turns a State into a State--
 --
moveLN :: State -> State -- dado o estado do pacman devolve um novo estado quando este se move para a esquerda e embate numa peça
moveLN (State maze [(Pacman (PacState (id,(a,b),s,o,p,v) t mo Normal))] l)| b == 0 && even (length maze) && a == (mMaze m) -1 = (State maze [(Pacman (PacState (id,(a,(corridorsize e)- 1),s,o,p,v)      t mo Normal))] l)
                                                                          | b == 0 && a == (mMaze m)                          = (State maze [(Pacman (PacState (id,(a,(corridorsize e)- 1),s,o,p,v)     t mo Normal))] l)
                                                                          | detect maze (a,b - 1) == Empty                  = (State maze [(Pacman (PacState (id,(a,b - 1),s,o,p,v)      t mo Normal))] l)
                                                                          | detect maze (a,b - 1) == Food Little            = (State maze [(Pacman (PacState (id,(a,b - 1),s,o,p + 1 ,v) t mo Normal))] l)
                                                                          | detect maze (a,b - 1) == Food Big               = (State maze [(Pacman (PacState (id,(a,b - 1),s,o,p + 5 ,v) t mo Mega))]   l)
                                                                          | isGhost (detect maze (a,b - 1)) == True         = if v >= 1 then (State maze [(Pacman (PacState (id,(a,b - 1),s,o,p,v -1) t mo Normal))] l) else (State maze [(Pacman (PacState (id,(a,b),s,o,p,v) t mo Dying))] l)
                                                                          | otherwise = (State maze [(Pacman (PacState (id,(a,b),s,o,p,v) t mo Normal))] l) 

moveLN (State maze [(Pacman (PacState (id,(a,b),s,o,p,v) t mo Mega))] l)  | b == 0 && even (length m) && a == (mMaze m) -1 = (State maze [(Pacman (PacState (id,(a,(corridorsize e)- 1),s,o,p,v) t mo Mega))] l)
                                                                          | b == 0 && a == (mMaze m)                = (State maze [(Pacman (PacState (id,(a,(corridorsize e)- 1),s,o,p,v)     t mo Mega))] l)
                                                                          | detect maze (a,b - 1) == Empty          = (State maze [(Pacman (PacState (id,(a,b - 1),s,o,p,v)       t mo Mega))] l)
                                                                          | detect maze (a,b - 1) == Food Little    = (State maze [(Pacman (PacState (id,(a,b - 1),s,o,p + 1  ,v) t mo Mega))] l)
                                                                          | detect maze (a,b - 1) == Food Big       = (State maze [(Pacman (PacState (id,(a,b - 1),s,o,p + 5  ,v) t mo Mega))] l)
                                                                          | isGhost (detect maze (a,b - 1)) == True = (State maze [(Pacman (PacState (id,(a,b - 1),s,o,p + 10 ,v) t mo Mega))] l)
                                                                          | otherwise = (State maze [(Pacman (PacState (id,(a,b),s,o,p,v) t mo Mega))] l) 

 -- | Given a State, returns a State--
 --                                                                          
moveUN :: State -> State -- dado o estado do pacman devolve um novo estado quando este se move para cima e embate numa peça
moveUN (State maze [(Pacman (PacState (id,(a,b),s,o,p,v) t mo Normal))] l)| detect maze (a - 1,b) == Empty          = (State maze [(Pacman (PacState (id,(a - 1,b),s,o,p,v)      t mo Normal))] l)
                                                                          | detect maze (a - 1,b) == Food Little    = (State maze [(Pacman (PacState (id,(a - 1,b),s,o,p + 1 ,v) t mo Normal))] l)
                                                                          | detect maze (a - 1,b) == Food Big       = (State maze [(Pacman (PacState (id,(a - 1,b),s,o,p + 5 ,v) t mo Mega))]   l)
                                                                          | isGhost (detect maze (a - 1,b)) == True = if v >= 1 then (State maze [(Pacman (PacState (id,(a - 1,b),s,o,p,v-1) t mo Normal))] l) else (State maze [(Pacman (PacState (id,(a,b),s,o,p,v) t mo Dying))] l)
                                                                          | otherwise = (State maze [(Pacman (PacState (id,(a,b),s,o,p,v) t mo Normal))] l) 

moveUM (State maze [(Pacman (PacState (id,(a,b),s,o,p,v) t mo Mega))] l)  | detect maze (a - 1,b) == Empty          = (State maze [(Pacman (PacState (id,(a - 1,b),s,o,p,v)       t mo Mega))] l)
                                                                          | detect maze (a - 1,b) == Food Little    = (State maze [(Pacman (PacState (id,(a - 1,b),s,o,p + 1  ,v) t mo Mega))] l)
                                                                          | detect maze (a - 1,b) == Food Big       = (State maze [(Pacman (PacState (id,(a - 1,b),s,o,p + 5  ,v) t mo Mega))] l)
                                                                          | isGhost (detect maze (a - 1,b)) == True = (State maze [(Pacman (PacState (id,(a - 1,b),s,o,p + 10 ,v) t mo Mega))] l) 
                                                                          | otherwise = (State maze [(Pacman (PacState (id,(a,b),s,o,p,v) t mo Mega))] l)   

 -- | Turns a State into a State--
 --                                                                                                                                                 
moveDN :: State -> State  -- dado o estado do pacman devolve um novo estado quando este se move para baixo e embate numa peça
moveDN (State maze [(Pacman (PacState (id,(a,b),s,o,p,v) t mo Normal))] l)| detect maze (a + 1,b) == Empty          = (State maze [(Pacman (PacState (id,(a + 1,b),s,o,p,v)      t mo Normal))] l)
                                                                          | detect maze (a + 1,b) == Food Little    = (State maze [(Pacman (PacState (id,(a + 1,b),s,o,p + 1 ,v) t mo Normal))] l)
                                                                          | detect maze (a + 1,b) == Food Big       = (State maze [(Pacman (PacState (id,(a + 1,b),s,o,p + 5 ,v) t mo Mega))]   l)
                                                                          | isGhost (detect maze (a + 1,b)) == True = if v >= 1 then (State maze [(Pacman (PacState (id,(a + 1,b),s,o,p,v -1) t mo Normal))] l) else (State maze [(Pacman (PacState (id,(a,b),s,o,p,v) t mo Dying))] l)
                                                                          | otherwise = (State maze [(Pacman (PacState (id,(a,b),s,o,p,v) t mo Normal))] l)

moveDM (State maze [(Pacman (PacState (id,(a,b),s,o,p,v) t mo Mega))] l)  | detect maze (a + 1,b) == Empty          = (State maze [(Pacman (PacState (id,(a + 1,b),s,o,p,v)      t mo Mega))] l)
                                                                          | detect maze (a + 1,b) == Food Little    = (State maze [(Pacman (PacState (id,(a + 1,b),s,o,p + 1  ,v) t mo Mega))] l)
                                                                          | detect maze (a + 1,b) == Food Big       = (State maze [(Pacman (PacState (id,(a + 1,b),s,o,p + 5  ,v) t mo Mega))] l)
                                                                          | isGhost (detect maze (a + 1,b)) == True = (State maze [(Pacman (PacState (id,(a + 1,b),s,o,p + 10 ,v) t mo Mega))] l)
                                                                          | otherwise = (State maze [(Pacman (PacState (id,(a,b),s,o,p,v) t mo Mega))] l) 
{- Introdução: Esta Tarefa é responsável por formar o labirinto do jogo, sendo uma base para o objetivo global do jogo

- objetivo: O objetivo desta tarefa é implementar um mecanismo de geração de labirintos. Os inputs serão o número de corredores (horizontais) e o seu comprimento,
 e um número inteiro positivo para usar como semente num gerador pseudo-aleatório. O output deverá ser um labirinto impresso no formato como conhecemos.

- conclusão: Achamos que foi uma tarefa desafiadora -}



  
 -- | Seed's pseudo-generator: Given a certain seed, returns a list of n integer randomly generated
 -- 
genRandoms :: Int -> Int -> [Int]
genRandoms :: Int -> Int -> [Int]
genRandoms n seed = let gen = mkStdGen seed                   -- creates a random generator
                        in take n $ randomRs (0,99) gen       -- takes the first n elements from an infinite series of random numbers between 0-9


 -- Converts a list into a list of list of size n
 --
subList :: Int -> [a] -> [[a]]
subList _ [] = []                   
subList n l  = take n l: subList n (drop n l)


 -- | Given the maze's length, it assigns a certain corridor to be made only by Wall pieces.
 -- descreve como devem ser formados os corredores  (vertical) nos seus limites, para mais tarde formar as paredes que delimitam o labirinto 
hWall :: Corridor -> Corridor
hWall []    = []
hWall (h:t) = [Wall] ++ hWall t

 
 -- descreve como devem ser formados os corredores (horizontal) nos seus limites, para mais tarde formar as paredes que delimitam o labirinto 
vWall :: Corridor -> Corridor
vWall [] = []
vWall x  = ([Wall] ++ (init (tail x) ) ++ [Wall])

vvWall :: Maze -> Maze
vvWall []    = []
vvWall (h:t) = vWall h : vvWall t


 -- | Converts a Corridor to a string 
 -- 
showCorridor :: Corridor -> String
showCorridor[]      = "\n"
showCorridor (p:ps) = show p ++ showCorridor ps

 
 -- | Converts a n integer into a piece, depending on its value.
 -- Dado um inteiro, converte o número numa peça do jogo 
convertPiece :: Int -> Piece
convertPiece n  | n == 3            = Food Big 
                | n >= 0 && n < 70  = Food Little 
                | otherwise         = Wall


 -- | Converts a list of integers into a Corridor
 -- Converte uma lista para peças que formam um corredor
convertCorridor :: [Int] -> Corridor
convertCorridor []     = []
convertCorridor (p:ps) = convertPiece p : (convertCorridor ps)


 -- 
 -- Mostrar o labirinto
displayMaze :: Maze ->  IO ()
displayMaze m = putStr $ showMaze m 


 -- | Converts a list of lists of integers into a Maze
 -- 
convertMaze :: [[Int]] -> Maze
convertMaze []       = []    
convertMaze (ns:nss) = ([Wall] ++ convertCorridor ns ++ [Wall]) : convertMaze nss


 -- 
 --
showMaze :: Maze -> String 
showMaze []     = ""
showMaze (c:cs) = showCorridor c ++ showMaze cs


 -- 
 -- abertura das laterais dos corredores do meio
access:: Maze -> [Corridor]
access x | even (length x) = take 2 (drop ((middleHeight x) - 1) x)
         | otherwise       = take 1 (drop (middleHeight x) x)


 -- | Given a list of Corridors, it returns a list of Corridors 
 -- parte paredes 
removeWall :: [Corridor] -> [Corridor]
removeWall []     = []
removeWall (x:xs) = ([Empty] ++ (init(tail x)) ++ [Empty]) : removeWall xs


 -- 
 --coloca o tunel no labirinto 
colocatunel :: Maze -> Maze
colocatunel x | even (length x) = (take ((middleHeight x) - 1) x) ++ (removeWall (access x)) ++ (drop ((middleHeight x) + 1) x)
              | otherwise       = (take (middleHeight x) (x)) ++ (removeWall (access x)) ++ drop ((middleHeight x) + 1) x


 --
 --
genMaze1 :: Int -> Int -> Int -> IO ()
genMaze1 x y s =
                 let random_nrs = genRandoms((x-2)*(y-2)) s
                 in putStrLn $ showMaze $ convertMaze $ subList x random_nrs

                 --genMaze seed = genCor l seed : genMaze l (seed) 



 -- | Given the length, height and seed, it returns the maze's interior, without the walls
 -- 
innerZone :: Int -> Int -> Int -> Maze                        
innerZone l h seed = convertMaze (subList l (genRandoms (1*h) seed))


 -- | Given the maze, it returns an integer 
 -- descobre a metade da altura
middleHeight :: Maze -> Int                      
middleHeight maze = div (length maze) 2


 -- | Given a corridor, it returns its middle length
breakCorridor :: Corridor -> Int
breakCorridor x = div (length x) 2


-- deteta os corredores que se encontram a meio da altura do labirinto
middleCorridors :: Maze -> [Corridor]                     
middleCorridors maze | even (length maze) = take 2 (drop ((middleHeight maze)-1) maze)
                     | otherwise          = take 1 (drop (middleHeight maze) maze)

 
 --abre o tunel (um ou dois corredores sem peças nas laterais)
openTunnel :: Maze -> Maze  
openTunnel maze | even (length maze) = (take (midH-1) maze) ++ tunnel ++ drop (midH + 1) maze
                | otherwise          =  (take midH maze) ++ tunnel ++ drop (midH + 1) maze
            where midH   = middleHeight maze 
                  tunnel = removeWall (middleCorridors maze)

-- cria um corredor vazio acima da entrada da casa dos fantasmas para que estes possam entrar e sair livremente 
houseRoof :: Corridor -> Corridor -- 
houseRoof x | even (length x) = (take ((breakCorridor x) - 5) x) ++ onlyflooreven ++ (drop ((breakCorridor x) + 5) x)
            | otherwise       = (take ((breakCorridor x) - 5) x) ++ onlyfloorodd ++ (drop ((breakCorridor x) + 6) x)
       where onlyflooreven    = take 10 (repeat Empty)
             onlyfloorodd     = take 11 (repeat Empty)


changeCorridor2 :: Corridor -> Corridor
changeCorridor2 [] = []
changeCorridor2 x | even (length x)   = (take ((breakCorridor  x) - 5) x) ++ [Empty] ++ [Wall] ++ [Wall] ++ [Wall] ++ [Empty] ++ [Empty] ++ [Wall] ++ [Wall] ++ [Wall] ++ [Empty] ++ (drop ((breakCorridor x) + 5) x)
                  | otherwise         = (take ((breakCorridor x) - 5) x) ++ [Empty] ++ [Wall] ++ [Wall] ++ [Wall] ++ [Empty] ++ [Empty] ++ [Empty] ++ [Wall] ++ [Wall] ++ [Wall] ++ [Empty] ++ (drop ((breakCorridor x) + 6) x)


-- cria o corredor com a entrada para a casa dos fantasmas
houseDoor :: Corridor -> Corridor
houseDoor x | even (length x) = (take ((breakCorridor x) - 5) x) ++ holeeven ++ (drop ((breakCorridor x) + 5) x)
            | otherwise       = (take ((breakCorridor x) - 5) x) ++ holeodd ++ (drop ((breakCorridor x) + 6) x)
            where holeodd     = [Empty] ++ take 3 (repeat Wall) ++ take 3 (repeat Empty) ++ take 3 (repeat Wall)
                  holeeven    = [Empty] ++ take 3 (repeat Wall) ++ take 2 (repeat Empty) ++ take 3 (repeat Wall)

-- cria o interior da casa dos fantasmas (espaço vazio dentro da mesma aonde os fantasmas perambularão)
houseInterior :: Corridor -> Corridor
houseInterior x | even (length x) = (take ((breakCorridor x) - 5) x) ++ holeeven ++ (drop ((breakCorridor x) + 5) x)
                | otherwise       = (take ((breakCorridor x) - 5) x) ++ holeodd ++ (drop ((breakCorridor x) + 6) x)
                where holeodd     = [Empty] ++ [Wall] ++ take 7 (repeat Empty) ++ [Wall] ++ [Empty]
                      holeeven    = [Empty] ++ [Wall] ++ take 6 (repeat Empty) ++ [Wall] ++ [Empty]

-- cria o "chão" da casa dos fantasmas (corredor que termina a casa. tamanho altera se o length é par ou ímpar)
houseFloor :: Corridor -> Corridor
houseFloor x | even (length x) = (take ((breakCorridor x) - 5) x) ++ holeeven ++ (drop ((breakCorridor x) + 5) x)
             | otherwise       = (take ((breakCorridor x) - 5) x) ++ holeodd ++ (drop ((breakCorridor x) + 6) x)
             where holeeven    = [Empty] ++ take 8 (repeat Wall) ++ [Empty] 
                   holeodd     = [Empty] ++ take 9 (repeat Wall) ++ [Empty]

-- junta todos os elementos da casa fantasma 
buildHouse :: Maze -> Maze
buildHouse [] = []
buildHouse (x:y:z:t:h:xs) = (houseRoof x) : (changeCorridor2 y) : (houseInterior z) : (houseFloor t) : (houseRoof h) : (buildHouse xs)


accessHouse :: Maze -> [Corridor]
accessHouse x | even (length x) = take 5 (drop ((middleHeight x) - 3) x)
              | otherwise       = take 5 (drop ((middleHeight x) - 2) x)

--posiciona a casa dos fantasmas no meio da altura do labirinto
housepos :: Maze -> [Corridor]
housepos maze | even (length maze) = take 5 (drop ((middleHeight maze) - 3) maze)
              | otherwise = take 5 (drop ((middleHeight maze) - 2) maze)

-- coloca a casa fantasma no labirinto 
putHouse :: Maze -> Maze
putHouse   x | even (length x) = (take ((middleHeight x) - 3) x) ++ (buildHouse (accessHouse x)) ++ (drop ((middleHeight x) + 3) x)
             | otherwise       = (take ((middleHeight x) - 2) x) ++ (buildHouse (accessHouse x)) ++ drop ((middleHeight x) + 3) x


-- gera um labirinto pseudo-aleatório com as dimensões desejadas.
generateMaze :: Int -> Int -> Int -> IO ()
generateMaze x y s = putStrLn $ tra2 x y s 

--funções auxiliares para consolidar a montagem do labirinto
tra2 :: Int -> Int -> Int -> String
tra2 x y s = printMaze $ tra8 x y s 

tra3 :: Int -> Int -> Int -> Maze
tra3 x y s = (genMaze2 x y s)

tra8 :: Int -> Int -> Int -> Maze  
tra8 x y s = putHouse (tra7 x y s)

tra6 :: Maze -> Maze
tra6 [] = []
tra6 (x:xs) = [hWall x] ++ (init xs) ++ [ hWall (last xs)]

final :: Int -> Int -> Int -> Maze
final x y s = tra6 (tra3 x y s)

tra7 :: Int -> Int -> Int -> Maze
tra7 x y s = colocatunel $ final x y s 

genMaze2 :: Int -> Int -> Int -> Maze
genMaze2 x y s =
                 let random_nrs = genRandoms ((x-2)*(y-2)) s
                 in convertMaze $ subList x random_nrs
--

--placeHouseOdd :: [Corridor] -> [Corridor] -> [Corridor]
placeHouseOdd (c:cs) (h:hs) = ((take (div ((length c) - 11) 2) c) ++ h ++ (drop ((div ((length c) - 11) 2) + 11) c)) --posiciona corretamente a casa dos fantasmas no meio do labirinto quando o length é ímpar
placeHouseOdd _ _ = []

placeHouseEven :: Maze -> Maze -> Corridor    --posiciona corretamente a casa dos fantasmas no meio do labirinto quando o length é par
placeHouseEven (c:cs) (h:hs) = ((take (div ((length c) - 10) 2) c) ++ h ++ (drop ((div ((length c) - 10) 2) + 10) c))
placeHouseEven _ _ = []


data Manager = Manager 
    {   
        state   :: State
    ,    pid    :: Int
    ,    step   :: Int
    ,    before :: Integer
    ,    delta  :: Integer
    ,    delay  :: Integer
    } 


loadManager :: Manager
loadManager = ( Manager (loadMaze "maps/1.txt") 0 0 0 0 defaultDelayTime )

updateControlledPlayer :: Key -> Manager -> Manager 
updateControlledPlayer keyLeftArrow  (Manager (State maze (x:xs) l) pid step before delta delay) = (Manager (State maze (changeStateOr 3 (x:xs)) l) pid step before delta delay) 
updateControlledPlayer keyRightArrow (Manager (State maze (x:xs) l) pid step before delta delay) = (Manager (State maze (changeStateOr 4 (x:xs)) l) pid step before delta delay)
updateControlledPlayer keyUpArrow    (Manager (State maze (x:xs) l) pid step before delta delay) = (Manager (State maze (changeStateOr 2 (x:xs)) l) pid step before delta delay)
updateControlledPlayer keyDownArrow  (Manager (State maze (x:xs) l) pid step before delta delay) = (Manager (State maze (changeStateOr 1 (x:xs)) l) pid step before delta delay)

updateScreen :: Window  -> ColorID -> Manager -> Curses ()
updateScreen w a man =
                  do
                    updateWindow w $ do
                      clear
                      setColor a
                      moveCursor 0 0 
                      drawString $ show (state man)
                    render
     
currentTime :: IO Integer
currentTime = fmap ( round . (* 1000) ) getPOSIXTime

updateTime :: Integer -> Manager -> Manager
updateTime now man = manager (state man)
                             (pid man)
                             (step man)
                             now 
                             (delta man) + (now - before man)
                             (delay man)

resetTimer :: Integer -> Manager -> Manager
resetTimer now (Manager state pid step before delta delay) = (Manager state pid 0 0 0 delay) 

nextFrame :: Integer -> Manager -> Manager
nextFrame now (Manager state pid step before delta delay) =  (Manager (passTime step (megaState state)) pid (step + 1) now 0 delay)                    -- tenho de aplicar a função do manager

loop :: Window -> Manager -> Curses ()                      -- define cores   
loop w man@(Manager s pid step bf delt del ) = do 
  color_schema <- newColorID ColorBlue ColorWhite  10
  now <- liftIO  currentTime
  updateScreen w  color_schema man
  if ( delt > del )             -- delt é o periodo de tempo que passou desde que vi o tempo pela ultima vez 
    then loop w $ nextFrame now man           -- resultado que atualiza o tempo
    else do
          ev <- getEvent w $ Just 0
          case ev of
                Nothing -> loop w (updateTime now man)    -- mede tempo
                Just (EventSpecialKey arrow ) -> loop w $ updateControlledPlayer arrow (updateTime now man)
                Just ev' ->
                  if (ev' == EventCharacter 'q')
                    then return ()
                    else loop w (updateTime now man)

main :: IO ()
main =
  runCurses $ do
    setEcho False
    setCursorMode CursorInvisible
    w <- defaultWindow
    loop w loadManager



loadMaze :: String -> State
loadMaze filepath = unsafePerformIO $ readStateFromFile filepath



readStateFromFile :: String -> IO State
readStateFromFile f = do
                content <- readFile f
                let llines = lines content 
                    (new_map,pl) = convertLinesToPiece llines 0 []
                return (State new_map pl 1)



convertLinesToPiece :: [String] -> Int -> [Player] -> (Maze,[Player])
convertLinesToPiece [] _ l = ([],l)
convertLinesToPiece (x:xs) n l  = let (a,b) = convertLineToPiece x n 0 l 
                                      (a1,b1) = convertLinesToPiece xs (n+1) b
                                  in (a:a1,b1)

convertLineToPiece :: String -> Int -> Int -> [Player] -> ([Piece],[Player])
convertLineToPiece [] _ _ l = ([],l)
convertLineToPiece (z:zs) x y l = let (a,b ) = charToPiece z x y l
                                      (a1,b1) = convertLineToPiece zs x (y+1) b 
                                  in (a:a1,b1)


charToPiece :: Char -> Int -> Int -> [Player] -> (Piece,[Player])
charToPiece c x y l
    | c == '{' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Open Normal ))   :l) )
    | c == '<' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Closed Normal )) :l) )
    | c == '}' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, L,0,1 ) 0 Open Normal ))   :l) )
    | c == '>' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, L,0,1 ) 0 Closed Normal )) :l) )
    | c == 'V' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, U,0,1 ) 0 Open Normal ))   :l) )
    | c == 'v' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, U,0,1 ) 0 Closed Normal )) :l) )
    | c == '^' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, D,0,1 ) 0 Open Normal ))   :l) )
    | c == '|' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, D,0,1 ) 0 Closed Normal )) :l) )
    | c == 'X' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Open Dying ))    :l) )
    | c == 'M' =  (Empty, ((Ghost (  GhoState (length l,(x,y),0,Null,0,1 ) Alive))            :l) )
    | c == '?' =  (Empty, ((Ghost (  GhoState (length l,(x,y),0,Null,0,1 ) Dead))             :l) )
    | c == 'o' =  (Food Big,l)
    | c == '.' =  (Food Little,l)
    | c == '#' =  (Wall,l)
    | otherwise = (Empty,l)
-- | Este módulo contém todos os tipos das tarefas


-- | Data que representa um estado  
data State = State 
    {
        maze :: Maze
    ,   playersState :: [Player]
    ,   level :: Int
    }
-- | Tipo que representa um labirinto, ou seja, lista de corridores
type Maze = [Corridor]
-- | Tipo que representa um corridor, ou seja, lista de peças
type Corridor = [Piece]
-- | Data que indica todas as peças do jogo
data Piece =  Food FoodType | PacPlayer Player| Empty | Wall deriving (Eq)
-- | Data que indica os papeis que um jogador pode assumir no jogo (Pacman ou Ghost)
data Player =  Pacman PacState | Ghost GhoState deriving (Eq)
-- | Data que indica as ações que ocorrem no jogo
data Action = EmptySlot | Eat FoodType | HitWall | LoseLife | Death | EatGhost | PacmanPlayer   deriving (Show)

-- | Data que indica todas as orientações que um jogador pode assumir
data Orientation = L | R | U | D | Null deriving (Eq,Show)
-- | Data que representa o estado de um pacman
data PacState= PacState 
    {   
        pacState :: PlayerState
    ,   timeMega :: Double
    ,   openClosed :: Mouth
    ,   pacmanMode :: PacMode
    
    } deriving Eq

-- | Data que representa o estado de um fantasma
data GhoState= GhoState 
    {
        ghostState :: PlayerState
    ,   ghostMode :: GhostMode
    } deriving Eq

-- | Tipo que representa as coordenadas
type Coords = (Int,Int)
-- | Tipo que representa um PlayerState
type PlayerState = (Int, Coords, Double , Orientation, Int, Int)
--                 (ID,  (x,y), velocity, orientation, points, lives) 
-- | Data que indica o estado da boca (aberta ou fechada)
data Mouth = Open | Closed deriving (Eq,Show)
-- | Data que indica o modo de um pacman
data PacMode = Dying | Mega | Normal deriving (Eq,Show)
-- | Data que indica o modo de um ghost
data GhostMode = Dead  | Alive deriving (Eq,Show)
-- | Data que indica se uma comida é grande ou pequena
data FoodType = Big | Little deriving (Eq)
-- | Data que indica as cores
data Color = Blue | Green | Purple | Red | Yellow | None deriving Eq 

-- | Data que representa uma jogada
data Play = Move Int Orientation deriving (Eq,Show)

-- | Tipo que representa uma lista de Instruction
type Instructions = [Instruction]

-- | Data que representa uma instruction
data Instruction = Instruct [(Int, Piece)]
                 | Repeat Int deriving (Show, Eq)



instance Show State where
  show (State m ps p) = printMaze mz ++ "Level: " ++ show p ++ "\nPlayers: \n" ++ (foldr (++) "\n" (map (\y-> printPlayerStats y) ps))
                          where mz = placePlayersOnMap ps m

instance Show PacState where
   show ( PacState s o m Dying  ) =  "X"
   show ( PacState (a,b,c,R,i,l) _ Open m  ) =  "{"
   show ( PacState (a,b,c,R,i,l) _ Closed m  ) =  "<"
   show ( PacState (a,b,c,L,i,l) _ Open m  ) =  "}"
   show ( PacState (a,b,c,L,i,l) _ Closed m  ) =  ">"
   show ( PacState (a,b,c,U,i,l) _ Open m  ) =  "V"
   show ( PacState (a,b,c,U,i,l) _ Closed m  ) =  "v"
   show ( PacState (a,b,c,D,i,l) _ Open m  ) =  "^"
   show ( PacState (a,b,c,D,i,l) _ Closed m  ) =  "|"
   show ( PacState (a,b,c,Null,i,l) _ Closed m  ) =  "<"
   show ( PacState (a,b,c,Null,i,l) _ Open m  ) =  "{"

instance Show Player where
   show (Pacman x ) =  show x
   show ( Ghost x ) =   show x

instance Show GhoState where
   show (GhoState x Dead ) =  "?"
   show (GhoState x Alive ) =  "M"

instance Show FoodType where
   show ( Big ) =  "o"
   show ( Little ) =  "."

instance Show Piece where
   show (  Wall ) = coloredString "#" None
   show (  Empty ) = coloredString " " None
   show (  Food z ) = coloredString (show z )   Green
   show ( PacPlayer ( Pacman ( PacState (i, c, x, y,z,l) o m Normal ) ) ) = coloredString (show ( PacState (i, c, x, y,z,l) o m Normal)  ) Yellow
   show ( PacPlayer ( Pacman ( PacState (i, c, x, y,z,l) o m Mega   ) ) ) = coloredString (show ( PacState (i, c, x, y,z,l) o m Mega)  ) Blue
   show ( PacPlayer ( Pacman ( PacState (i, c, x, y,z,l) o m Dying   ) ) ) = coloredString (show ( PacState (i, c, x, y,z,l) o m Dying)  ) Red
   show ( PacPlayer (Ghost z) ) = coloredString (show z)  Purple


-- | Função que dada uma string e um cor, colore a string
coloredString :: String -> Color -> String
coloredString x y = x
{-
    | y == Blue ="\x1b[36m" ++  x ++ "\x1b[0m"
    | y == Red = "\x1b[31m" ++ x ++ "\x1b[0m"
    | y == Green = "\x1b[32m" ++ x ++ "\x1b[0m"
    | y == Purple ="\x1b[35m" ++ x ++ "\x1b[0m"
    | y == Yellow ="\x1b[33m" ++ x ++ "\x1b[0m"
    | otherwise =  "\x1b[0m" ++ x 
-}

-- | Função que coloca os jogadores no labirinto
placePlayersOnMap :: [Player] -> Maze -> Maze
placePlayersOnMap [] x = x
placePlayersOnMap (x:xs) m = placePlayersOnMap xs ( replaceElemInMaze (getPlayerCoords x) (PacPlayer x) m )

-- | Função que dado um labirinto transforma-o em string
printMaze :: Maze -> String
printMaze []  =  ""
printMaze (x:xs) = foldr (++) "" ( map (\y -> show y) x )  ++ "\n" ++ printMaze ( xs )

-- | Função que dado um jogador transforma em string o seu playerstate, as vidas, etc..
printPlayerStats :: Player -> String
printPlayerStats p = let (a,b,c,d,e,l) = getPlayerState p
                     in "ID:" ++ show a ++  " Points:" ++ show e ++ " Lives:" ++ show l ++"\n"

-- | Função que dado um jogador retorna o seu id
getPlayerID :: Player -> Int
getPlayerID (Pacman (PacState (x,y,z,t,h,l) q c d )) = x
getPlayerID  (Ghost (GhoState (x,y,z,t,h,l) q )) = x

-- | Função que dado um jogador retorna os seus pontos
getPlayerPoints :: Player -> Int
getPlayerPoints (Pacman (PacState (x,y,z,t,h,l) q c d )) = h
getPlayerPoints (Ghost (GhoState (x,y,z,t,h,l) q )) = h

-- | Função que dado um jogador jogador e umas coordenadas, atualiza o jogador com as coordenadas dadas
setPlayerCoords :: Player -> Coords -> Player
setPlayerCoords (Pacman (PacState (x,y,z,t,h,l) q c d )) (a,b) = Pacman (PacState (x,(a,b),z,t,h,l) q c d )
setPlayerCoords (Ghost (GhoState (x,y,z,t,h,l) q )) (a,b) = Ghost (GhoState (x,(a,b),z,t,h,l) q )
 
-- | Função que dada uma peça retorna a sua orientação
getPieceOrientation :: Piece -> Orientation
getPieceOrientation (PacPlayer p) =  getPlayerOrientation p
getPieceOrientation _ = Null

-- | Função que dado um jogador pacman retorna o modo do pacman
getPacmanMode :: Player -> PacMode
getPacmanMode (Pacman (PacState a b c d)) = d

getGhostMode :: Player -> GhostMode
getGhostMode (Ghost (GhoState a b )) = b

-- | Função que dado um jogador retorna o seu playerstate  
getPlayerState :: Player -> PlayerState
getPlayerState (Pacman (PacState a b c d )) = a
getPlayerState (Ghost (GhoState a b )) = a

getPlayerLives :: Player -> Int
getPlayerLives (Pacman (PacState (x,y,z,t,h,l) q c d )) = l 
getPlayerLives  (Ghost (GhoState (x,y,z,t,h,l) q )) = l

getPlayerVelocity :: Player -> Double
getPlayerVelocity (Pacman (PacState (x,y,z,t,h,l) q c d )) = z
getPlayerVelocity (Ghost (GhoState (x,y,z,t,h,l) q )) = z

-- | Função que dado um jogador retorna a sua orientação
getPlayerOrientation :: Player -> Orientation
getPlayerOrientation (Pacman (PacState (x,y,z,t,h,l) q c d )) = t
getPlayerOrientation  (Ghost (GhoState (x,y,z,t,h,l) q )) = t

-- | Função que substitui uma peça nas coordenadas dadas
replaceElemInMaze :: Coords -> Piece -> Maze -> Maze
replaceElemInMaze (a,b) _ [] = []
replaceElemInMaze (a,b) p (x:xs) 
  | a == 0 = replaceNElem b p x : xs 
  | otherwise = x : replaceElemInMaze (a-1,b) p xs

-- | Função auxiliar para a replaceElemInMaze
replaceNElem :: Int -> a -> [a] -> [a]
replaceNElem i _ [] = [] 
replaceNElem i el (x:xs)
  |  i == 0 = el : xs 
  | otherwise =  x : replaceNElem (i-1) el xs

-- | Função que dado um jogador retorna as suas coordenadas
getPlayerCoords :: Player -> Coords
getPlayerCoords (Pacman (PacState (x,y,z,t,h,l) b c d )) = y
getPlayerCoords (Ghost (GhoState (x,y,z,t,h,l) b )) = y

-- | Função que nos dá o "meio" do Labirinto
getMiddle :: Maze -> Int
getMiddle x = div (length x) 2

-- | Função que retorna o pacman da lista de players
getPacman :: [Player] -> Player
getPacman (Pacman p : xs) = Pacman p
getPacman (x:xs) = getPacman xs 

-- | Função que retorna o id do pacman da lista de players
getPacID :: [Player] -> Int
getPacID (Pacman (PacState (a,(x,y),b,ori,c,d) tm m pm) : xs) = a
getPacID (x:xs) = getPacID xs

-- | Função que verifica se um player é pacman ou não, retornando um bool
isPacman :: Player -> Bool
isPacman (Pacman _) = True
isPacman (Ghost _) = False

-- | Função que verifica se pacman está em modo mega ou não, retornando um bool
isMega :: Player -> Bool
isMega (Pacman (PacState _ _ _ Mega)) = True
isMega _ = False

-- | Função que retorna o estado da boca de um pacman
getMouth :: Player -> Mouth
getMouth (Pacman (PacState _ _ m _)) = m

-- | Função que retorna o tempo mega do pacman
getTimeMega :: [Player] -> Double
getTimeMega (Pacman (PacState _ tm _ _):xs) = tm
getTimeMega (x:xs) = getTimeMega xs

-- | Função que compara coordenadas e retorna uma booliano
compareCoords :: Coords -> Coords -> Bool 
compareCoords (x1,y1) (x2,y2) = x1==x2 && y1==y2

-- | Função que reduz o tempo mega consoante a variável passada como argumento
updateTimeMega :: Double -> Player -> Player
updateTimeMega x (Pacman (PacState ps tm m pm)) = Pacman (PacState ps (tm-x) m pm)

-- | Função que reduz o tempo mega de um pacman aplicada a uma lista
reduceTimeMega :: [Player] -> [Player]
reduceTimeMega [] = []
reduceTimeMega (x:xs)
 | isPacman x = updateTimeMega 250 x : xs
 | otherwise = x : reduceTimeMega xs

-- | Função que aplica a __reduceTimeMega__ a um state
reduceTimeMegaState :: State -> State
reduceTimeMegaState (State m pls lvl) = State m (reduceTimeMega pls) lvl

-- | Função que dá as coordenadas de um pacman através de uma lista
getPacmanCoords :: [Player] -> Coords
getPacmanCoords ((Pacman (PacState (x,y,z,t,h,l) q c d )):xs) = y
getPacmanCoords (x:xs) = getPacmanCoords xs 

-- | Função que calcula a distância perante duas coordenadas
distance :: Coords -> Coords -> Float
distance (x1,y1) (x2,y2) = sqrt ((fromIntegral x1 - fromIntegral x2)^2 + (fromIntegral y1 - fromIntegral y2)^2)

-- | Função que dá a lista dos fantasmas de um state
getGhosts :: State -> [Player]
getGhosts (State m [] lvl) = []
getGhosts (State m (Ghost (GhoState ps gm) : xs ) lvl) = Ghost (GhoState ps gm) : getGhosts (State m xs lvl)
getGhosts (State m (x:xs) lvl) = getGhosts (State m xs lvl) 

-- | Função que dá a lista dos fantasmas vivos de um state
getGhostsAlive :: State -> [Player]
getGhostsAlive (State m [] lvl) = []
getGhostsAlive (State m (Ghost (GhoState ps Alive) : xs ) lvl) = Ghost (GhoState ps Alive) : getGhosts (State m xs lvl)
getGhostsAlive (State m (x:xs) lvl) = getGhosts (State m xs lvl) 

-- | Função que dá a lista de coordenadas dos fantasmas
ghostCoords :: [Player] -> [Coords]
ghostCoords [] = []
ghostCoords (x:xs) = getPlayerCoords x : ghostCoords xs

-- | Função que verifica se há ghost Alive 
checkGhostsAlive :: [Player] -> Bool
checkGhostsAlive [] = False
checkGhostsAlive (Ghost (GhoState ps Alive) : xs) = True
checkGhostsAlive (x:xs) = checkGhostsAlive xs







{- |

= Introdução 
Nesta tarefa, o objetivo principal era implementar um bot eficaz que obedecia a determinados 
comportamentos, dependendo da condição a que está sujeito. Para a sua realização, apoiamo-nos
em raciocínios semelhantes aos da tarefa5.

= Objetivos
De modo a realizarmos um bot eficaz, começamos por pensar nas condições a que este podia estar sujeito.
Portanto, decidimos diversas estratégias para quando o bot se depara com uma parede, quando o pacman está em modo Mega, 
quando o fantasma mais próximo se encontra num determinado raio e quando existe comida pequena e grande em volta do bot.

Estratégia quando a próxima peça é parede : Para este caso, decidimos calcular as orientações em que não tem parede e, por
conseguinte, calculamos destas orientações a que se encontra mais longe do fantasma mais próximo.

Estratégia quando está em modo Mega : Dividimos este caso em duas possíveis movimentações: uma em que o pacman e está em
modo Mega e existe pelo menos um fantasma vivo; e o outra em que o pacman está em Mega mas não existem fantasmas vivos. Para
a primeira, decidimos aplicar a estratégia usada para quando a próxima peça é parede. Para a segunda, decidimos aplicar uma 
estratégia semelhante a esta, só que difere no facto de em vez de escolher a orientação mais longe do fantasma mais próximo, escolhe
a orientação mais perto deste fantasma.

Estratégia quando o fantasma mais próximo está dentro de um raio : Neste caso, definimos uma distância de 5 unidades para o raio e,
quando o fantasma mais próxima se encontra numa distância ao pacman inferior a esse valor, então aciona o mecanismo de começar a fugir
que corresponde, novamente, à estratégia utilizada para quando é parede.

Estratégia quando existem comidas em volta do pacman: Neste caso, dividimos em dois estratégias análogas uma para a food big e outra 
para a food little, dando prioridade à food big. Fizemos uma função que verifica se existe comida em volta, em caso afirmativo dirige-se 
para a comida. Em caso negativo, mantém a orientação.

= Discussão e conclusão
Em conclusão, pensamos que poderiamos ter melhorado e aperfeiçoado certos aspetos do bot. No entanto, achamos que conseguimos realizar  
uma estratégia boa e eficaz para o bot.

-}



-- | Função principal que determina uma jogada segundo um state
bot :: Int -> State -> Maybe Play 
bot id s@(State m pls lvl) 
 | isWall s id = Just (Move id bestOriToRun)
 | (isMega (getPacman pls) && (checkGhostsAlive pls)) && not (insideTheRay rayAlive) = Just (Move id bestOriToChase)
 | (isMega (getPacman pls) && (checkGhostsAlive pls)) && insideTheRay rayAlive = Just (Move id bestOriToRun)
 | isMega (getPacman pls) && not (checkGhostsAlive pls) = Just (Move id bestOriToChase)
 | foodBigArea m (getPacmanCoords pls) = Just (goToFoodBig m id (getPacmanCoords pls) (getPlayerOrientation (getPacman pls)))
 | insideTheRay ray = Just (Move id bestOriToRun)
 | foodLittleArea m (getPacmanCoords pls) = Just (goToFoodLittle m id (getPacmanCoords pls) (getPlayerOrientation (getPacman pls)))
 | otherwise = Just (Move id (getPlayerOrientation (getPacman pls)))
             where bestOriToRun = bestOriToRunWithoutWall (oriWithoutWallsforBot m (getPlayerCoords (closestGhost (getPacman pls) (getGhosts s))) (fourCoords (getPacmanCoords pls)))
                   bestOriToChase = bestOriToChaseWithoutWall (oriWithoutWallsforBot m (getPlayerCoords (closestGhost (getPacman pls) (getGhosts s))) (fourCoords (getPacmanCoords pls)))
                   ray = (distanceToGhosts (getPacmanCoords pls) (ghostCoords (getGhosts s)))
                   rayAlive = (distanceToGhosts (getPacmanCoords pls) (ghostCoords (getGhostsAlive s)))

-- | Função que determina a lista das distâncias do pacman aos ghosts
distanceToGhosts :: Coords -> [Coords] -> [Float] 
distanceToGhosts _ [] = []
distanceToGhosts (x1,y1) ((x2,y2):xs) = (distance (x1,y1) (x2,y2)) : distanceToGhosts (x1,y1) xs

-- | Função que verifica se algum ghost está dentro do valor do raio
insideTheRay :: [Float] -> Bool
insideTheRay [] = False
insideTheRay (x:xs)
 | x < 7 = True
 | otherwise = insideTheRay xs

-- | Função que retorna uma play em direção à comida grande
goToFoodBig :: Maze -> Int -> Coords -> Orientation -> Play 
goToFoodBig m id (x,y) ori
 | getPiece m (orientationAux ori (x,y)) == (Food Big) = (Move id ori)
 | getPiece m (x+1,y) == (Food Big) = Move id D
 | getPiece m (x-1,y) == (Food Big) = Move id U
 | getPiece m (x,y+1) == (Food Big) = Move id R
 | getPiece m (x,y-1) == (Food Big) = Move id L

-- | Função que verifica se tem comida grande em volta do pacman
foodBigArea :: Maze -> Coords -> Bool
foodBigArea m (x,y)
 | getPiece m (x+1,y) == (Food Big) = True
 | getPiece m (x-1,y) == (Food Big) = True
 | getPiece m (x,y+1) == (Food Big) = True
 | getPiece m (x,y-1) == (Food Big) = True
 | otherwise = False

-- | Função que retorna uma play em direção à comida pequena
goToFoodLittle :: Maze -> Int -> Coords -> Orientation -> Play
goToFoodLittle m id (x,y) ori
 | getPiece m (orientationAux ori (x,y)) == (Food Little) = (Move id ori)
 | getPiece m (x+1,y) == (Food Little) = Move id D
 | getPiece m (x-1,y) == (Food Little) = Move id U
 | getPiece m (x,y+1) == (Food Little) = Move id R
 | getPiece m (x,y-1) == (Food Little) = Move id L

-- | Função que verifica se tem comida pequena em volta do pacman
foodLittleArea :: Maze -> Coords -> Bool
foodLittleArea m (x,y)
 | getPiece m (x+1,y) == (Food Little) = True
 | getPiece m (x-1,y) == (Food Little) = True
 | getPiece m (x,y+1) == (Food Little) = True
 | getPiece m (x,y-1) == (Food Little) = True
 | otherwise = False

-- | Função que determina o ghost mais proximo do pacman
closestGhost :: Player -> [Player] -> Player
closestGhost p l = head (sortOn  (distanceFromPlayers p) l)

-- | Função que determina a distancia entre 2 jogadores
distanceFromPlayers :: Player -> Player -> Float
distanceFromPlayers p1 p2 = let (a1,b1) = getPlayerCoords p1
                                (a2,b2) = getPlayerCoords p2 
                            in sqrt ((fromIntegral a1 - fromIntegral a2)^2 + (fromIntegral b1 - fromIntegral b2)^2)      

-- | Função que escolhe a melhor orientação para perseguir sem parede
bestOriToChaseWithoutWall :: [(Orientation,Float)] -> Orientation -- coords do closest ghost
bestOriToChaseWithoutWall l = fst ( head (sortOn (snd) l))

-- | Função que escolhe a melhor orientação para fugir sem parede
bestOriToRunWithoutWall :: [(Orientation,Float)] -> Orientation -- coords do closest ghost
bestOriToRunWithoutWall l = fst ( head (reverse (sortOn (snd) l)))

-- | Função que retira as orientações do bot que têm parede
oriWithoutWallsforBot :: Maze -> Coords -> ([Coords],[Orientation]) -> [(Orientation,Float)] -- usar fourCoords e coords do ghost
oriWithoutWallsforBot mz@(z:zs) gc ([],[]) = []
oriWithoutWallsforBot mz@(z:zs) gc ((x:xs),(y:ys))
 | or [getPiece mz x == Wall , x == ((div (length mz) 2),(length z)-1) , x == ((div (length mz) 2),0) , x == ((div (length mz) 2)-1,(length z)-1),x == ((div (length mz) 2)-1,0), x == ((div (length mz) 2)-1,div (length z) 2), x == ((div (length mz) 2)-1,1+(div (length z) 2)),x == ((div (length mz) 2)-1,(div (length z) 2)-1)] = oriWithoutWallsforBot mz gc (xs,ys)
 | otherwise = (y,distance gc x) : oriWithoutWallsforBot mz gc (xs,ys)

-- | Função que retira as orientações do fantasma que têm parede
oriWithoutWallsforGhost :: Maze -> Coords -> ([Coords],[Orientation]) -> [(Orientation,Float)] -- usar fourCoords e coords do ghost
oriWithoutWallsforGhost mz@(z:zs) gc ([],[]) = []
oriWithoutWallsforGhost mz@(z:zs) gc ((x:xs),(y:ys))
 | or [getPiece mz x == Wall , x == ((div (length mz) 2),(length z)-1) , x == ((div (length mz) 2),0) , x == ((div (length mz) 2)-1,(length z)-1),x == ((div (length mz) 2)-1,0)] = oriWithoutWallsforGhost mz gc (xs,ys)
 | otherwise = (y,distance gc x) : oriWithoutWallsforGhost mz gc (xs,ys)

-- | Função auxiliar que retira o segundo elemento de um tuplo com tres elementos
sndAux (a,b,c) = b

-- | Função que dá as coordenadas consoante a orientação
orientationAux :: Orientation -> Coords -> Coords
orientationAux U (x,y) = (x-1,y)
orientationAux D (x,y) = (x+1,y)
orientationAux R (x,y) = (x,y+1)
orientationAux L (x,y) = (x,y-1)

-- | Função que devolve a lista das quatro orientaçoes e das quatro coordenadas em volta de um jogador.
fourCoords :: Coords -> ([Coords],[Orientation])
fourCoords (x,y) = ([(x+1,y),(x-1,y),(x,y+1),(x,y-1)],[D,U,R,L])























{- |

= Introdução
Nesta tarefa, o objetivo principal é implementarmos diversos comportamentos para os fantasmas, 
tendo de complementar a tarefa 2 com certas funções que nos permitissem fazer as jogadas desejadas
com os fantasmas.

= Objetivos
Para fazer esta tarefa, esquematizamos aquilo que pretendíamos obter, sendo que, como era bastante 
intuitivo, não foi difícil de traduzir o nosso raciocínio para o código. Implementamos funções que 
verificam o estado do fantasma (morto ou vivo) e, por exemplo, a scatterMode e a chaseMode, que são 
duas funções importantíssimas, visto que são as responsáveis pelo que o fantasma vai fazer dada uma 
condição e a mais geral. A função "scatterMode" é responsável pelo movimento de fuga do pacman e a função
"chaseMode" é responsável pelo movimento de perseguição ao pacman.

Estratégia Scatter Mode : Utilizamos uma estratégia simples para o scatter mode, que consistem em manter
a orientação quando a próxima peça não é uma parede. Caso seja uma parede então o ghost vai acimar a orientação 
à sua direita.

Estratégia Chase Mode : Para o chase mode utilizamos uma estratégia em que quando a próxima peça não é parede 
mantém a orientação que tinha. Caso seja uma parede, então vai determinar a orientação mais próxima do pacman.

= Discussão e conclusão
Overall, esta tarefa era bastante intuitiva, o que levou a um raciocínio fluido e objetivo. O resultado 
final é o esperado, e funciona tudo na perfeição.

-}



-- | Função principal que devolve a lista de jogadas dos fantasmas
ghostPlay :: State -> [Play] -- ver esta função
ghostPlay s@(State m [x] lvl) = []
ghostPlay s@(State m (x:xs) lvl)
 | isPacman x = ghostPlay (State m (xs ++ [x]) lvl)
 | getGhostMode x == Alive = (chaseMode s (getPlayerID x)) : ghostPlay (State m xs lvl) 
 | getGhostMode x == Dead  = (scatterMode s (getPlayerID x)) : ghostPlay (State m xs lvl)

-- | Função que retorna uma play que persegue o pacman
chaseMode :: State -> Int -> Play
chaseMode s@(State m pls lvl) id 
 | (isWall s id)     = Move id bestOriToChase
 | not (isWall s id) = Move id (getPlayerOrientation (selectCertainPlayer id pls))
                 where bestOriToChase = bestOriToChaseWithoutWall (oriWithoutWallsforGhost m (getPacmanCoords pls) (fourCoords (getPlayerCoords (selectCertainPlayer id pls))))

-- | Função que retorna uma play que foge do pacman
scatterMode :: State -> Int -> Play
scatterMode s@(State m pls lvl) id 
 | (isWall s id)     = Move id (guessGhostDeadOri (getPlayerOrientation (selectCertainPlayer id pls)))
 | not (isWall s id) = Move id (getPlayerOrientation (selectCertainPlayer id pls))

-- | Função que determina uma orientação clockwise
guessGhostDeadOri :: Orientation -> Orientation
guessGhostDeadOri R = D
guessGhostDeadOri D = L
guessGhostDeadOri L = U
guessGhostDeadOri U = R

















