{-|
= Introdução
A tarefa 4 foi a tarefa na qual foi adicionada a passagem de tempo  no jogo, acabando por ser uma das mais desafiantes e
dificeis de concluir
= Objetivos
Nesta tarefa tentamos abordar a situação do modo mais direto e simples possível uma vez que as nossas habilidades em 
haskell não são as melhores. A nossa abordagem passou pela aplicação de uma função que, recursivamente, atualizava o playerstate
de cada jogador a cada iteração da função passTime. 
= Discussão e conclusão
Esta tarefa foi uma das mais difíceis, razão pela qual não a conseguimos concluir, ficando um pouco sem noção de como  a abordar.
A parte mais complicada deste tarefa foi a implementção de diferentes velocidades para os jogadores e a consequente passagem de iterações.

-}


defaultdelaytime = 250 -- delay em ms

-- | Faz passar o tempo entre jogadas
passTime :: Int -> State -> State
passTime  s (State m ps l) = if playSpeed (head ps) == 1`div`2 && even s == True then (State m (finalFunc ps) l)
                             else if playSpeed (head ps) == 1`div`2 && even s == False then (State m (finalFunc ps) l)
                             else if playSpeed (head ps) == 1 then (State m (finalFunc ps) l) ------falta a parte da velocidade
                             else if playSpeed (head ps) == 3`div`2 then (State m (finalFunc ps) l) --------falta a parte da velocidade
                             else if playSpeed (head ps) == 2 then (State m (finalFunc ps) l) -----------falta a parte da velocidade
                             else passTime (s+1) (State m ps l)

-- |funcao que verifica o estado do pacman

finalFunc :: [Player] -> [Player]
finalFunc (n@(Pacman(PacState (id,cd,v,o,p,l) tm oc ps)):t) | openOrClosed n == 1 && ps == Mega = backToNormal n : finalFunc t
                                                            | openOrClosed n == 1 && ps == Normal = Pacman(PacState (id,cd,v,o,p,l) tm Closed ps): finalFunc t
                                                            | openOrClosed n == 0 && ps == Mega = backToNormal n : finalFunc t
                                                            | openOrClosed n == 0 && ps == Normal = Pacman(PacState (id,cd,v,o,p,l) tm Open ps): finalFunc t

-- | verifica se tem a boca aberta ou fechada
openOrClosed :: Player -> Int
openOrClosed (Pacman(PacState(id,cd,v,o,p,l) tm oc ps)) = if oc == Open then 1
                                                 else 0

-- | perde tempo de mega
loseTimeMega :: Player -> Player
loseTimeMega (Pacman(PacState (id,cd,v,o,p,l) tm oc Mega)) = Pacman(PacState (id,cd,v,o,p,l) (tm-1) oc Mega)

-- | volta ao estado normal
backToNormal :: Player -> Player
backToNormal (Pacman(PacState (id,cd,v,o,p,l) tm oc Mega)) = if tm <= 0 then Pacman(PacState (id,cd,v,o,p,l) tm oc Normal)
                                      else loseTimeMega (Pacman(PacState (id,cd,v,o,p,l) tm oc Mega))

-- | volta ao estado alive
ghostAlive :: Player -> Player
ghostAlive (Ghost(GhoState (id,cd,v,o,p,l) gm)) = Ghost(GhoState (id,cd,v,o,p,l) Alive)

-- | verifica a velocidade
playSpeed :: Player -> Int
playSpeed (Pacman(PacState (_,_,v,_,_,_)_ _ _)) |v == 0.5 = 1`div`2
                                                | v == 1 = 1
                                                | v == 1.5 = 3`div`2
                                                | v == 2 = 2
                                                
	

{- | A funcão compactCorridor transforma um Corridor em tuplos -}

compactCorridor :: Corridor -> [(Int,Piece)]
compactCorridor [] = []
compactCorridor (x:xs) = (1,x) : compactCorridor xs


-- | Agrupa elementos iguais seguidos de um Corridor -- 

shortenCorridor :: [(Int,Piece)] -> [(Int,Piece)]
shortenCorridor [] = []
shortenCorridor (x:xs) = if length xs > 0 && (snd x) == (snd (xs!!0)) then  shortenCorridor ((((fst x) +1), snd x) : drop 1 xs)  
                            else  x : shortenCorridor xs


-- | Transforma os Corridors no tipo Instruction --

instructCorridor :: Corridor -> Instruction
instructCorridor (x:xs) = Instruct (shortenCorridor $ compactCorridor (x:xs)) 


-- | Transforma todo o Maze em Instructions --

compactMaze :: Maze -> [Instruction]
compactMaze [x] = [instructCorridor x]
compactMaze (x:xs) = [instructCorridor x] ++ compactMaze xs












js :: [Player]
js = [jogador1, jogador2]
jogador1 = (Pacman (PacState (1,(7,10),1,U,0,1)0 Open Normal))
jogador2 = (Ghost  (GhoState (0,(5,12),1,R,0,1) Alive))


-- | Permite achar o ponto médio do labirinto -- 

getMiddlePoint :: Maze -> (Int,Int)
getMiddlePoint (h:t) = ((length h `div` 2),(length (h:t) `div` 2))


-- | Permite selecionar os Ghosts de uma lista de Players --

selectGhosts :: [Player] -> [Player]
selectGhosts ((Pacman (PacState (_,_,_,_,_,_) _ _ _)):t) = t
selectGhosts ((Ghost (GhoState (a,b,c,d,e,f) g)):t) = (Ghost (GhoState (a,b,c,d,e,f) g)): selectGhosts t


-- | Altera o estado dos Ghosts de Alice para Dead --

updateghostsToDead :: [Player] -> [Player]
updateghostsToDead j = changeToDead $ selectGhosts j


-- | Altera o estado de todos os Players para Dead ou Dying --

changeToDead :: [Player] -> [Player]
changeToDead [] = []
changeToDead ((Pacman (PacState (a,b,c,d,e,f) g h Normal)):t) = (Pacman (PacState (a,b,c,d,e,f) g h Dying)) : changeToDead t
changeToDead ((Ghost (GhoState (a,b,v,d,e,f) Alive)):t) = (Ghost (GhoState (a,b,(v * (1/2)),d,e,f) Dead)) : changeToDead t

changeToAlive :: [Player] -> [Player]
changeToAlive [] = []
changeToAlive ((Pacman (PacState (a,b,c,d,e,f) g h Dying)):t) = (Pacman (PacState (a,b,c,d,e,f) g h Normal)) : changeToAlive t
changeToAlive ((Ghost (GhoState (a,b,c,d,e,f) Dead)):t) = ((Ghost (GhoState (a,b,c,d,e,f) Alive))) : changeToAlive t


-- | Exprime os possiveis resultados no caso de um Player Pacman e um Player Ghost se encontrarem na mesma posição --

hitghost :: State -> State
hitghost (State m (Pacman (PacState (a,(y,x),c,d,e,0) g h Normal) : Ghost (GhoState (a1,(y1,x1),c1,d1,e1,f1) Alive):t) l) = (State m (Pacman (PacState (a,(y,x),c,d,e,0) g h Dying) : Ghost (GhoState (a1,(y1,x1),c1,d1,e1,f1) Alive):t) l)
hitghost (State m (Pacman (PacState (a,(y,x),c,d,e,f) g h Normal) : Ghost (GhoState (a1,(y1,x1),c1,d1,e1,f1) Alive):t) l) = (State m (Pacman (PacState (a,(y,x),c,d,e,f-1) g h Normal) : Ghost (GhoState (a1,(y,x),c1,d1,e1,f1) Alive):t) l)
hitghost (State m (Pacman (PacState (a,(y,x),c,d,e,f) g h Mega) : Ghost (GhoState (a1,(y1,x1),c1,d1,e1,f1) Dead):t) l) = (State m (Pacman (PacState (a,(y,x),c,d,e+10,f) g h Mega) : Ghost (GhoState (a1,(middlePoint m (y1,x1)),c1,d1,e1,f1) Alive):t) l)                                                                                                                       

middlePoint :: Maze -> Coords -> Coords 
middlePoint m (y,x) = if length m `mod` 2 == 0 then (length m `div`2 + (1`div`2),length (head m))
               else (length m `div` 2, length (head m))

-- | Mostra a peça que se encontra em determinada posiçao do Maze -- 

piecePos :: Maze -> Coords -> Piece
piecePos m (y,x) = m!!y!!x

choosePlayer :: Play -> [Player] -> Player
choosePlayer (Move n o) (p:ps) = if n == getPlayerID p then p 
                              else choosePlayer (Move n o) ps 


play :: Play -> State -> State
play (Move j R) (State m ((Pacman (PacState(a,(y,x),c,d,e,f) g h i)): Ghost (GhoState (a1,(y1,x1),c1,d1,e1,f1) g1) :t) l) =         if piecePos m (y,x+1) == Food Little                          then (State (replaceElemInMaze (y,x+1) Empty m) ((Pacman (PacState(a,(y,x+1),c,d,e+1,f) g h i)):t) l)
                                                                                                                                    else if piecePos m (y,x+1) == Food Big                               then (State (replaceElemInMaze (y,x+1) Empty m) (updateghostsToDead ((Pacman (PacState(a,(y,x+1),c,d,e+5,f) g h Mega )):t)) l)
                                                                                                                                    else if piecePos m (y,x+1) == Empty                                  then (State m ((Pacman (PacState(a,(y,x+1),c,d,e,f) g h i)):t) l) 
                                                                                                                                    else if (y,x+1) == (y1,x1)                                           then hitghost (State (replaceElemInMaze (y,x+1) Empty m) ((Pacman (PacState(a,(y,x+1),c,d,e,f) g h i)): Ghost (GhoState (a1,(y1,x1),c1,d1,e1,f1) g1) :t) l)
                                                                                                                                    else if (y,x) == (y,length (head m)) && piecePos m (y,x) == Empty    then (State m ((Pacman (PacState(a,(y,0) ,c,d,e,f) g h i)): Ghost (GhoState (a1,(y1,x1),c1,d1,e1,f1) g1) :t) l)
                                                                                                                                    else    (State m ((Pacman (PacState(a,(y,x),c,d,e,f) g h i)): Ghost (GhoState (a1,(y1,x1),c1,d1,e1,f1) g1) :t) l)  
play (Move j L ) (State m ((Pacman (PacState(a,(y,x),c,d,e,f) g h i)): Ghost (GhoState (a1,(y1,x1),c1,d1,e1,f1) g1) :t) l) =        if piecePos m (y,x-1) == Food Little                                 then (State (replaceElemInMaze (y,x-1) Empty m) ((Pacman (PacState(a,(y,x+1),c,d,e+1,f) g h i)):t) l)
                                                                                                                                    else if piecePos m (y,x-1) == Food Big                               then (State (replaceElemInMaze (y,x-1) Empty m) (updateghostsToDead ((Pacman (PacState(a,(y,x-1),c,d,e+5,f) g h Mega )):t)) l)
                                                                                                                                    else if piecePos m (y,x-1) == Empty                                  then (State m ((Pacman (PacState(a,(y,x-1),c,d,e,f) g h i)):t) l) 
                                                                                                                                    else if (y,x-1) == (y1,x1)                                           then hitghost (State (replaceElemInMaze (y,x-1) Empty m) ((Pacman (PacState(a,(y,x-1),c,d,e,f) g h i)): Ghost (GhoState (a1,(y1,x1),c1,d1,e1,f1) g1) :t) l)
                                                                                                                                    else if (y,x) == (y,0) && piecePos m (y,x) == Empty                  then (State m ((Pacman (PacState(a,(y,(length (head m))) ,c,d,e,f) g h i)): Ghost (GhoState (a1,(y1,x1),c1,d1,e1,f1) g1) :t) l)
                                                                                                                                    else (State m ((Pacman (PacState(a,(y,x),c,d,e,f) g h i)): Ghost (GhoState (a1,(y1,x1),c1,d1,e1,f1) g1) :t) l)
play (Move j U) (State m ((Pacman (PacState(a,(y,x),c,d,e,f) g h i)): Ghost (GhoState (a1,(y1,x1),c1,d1,e1,f1) g1) :t) l) =         if piecePos m (y-1,x) == Food Little                                 then (State (replaceElemInMaze (y-1,x) Empty m) ((Pacman (PacState(a,(y-1,x),c,d,e+1,f) g h i)):t) l)
                                                                                                                                    else if piecePos m (y-1,x) == Food Big                               then (State (replaceElemInMaze (y-1,x) Empty m) (updateghostsToDead ((Pacman (PacState(a,(y-1,x),c,d,e+5,f) g h Mega )):t)) l)
                                                                                                                                    else if piecePos m (y-1,x) == Empty                                  then (State m ((Pacman (PacState(a,(y-1,x),c,d,e,f) g h i)):t) l) 
                                                                                                                                    else if (y-1,x) == (y1,x1)                                           then hitghost (State (replaceElemInMaze (y-1,x) Empty m) ((Pacman (PacState(a,(y-1,x),c,d,e,f) g h i)): Ghost (GhoState (a1,(y1,x1),c1,d1,e1,f1) g1) :t) l)
                                                                                                                                    else (State m ((Pacman (PacState(a,(y,x),c,d,e,f) g h i)): Ghost (GhoState (a1,(y1,x1),c1,d1,e1,f1) g1) :t) l)                       
play (Move j D) (State m ((Pacman (PacState(a,(y,x),c,d,e,f) g h i)): Ghost (GhoState (a1,(y1,x1),c1,d1,e1,f1) g1) :t) l) =         if piecePos m (y+1,x) == Food Little                                 then (State (replaceElemInMaze (y+1,x) Empty m) ((Pacman (PacState(a,(y+1,x),c,d,e+1,f) g h i)):t) l)
                                                                                                                                    else if piecePos m (y+1,x) == Food Big                               then (State (replaceElemInMaze (y+1,x) Empty m) (updateghostsToDead ((Pacman (PacState(a,(y+1,x),c,d,e+5,f) g h Mega )):t)) l)
                                                                                                                                    else if piecePos m (y+1,x) == Empty                                  then (State m ((Pacman (PacState(a,(y+1,x),c,d,e,f) g h i)):t) l) 
                                                                                                                                    else if (y+1,x) == (y1,x1)                                           then hitghost (State (replaceElemInMaze (y+1,x) Empty m) ((Pacman (PacState(a,(y+1,x),c,d,e,f) g h i)): Ghost (GhoState (a1,(y1,x1),c1,d1,e1,f1) g1) :t) l)
                                                                                                                                    else (State m ((Pacman (PacState(a,(y,x),c,d,e,f) g h i)): Ghost (GhoState (a1,(y1,x1),c1,d1,e1,f1) g1) :t) l)
play (Move j R) (State m ((Pacman (PacState(a,(y,x),c,d,e,f) g h i)): Ghost (GhoState (a1,(y1,x1),c1,d1,e1,f1) g1) :t) l) | j == a1 = (State m ((Pacman (PacState(a,(y,x),c,d,e,f) g h i)): Ghost (GhoState (a1,(y1,x1+1),c1,d1,e1,f1) g1) :t) l)
play (Move j L) (State m ((Pacman (PacState(a,(y,x),c,d,e,f) g h i)): Ghost (GhoState (a1,(y1,x1),c1,d1,e1,f1) g1) :t) l) | j == a1 = (State m ((Pacman (PacState(a,(y,x),c,d,e,f) g h i)): Ghost (GhoState (a1,(y1,x1-1),c1,d1,e1,f1) g1) :t) l)
play (Move j U) (State m ((Pacman (PacState(a,(y,x),c,d,e,f) g h i)): Ghost (GhoState (a1,(y1,x1),c1,d1,e1,f1) g1) :t) l) | j == a1 = (State m ((Pacman (PacState(a,(y,x),c,d,e,f) g h i)): Ghost (GhoState (a1,(y1-1,x1),c1,d1,e1,f1) g1) :t) l)
play (Move j D) (State m ((Pacman (PacState(a,(y,x),c,d,e,f) g h i)): Ghost (GhoState (a1,(y1,x1),c1,d1,e1,f1) g1) :t) l) | j == a1 = (State m ((Pacman (PacState(a,(y,x),c,d,e,f) g h i)): Ghost (GhoState (a1,(y1+1,x1),c1,d1,e1,f1) g1) :t) l)




{- | A função generateRandoms permite gerar números aleatórios  -}

generateRandoms :: Int -> Int -> [Int]
generateRandoms n seed = let gen = mkStdGen seed -- creates a random generator
                        in take n $ randomRs (0,99) gen


-- | Gera números random --

nrRandom :: Int -> Int 
nrRandom seed = head $ generateRandoms 1 seed


-- | A função subLista agrupa os elementos da list dos numeros gerados aleatoriamente em lists de n elementos (correspondem aos corridors) --

subLista :: Int -> [a] -> [[a]]
subLista _ [] = []
subLista n l = take n l: subLista n (drop n l)


-- | Converte os nºs gerados aleatoriamente em Pieces --

convertPiece :: Int -> Piece
convertPiece n | n >= 70 && n <= 99 = Wall
               | n >= 0 && n < 70   = Food Little
               | n == 3             = Food Big


-- | Dá print de um corredor --

printCorridor :: Corridor -> String
printCorridor [] = "\n"
printCorridor (h:t) = show h ++ printCorridor t


-- |converte uma list de Piece em um Corridor --

convertCorridor :: [Int] -> Corridor
convertCorridor [] = []
convertCorridor (h:t) = [Wall] ++ map convertPiece (take ((length t)-1 ) t) ++ [Wall]


-- | Gera um labirinto simples delimitado por Pieces Wall --

simpleMaze :: [[Int]] -> [[Piece]]
simpleMaze (h:t) = map createWall [h] ++ map convertCorridor (take ((length t)-1) t) ++ map createWall [h] 


-- | Função auxiliar, permite criar uma parede com a length do labirinto --

createWall :: [Int] -> [Piece]
createWall l = replicate (length l) Wall


-- | Permite adicionar o tunel ao Maze

tunnel:: Corridor -> Corridor
tunnel (h:t) = [Empty] ++ init t ++ [Empty]

tunnelCorridor :: Maze -> [Corridor]
tunnelCorridor (h:t) = map tunnel (getMiddle (h:t))


-- | Adiciona o tunel ao Maze

addTunneltoMaze :: [Corridor]-> [Corridor]
addTunneltoMaze (h:t) = if ((lengthMazeV (h:t)) `mod` 2) == 0 then take ((lengthMazeV (h:t) `div` 2)-1) (h:t) ++ tunnelCorridor (h:t) ++ drop (((lengthMazeV (h:t)) `div` 2)+1) (h:t)
                        else take ( (lengthMazeV (h:t) `div` 2)-1) (h:t) ++ tunnelCorridor (h:t) ++ drop ((lengthMazeV(h:t) `div` 2)) (h:t)


-- | Comprimento vertical e horizontal do Maze e da casa dos fantasmas --

lengthMazeV :: [[Piece]] -> Int
lengthMazeV [[]] = 0
lengthMazeV (h:t) = length (h:t)

lengthMazeH :: [[Piece]]-> Int
lengthMazeH (h:t) = length h 

lengthGhosthouse :: Corridor -> Int
lengthGhosthouse (m:ms) = if length (m:ms) `mod` 2 == 0 then 10
                          else 11


-- | Função auxiliar, Permite achar o/s Corridor/s centrais do labirinto --

getMiddle :: Maze -> [Corridor]
getMiddle (h:t) = if ((lengthMazeV (h:t)) `mod` 2) == 0 then [(h:t)!!((length (h:t)`div`2)), ((h:t)!!((length (h:t)`div`2)+1))] 
              else [(h:t)!! ((length (h:t)`div`2) + (1`div`2))] 




-- | Corredores da casa de fantasmas 

ghosthousecorridor1 :: Corridor -> Corridor
ghosthousecorridor1 (h:t) = take ((((length (h:t)) - (lengthGhosthouse (h:t)))`div` 2)) (h:t) ++ [Empty, Empty, Empty, Empty, Empty,Empty, Empty, Empty, Empty, Empty] ++  drop (((((length (h:t)) - (lengthGhosthouse (h:t)))`div`2) + lengthGhosthouse (h:t)))  (h:t)

ghosthousecorridor2 :: Corridor -> Corridor
ghosthousecorridor2 (h:t) = take ((((length (h:t)) - (lengthGhosthouse (h:t)))`div` 2)) (h:t) ++ [Empty, Wall, Wall, Wall, Empty, Empty, Wall, Wall, Wall, Empty] ++ drop (((((length (h:t)) - (lengthGhosthouse (h:t)))`div`2) + lengthGhosthouse (h:t)))  (h:t)

ghosthousecorridor3 :: Corridor -> Corridor
ghosthousecorridor3 (h:t) = take ((((length (h:t)) - (lengthGhosthouse (h:t)))`div` 2)) (h:t) ++ [Empty, Wall, Empty, Empty, Empty, Empty, Empty, Empty, Wall, Empty] ++  drop (((((length (h:t)) - (lengthGhosthouse (h:t)))`div`2) + lengthGhosthouse (h:t)))  (h:t)

ghosthousecorridor4 :: Corridor -> Corridor
ghosthousecorridor4 (h:t) = take ((((length (h:t)) - (lengthGhosthouse (h:t)))`div` 2)) (h:t) ++ [Empty,Wall, Wall, Wall, Wall, Wall, Wall, Wall, Wall, Empty] ++ drop (((((length (h:t)) - (lengthGhosthouse (h:t)))`div`2) + lengthGhosthouse (h:t)))  (h:t)

ghosthousecorridora :: Corridor -> Corridor
ghosthousecorridora (h:t) = take ((((length (h:t)) - (lengthGhosthouse (h:t)))`div` 2)) (h:t) ++ [Empty, Empty, Empty, Empty, Empty, Empty, Empty, Empty, Empty, Empty, Empty] ++ drop (((((length (h:t)) - (lengthGhosthouse (h:t)))`div`2) + lengthGhosthouse (h:t)))  (h:t)

ghosthousecorridorb :: Corridor -> Corridor
ghosthousecorridorb (h:t) = take ((((length (h:t)) - (lengthGhosthouse (h:t)))`div` 2)) (h:t) ++ [Empty, Wall, Wall, Wall, Empty, Empty, Empty, Wall, Wall, Wall, Empty] ++ drop (((((length (h:t)) - (lengthGhosthouse (h:t)))`div`2) + lengthGhosthouse (h:t))) (h:t)

ghosthousecorridorc :: Corridor -> Corridor
ghosthousecorridorc (h:t) = take ((((length (h:t)) - (lengthGhosthouse (h:t)))`div` 2)) (h:t) ++ [Empty, Wall, Empty, Empty, Empty, Empty, Empty, Empty, Empty, Wall, Empty] ++ drop (((((length (h:t)) - (lengthGhosthouse (h:t)))`div`2) + lengthGhosthouse (h:t))) (h:t)

ghosthousecorridord :: Corridor -> Corridor
ghosthousecorridord (h:t) = take ((((length (h:t)) - (lengthGhosthouse (h:t)))`div` 2)) (h:t) ++ [Empty,Wall, Wall, Wall, Wall, Wall, Wall, Wall, Wall, Wall, Empty] ++ drop (((((length (h:t)) - (lengthGhosthouse (h:t)))`div`2) + lengthGhosthouse (h:t))) (h:t)


-- | Cria um Maze com os Corridors da Casa dos Fantasmas

mazeghosthouse :: Maze -> Maze 
mazeghosthouse (a:b) = if lengthMazeH (a:b) `mod` 2 == 0 then take ((((lengthMazeV (a:b))-5)`div`2)) (a:b) ++ [ghosthousecorridor1 ((a:b)!!((length (a:b)`div`2)-3))] ++ [ghosthousecorridor2  ((a:b)!!((length (a:b)`div`2)-2))] ++ [ghosthousecorridor3  ((a:b)!!((length (a:b)`div`2)-1))] ++ [ghosthousecorridor4  ((a:b)!!((length (a:b)`div`2)))] ++ [ghosthousecorridor1  ((a:b)!!((length (a:b)`div`2)+1))] ++ drop (((lengthMazeV (a:b))+5)`div`2) (a:b)
               else take (((lengthMazeV (a:b))-5)`div`2) (a:b) ++ [ghosthousecorridora ((a:b)!!((length (a:b)`div`2)-3))] ++ [ghosthousecorridorb ((a:b)!!((length (a:b)`div`2)-2))] ++ [ghosthousecorridorc  ((a:b)!!((length (a:b)`div`2)-1))] ++ [ghosthousecorridord  ((a:b)!!((length (a:b)`div`2)))] ++ [ghosthousecorridora ((a:b)!!((length (a:b)`div`2)+1))] ++ drop (((lengthMazeV (a:b))+5)`div`2) (a:b)

            
-- | Gera o labirinto

generateMaze :: Int -> Int -> Int -> IO()
generateMaze x y z | x >= 15 && y >= 10 = let randomNrs = generateRandoms (x*y) z
                                         in putStrLn $ printMaze $  mazeghosthouse $ addTunneltoMaze $ simpleMaze $ subLista x (randomNrs)
                   | otherwise = error "not enough space"

-- | Testes 

testesT1 :: [(Int, Int, Int)]
testesT1  = [(35,15,5),(20,20,3),(25,30,4),(42,35,5)]



data Manager = Manager 
    {   
        state   :: State
    ,    pid    :: Int
    ,    step   :: Int
    ,    before :: Integer
    ,    delta  :: Integer
    ,    delay  :: Integer
    } 


loadManager :: Manager
loadManager = ( Manager (loadMaze "maps/1.txt") 0 0 0 0 defaultdelaytime )

updateControlledPlayer :: Key -> Manager -> Manager
updateControlledPlayer arrow (Manager (State m (Pacman(PacState(a,(y,x),c,d,e,f)g h i):t) l) id sp be del dy) = if arrow == KeyLeftArrow && a == id  then (Manager (State m (Pacman(PacState(a,(y,x-1),c,d,e,f)g h i):t) l) id sp be del dy)
                                                                                          else if  arrow == KeyRightArrow && a == id then (Manager (State m (Pacman(PacState(a,(y,x+1),c,d,e,f)g h i):t) l) id sp be del dy)
                                                                                          else if  arrow == KeyUpArrow && a == id  then (Manager (State m (Pacman(PacState(a,(y-1,x),c,d,e,f)g h i):t) l) id sp be del dy)
                                                                                          else if  arrow == KeyDownArrow && a == id  then (Manager (State m (Pacman(PacState(a,(y+1,x),c,d,e,f)g h i):t) l) id sp be del dy)
                                                                                          else updateControlledPlayer arrow (Manager (State m  t l) id sp be del dy)

updateScreen :: Window  -> ColorID -> Manager -> Curses ()
updateScreen w a man =
                  do
                    updateWindow w $ do
                      clear
                      setColor a
                      moveCursor 0 0 
                      drawString $ show (state man)
                    render
     
currentTime :: IO Integer
currentTime = fmap ( round . (* 1000) ) getPOSIXTime

updateTime :: Integer -> Manager -> Manager
updateTime now (Manager st i sp be del dy) = (Manager st i sp now ((now-be)+del) dy)

resetTimer :: Integer -> Manager -> Manager
resetTimer now (Manager st i sp be del dy) = (Manager st i sp now 0 dy)

nextFrame :: Integer -> Manager -> Manager
nextFrame now (Manager st i sp be del dy) = let newState = passTime sp st
                    in resetTimer now (Manager newState i (sp+1) be del dy)


loop :: Window -> Manager -> Curses ()
loop w man@(Manager s pid step bf delt del ) = do 
  color_schema <- newColorID ColorBlue ColorWhite  10
  now <- liftIO  currentTime
  updateScreen w  color_schema man
  if ( delt > del )
    then loop w $ nextFrame now man
    else do
          ev <- getEvent w $ Just 0
          case ev of
                Nothing -> loop w (updateTime now man)
                Just (EventSpecialKey arrow ) -> loop w $ updateControlledPlayer arrow (updateTime now man)
                Just ev' ->
                  if (ev' == EventCharacter 'q')
                    then return ()
                    else loop w (updateTime now man)

main :: IO ()
main =
  runCurses $ do
    setEcho False
    setCursorMode CursorInvisible
    w <- defaultWindow
    loop w loadManager




loadMaze :: String -> State
loadMaze filepath = unsafePerformIO $ readStateFromFile filepath



readStateFromFile :: String -> IO State
readStateFromFile f = do
                content <- readFile f
                let llines = lines content 
                    (new_map,pl) = convertLinesToPiece llines 0 []
                return (State new_map pl 1)



convertLinesToPiece :: [String] -> Int -> [Player] -> (Maze,[Player])
convertLinesToPiece [] _ l = ([],l)
convertLinesToPiece (x:xs) n l  = let (a,b) = convertLineToPiece x n 0 l 
                                      (a1,b1) = convertLinesToPiece xs (n+1) b
                                  in (a:a1,b1)

convertLineToPiece :: String -> Int -> Int -> [Player] -> ([Piece],[Player])
convertLineToPiece [] _ _ l = ([],l)
convertLineToPiece (z:zs) x y l = let (a,b ) = charToPiece z x y l
                                      (a1,b1) = convertLineToPiece zs x (y+1) b 
                                  in (a:a1,b1)


charToPiece :: Char -> Int -> Int -> [Player] -> (Piece,[Player])
charToPiece c x y l
    | c == '{' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Open Normal ))   :l) )
    | c == '<' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Closed Normal )) :l) )
    | c == '}' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, L,0,1 ) 0 Open Normal ))   :l) )
    | c == '>' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, L,0,1 ) 0 Closed Normal )) :l) )
    | c == 'V' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, U,0,1 ) 0 Open Normal ))   :l) )
    | c == 'v' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, U,0,1 ) 0 Closed Normal )) :l) )
    | c == '^' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, D,0,1 ) 0 Open Normal ))   :l) )
    | c == '|' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, D,0,1 ) 0 Closed Normal )) :l) )
    | c == 'X' =  (Empty, ((Pacman ( PacState (length l, (x,y), 1, R,0,1 ) 0 Open Dying ))    :l) )
    | c == 'M' =  (Empty, ((Ghost (  GhoState (length l,(x,y),0,Null,0,1 ) Alive))            :l) )
    | c == '?' =  (Empty, ((Ghost (  GhoState (length l,(x,y),0,Null,0,1 ) Dead))             :l) )
    | c == 'o' =  (Food Big,l)
    | c == '.' =  (Food Little,l)
    | c == '#' =  (Wall,l)
    | otherwise = (Empty,l)



data State = State 
    {
        maze :: Maze
    ,   playersState :: [Player]
    ,   level :: Int
    }

type Maze = [Corridor]
type Corridor = [Piece]
data Piece =  Food FoodType | PacPlayer Player| Empty | Wall deriving (Eq)
data Player =  Pacman PacState | Ghost GhoState deriving (Eq)

data Orientation = L | R | U | D | Null deriving (Eq,Show)
data PacState= PacState 
    {   
        pacState :: PlayerState
    ,   timeMega :: Double
    ,   openClosed :: Mouth
    ,   pacmanMode :: PacMode
    
    } deriving Eq

data GhoState= GhoState 
    {
        ghostState :: PlayerState
    ,   ghostMode :: GhostMode
    } deriving Eq

type Coords = (Int,Int)
type PlayerState = (Int, Coords, Double , Orientation, Int, Int)
--                 (ID,  (x,y), velocity, orientation, points, lives) 
data Mouth = Open | Closed deriving (Eq,Show)
data PacMode = Dying | Mega | Normal deriving (Eq,Show)
data GhostMode = Dead  | Alive deriving (Eq,Show)
data FoodType = Big | Little deriving (Eq)
data Color = Blue | Green | Purple | Red | Yellow | None deriving Eq 

data Play = Move Int Orientation deriving (Eq,Show)

type Instructions = [Instruction]

data Instruction = Instruct [(Int, Piece)]
                 | Repeat Int deriving (Show, Eq)



instance Show State where
  show (State m ps p) = printMaze mz ++ "Level: " ++ show p ++ "\nPlayers: \n" ++ (foldr (++) "\n" (map (\y-> printPlayerStats y) ps))
                          where mz = placePlayersOnMap ps m

instance Show PacState where
   show ( PacState s o m Dying  ) =  "X"
   show ( PacState (a,b,c,R,i,l) _ Open m  ) =  "{"
   show ( PacState (a,b,c,R,i,l) _ Closed m  ) =  "<"
   show ( PacState (a,b,c,L,i,l) _ Open m  ) =  "}"
   show ( PacState (a,b,c,L,i,l) _ Closed m  ) =  ">"
   show ( PacState (a,b,c,U,i,l) _ Open m  ) =  "V"
   show ( PacState (a,b,c,U,i,l) _ Closed m  ) =  "v"
   show ( PacState (a,b,c,D,i,l) _ Open m  ) =  "^"
   show ( PacState (a,b,c,D,i,l) _ Closed m  ) =  "|"
   show ( PacState (a,b,c,Null,i,l) _ Closed m  ) =  "<"
   show ( PacState (a,b,c,Null,i,l) _ Open m  ) =  "{"

instance Show Player where
   show (Pacman x ) =  show x
   show ( Ghost x ) =   show x

instance Show GhoState where
   show (GhoState x Dead ) =  "?"
   show (GhoState x Alive ) =  "M"

instance Show FoodType where
   show ( Big ) =  "o"
   show ( Little ) =  "."

instance Show Piece where
   show (  Wall ) = coloredString "#" None
   show (  Empty ) = coloredString " " None
   show (  Food z ) = coloredString (show z )   Green
   show ( PacPlayer ( Pacman ( PacState (i, c, x, y,z,l) o m Normal ) ) ) = coloredString (show ( PacState (i, c, x, y,z,l) o m Normal)  ) Yellow
   show ( PacPlayer ( Pacman ( PacState (i, c, x, y,z,l) o m Mega   ) ) ) = coloredString (show ( PacState (i, c, x, y,z,l) o m Mega)  ) Blue
   show ( PacPlayer ( Pacman ( PacState (i, c, x, y,z,l) o m Dying   ) ) ) = coloredString (show ( PacState (i, c, x, y,z,l) o m Dying)  ) Red
   show ( PacPlayer (Ghost z) ) = coloredString (show z)  Purple


coloredString :: String -> Color -> String
coloredString x y = x 
{-    | y == Blue ="\x1b[36m" ++  x ++ "\x1b[0m"
    | y == Red = "\x1b[31m" ++ x ++ "\x1b[0m"
    | y == Green = "\x1b[32m" ++ x ++ "\x1b[0m"
    | y == Purple ="\x1b[35m" ++ x ++ "\x1b[0m"
    | y == Yellow ="\x1b[33m" ++ x ++ "\x1b[0m"
    | otherwise =  "\x1b[0m" ++ x 
-}

placePlayersOnMap :: [Player] -> Maze -> Maze
placePlayersOnMap [] x = x
placePlayersOnMap (x:xs) m = placePlayersOnMap xs ( replaceElemInMaze (getPlayerCoords x) (PacPlayer x) m )


printMaze :: Maze -> String
printMaze []  =  ""
printMaze (x:xs) = foldr (++) "" ( map (\y -> show y) x )  ++ "\n" ++ printMaze ( xs )

printPlayerStats :: Player -> String
printPlayerStats p = let (a,b,c,d,e,l) = getPlayerState p
                     in "ID:" ++ show a ++  " Points:" ++ show e ++ " Lives:" ++ show l ++"\n"

getPlayerID :: Player -> Int
getPlayerID (Pacman (PacState (x,y,z,t,h,l) q c d )) = x
getPlayerID  (Ghost (GhoState (x,y,z,t,h,l) q )) = x
 
getPlayerPoints :: Player -> Int
getPlayerPoints (Pacman (PacState (x,y,z,t,h,l) q c d )) = h
getPlayerPoints (Ghost (GhoState (x,y,z,t,h,l) q )) = h

setPlayerCoords :: Player -> Coords -> Player
setPlayerCoords (Pacman (PacState (x,y,z,t,h,l) q c d )) (a,b) = Pacman (PacState (x,(a,b),z,t,h,l) q c d )
setPlayerCoords (Ghost (GhoState (x,y,z,t,h,l) q )) (a,b) = Ghost (GhoState (x,(a,b),z,t,h,l) q )


getPieceOrientation :: Piece -> Orientation
getPieceOrientation (PacPlayer p) =  getPlayerOrientation p
getPieceOrientation _ = Null

getPacmanMode :: Player -> PacMode
getPacmanMode (Pacman (PacState a b c d)) = d

getGhostMode :: Player -> GhostMode
getGhostMode (Ghost (GhoState a d)) = d

getPlayerState :: Player -> PlayerState
getPlayerState (Pacman (PacState a b c d )) = a
getPlayerState (Ghost (GhoState a b )) = a

getPlayerOrientation :: Player -> Orientation
getPlayerOrientation (Pacman (PacState (x,y,z,t,h,l) q c d )) = t
getPlayerOrientation  (Ghost (GhoState (x,y,z,t,h,l) q )) = t

replaceElemInMaze :: Coords -> Piece -> Maze -> Maze
replaceElemInMaze (a,b) _ [] = []
replaceElemInMaze (a,b) p (x:xs) 
  | a == 0 = replaceNElem b p x : xs 
  | otherwise = x : replaceElemInMaze (a-1,b) p xs


replaceNElem :: Int -> a -> [a] -> [a]
replaceNElem i _ [] = [] 
replaceNElem i el (x:xs)
  |  i == 0 = el : xs 
  | otherwise =  x : replaceNElem (i-1) el xs

getPlayerCoords :: Player -> Coords
getPlayerCoords (Pacman (PacState (x,y,z,t,h,l) b c d )) = y
getPlayerCoords (Ghost (GhoState (x,y,z,t,h,l) b )) = y

-- | Esta função tem como finalidade identificar um determinado /Player/ de uma lista de /Players/ a partir de um determinado __id__ fornecido
identificaID :: [Player] -> Int -> Player
identificaID ((Ghost (GhoState (id1, (x,y), vel1, ori1, points1, life1) d)):xs) newid
                     | id1 == newid = (Ghost (GhoState (id1, (x,y), vel1, ori1, points1, life1) d))
                     | otherwise = identificaID xs newid
identificaID ((Pacman (PacState (id, (x,y), vel, ori, points, life) a b c)):xs) newid
                     | id == newid = (Pacman (PacState (id, (x,y), vel, ori, points, life) a b c))
                     | otherwise = identificaID xs newid


substituirPID :: Int -> [Player] -> [Player]
substituirPID _ [] = []
substituirPID newid ((Pacman (PacState (id, (x,y), vel, ori, points, life) a b c)): xs) = (Pacman (PacState (id, (x,y), vel, ori, points, life) a b c)) : substituirPID newid xs
substituirPID  id ((Ghost (GhoState  (ig,(xg,yg),vg,og,pg,lg) mg)):tail) =
  filter (\(Ghost (GhoState  (ig,(xg,yg),vg,og,pg,lg) mg)) -> id/=ig) ((Ghost (GhoState  (ig,(xg,yg),vg,og,pg,lg) mg)):tail)

--se o id do ghost for diferente do id que damos ele vai ficar na lista
-- com a funçao juntar lista vai pegar no ghost movido e juntar nessa lista
{- |
=Introdução:
  Esta tarefa tem como objetivo definir um comportamento para os fantasmas dependendo se o Pacman se encontra ou não em modo __/Mega/__,
  tendo portanto em conta o facto da função 'play' poder receber fantasmas.

=Objetivos:
  Após a leitura do enunciado, chegámos à conclusão que era necessário definir duas funções: uma à qual dariamos o nome de __'scatterMode'__, tendo 
  como objetivo fazer com que os fantasmas 'fugissem' do Pacman, e outra que faria com que os fantasmas o 'perseguissem', chamada __'chaseMode'__.
  Decidimos começar pela __'scatterMode'__. Para tal, decidimos que sempre que o Pacman estivesse em /Mega/, o fantasma iria movimentar-se com a 
  mesma orientação que tinha inicialmente, mudando-a apenas quando encontrava uma parede. Nesse caso, o fantasma deveria mudar a sua orientação para 
  o sentido dos ponteiros do relógio e continuar a movimentar-se nesse sentido até se deparar de novo com uma parede. Foi necessário ter também em 
  conta que o fantasma não deveria permanecer dentro da casa dos fantasmas, tendo sido criada outra função responsável para prevenir essa situação.
  Inicialmente pensámos em criar uma função que comparasse as coordenadas do Pacman com a do fantasma, de forma a calcular a melhor via para o segundo
  fugir. No entanto acabámos por não o fazer pois achámos mais simples o raciocínio mencionado anteriormente.
  De seguida partimos para a criação da __'chaseMode'__. Esta vai ser responsável por fazer os fantasmas irem de encontro ao Pacman da forma mais
  eficaz quando este não está em /Mega/.
  Decidimos então que, comparando a localização do Pacman e a dos fantasmas, iríamos enumerar uma série de casos que decidem a nova orientação a tomar
  pelos fantasmas, dando prioridade a uma das coordenadas quando necessário.
  Após solucinar estes problemas, apenas se criou uma função final que era uma junção das duas mencionadas anteriormente, e que decidia quando uma delas
  entrava em vigor.

=Discussão e Conclusão:
  Durante a realização desta tarefa, a nossa maior dificuldade foi decidir qual a melhor abordagem para encontrar o caminho mais curto até ao Pacman. 
  Para além disso, conseguimos cumprir os nossos objetivos com relativa facilidade.

-}



-- | Funçao play para os fantasmas
ghostPlay :: State -> [Play]
ghostPlay (State m ps l)
            |(length ps) == 1 = []
            |getGhostMode (head (pacOuGhost2 ps)) == Alive = (chaseMode (State m ps l) (getPlayerID (head (pacOuGhost2 ps)))) : ghostPlay (State m ((tail (pacOuGhost2 ps)) ++ [pacOuGhost ps]) l)
            |otherwise = (scatterMode (State m ps l) (getPlayerID (head (pacOuGhost2 ps)) )) : ghostPlay (State m ((tail (pacOuGhost2 ps)) ++ [pacOuGhost ps]) l)

-- | Esta função determina o comportamento dos fantasmas quando o Pacman se encontra em modo __/Alive/__
chaseMode :: State -> Int -> Play
chaseMode (State m ps l) id = Move id (getPlayerOrientation (perseguePac (pacOuGhost ps) (identificaID ps id) m))

{- 
| Esta função tem como objetivo determinar os movimentos dos fantasmas quando estes estão __/Alive/__, de modo a que estes persigam o PacMan de forma inteligente
-}
perseguePac :: Player -> Player -> Maze -> Player
perseguePac (Pacman (PacState (id, (x,y), vel, ori, points, life) a b c)) (Ghost (GhoState (id1, (x1,y1), vel1, ori1, points1, life1) d)) m
            | x > x1  && y == y1 = (Ghost (GhoState (id1, (x1,y1), vel1, D , points1, life1) d))
            | x < x1  && y == y1 = (Ghost (GhoState (id1, (x1,y1), vel1, U , points1, life1) d))
            | x == x1 && y > y1  = (Ghost (GhoState (id1, (x1,y1), vel1, R , points1, life1) d))
            | x == x1 && y < y1  = (Ghost (GhoState (id1, (x1,y1), vel1, L , points1, life1) d))
            | x > x1  && y > y1  = (Ghost (GhoState (id1, (x1,y1), vel1, R , points1, life1) d))
            | x < x1  && y < y1  = (Ghost (GhoState (id1, (x1,y1), vel1, L , points1, life1) d))
            | x > x1  && y < y1  = (Ghost (GhoState (id1, (x1,y1), vel1, L , points1, life1) d))
            | x < x1  && y > y1  = (Ghost (GhoState (id1, (x1,y1), vel1, R , points1, life1) d))
            | identificarPeca (x1,y1) m == Wall && ori1 == R && x == x1  = (Ghost (GhoState (id1, (x,y), vel1, L , points1, life1) d))
            | identificarPeca (x1,y1) m == Wall && ori1 == R && x < x1   = (Ghost (GhoState (id1, (x,y), vel1, U , points1, life1) d))
            | identificarPeca (x1,y1) m == Wall && ori1 == R && x > x1   = (Ghost (GhoState (id1, (x,y), vel1, D , points1, life1) d))
            | identificarPeca (x1,y1) m == Wall && ori1 == D && y == y1  = (Ghost (GhoState (id1, (x,y), vel1, U , points1, life1) d))
            | identificarPeca (x1,y1) m == Wall && ori1 == D && y >  y1  = (Ghost (GhoState (id1, (x,y), vel1, R , points1, life1) d))
            | identificarPeca (x1,y1) m == Wall && ori1 == D && y <  y1  = (Ghost (GhoState (id1, (x,y), vel1, L , points1, life1) d))
            | identificarPeca (x1,y1) m == Wall && ori1 == L && x == x1  = (Ghost (GhoState (id1, (x,y), vel1, R , points1, life1) d))
            | identificarPeca (x1,y1) m == Wall && ori1 == L && x <  x1  = (Ghost (GhoState (id1, (x,y), vel1, U , points1, life1) d))
            | identificarPeca (x1,y1) m == Wall && ori1 == L && x >  x1  = (Ghost (GhoState (id1, (x,y), vel1, D , points1, life1) d))
            | identificarPeca (x1,y1) m == Wall && ori1 == U && y == y1  = (Ghost (GhoState (id1, (x,y), vel1, D , points1, life1) d))
            | identificarPeca (x1,y1) m == Wall && ori1 == U && y <  y1  = (Ghost (GhoState (id1, (x,y), vel1, L , points1, life1) d))
            | identificarPeca (x1,y1) m == Wall && ori1 == U && y >  y1  = (Ghost (GhoState (id1, (x,y), vel1, R , points1, life1) d))
            | otherwise = (Ghost (GhoState (id1, (x1,y1), vel1, ori1, points1, life1) d))


-- | Quando um fantasma se encontra na casa dos fantasmas, este não pode permanecer lá dentro, devendo movimentar-se para fora da mesma.
tiraReal :: Player -> Maze -> Player
tiraReal (Ghost (GhoState (id1, (x,y), vel1, ori1, points1, life1) d)) m 
         | auxTira (x,y) m = (Ghost (GhoState (id1, (x,y-1), vel1, U , points1, life1) d))
         | otherwise = (Ghost (GhoState (id1, (x,y), vel1, ori1, points1, life1) d))

auxTira :: Coords -> Maze -> Bool
auxTira (x,y) m 
                 | x == (div (length (head m)) 2) && y == ((div (length m) 2)-1) = True
                 | x == ((div (length (head m)) 2)-1) && y == ((div (length m) 2)-1) = True
                 | otherwise = False

-- | Quando um fantasma encontra uma parede, este deve mudar a sua orientação de acordo com o sentido dos ponteiros do relógio.
jogadaGhost :: Player -> Maze -> Player
jogadaGhost (Ghost (GhoState (id1, (x,y), vel1, ori1, points1, life1) Dead)) m 
            | ori1 == U && identificarPeca (x,y) m == Wall = (Ghost (GhoState (id1, (x,y), vel1, R , points1, life1) Dead))
            | ori1 == R && identificarPeca (x,y) m == Wall = (Ghost (GhoState (id1, (x,y), vel1, D , points1, life1) Dead))
            | ori1 == D && identificarPeca (x,y) m == Wall = (Ghost (GhoState (id1, (x,y), vel1, L , points1, life1) Dead))
            | ori1 == L && identificarPeca (x,y) m == Wall = (Ghost (GhoState (id1, (x,y), vel1, U , points1, life1) Dead))
            | otherwise = (Ghost (GhoState (id1, (x,y), vel1, ori1, points1, life1) Dead))

-- | Função responsável por "juntar" as funções 'tiraReal' e 'jogadaGhost'
juntaGhost :: Player -> Maze -> Player
juntaGhost p@(Ghost (GhoState (id1, (x,y), vel1, ori1, points1, life1) d)) m = tiraReal (jogadaGhost p m) m 


-- | Esta função determina o comportamento dos fantasmas quando o PacMan está em __/Mega/__ 
scatterMode :: State -> Int -> Play
scatterMode (State m ps l) id = Move id (getPlayerOrientation (juntaGhost (identificaID ps id) m))



